-- Poems batch 264
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('4792e99f-0e5d-4c9e-b76d-fb183d61b74c','布袋贊  其二','釋月磵','宋','宋诗','song-poetry','','[]','無端拋却率陀天，奉化江頭恣掣顛。',32,'全唐诗/poet.song.235000.json','["無端拋却率陀天，奉化江頭恣掣顛。", "拄杖奪來還痛與，我儂要結下生緣。"]'),
('8c40cf33-48b5-4de3-9dbf-dca74c1e0f2e','寒山贊','釋月磵','宋','宋诗','song-poetry','','[]','山河大地，猶一點埃。',24,'全唐诗/poet.song.235000.json','["山河大地，猶一點埃。", "面前掃却，背後成堆。", "獃，獃。"]'),
('3eeb0858-3d45-4072-aa69-22aaf3e456ae','拾得贊','釋月磵','宋','宋诗','song-poetry','','[]','台雲萬丈，猶一菜滓。',24,'全唐诗/poet.song.235000.json','["台雲萬丈，猶一菜滓。", "收拾筒中，如金自誇。", "差，差。"]'),
('0d402929-9509-4ffd-8335-99459d1d7246','豐干指虎與閭丘說贊','釋月磵','宋','宋诗','song-poetry','','[]','所指是何物，所說是何言。',34,'全唐诗/poet.song.235000.json','["所指是何物，所說是何言。", "心毒不如口毒，合成生死深冤。", "閭丘老，惜尊拳。"]'),
('e7862202-6ce9-423d-8a65-50bcddf504ba','寒山拾得贊','釋月磵','宋','宋诗','song-poetry','','[]','忘却自家心，却指天邊月。',34,'全唐诗/poet.song.235000.json','["忘却自家心，却指天邊月。", "更言無物比倫，分明話作兩橛。", "生苕菷，何不摵。"]'),
('bbf7c2e5-a0ad-45f0-ae54-ace88e1e80ae','朝陽贊','釋月磵','宋','宋诗','song-poetry','','[]','渾無針劄處，爲君道線路。',24,'全唐诗/poet.song.235000.json','["渾無針劄處，爲君道線路。", "夜半三足烏，飛上珊瑚樹。"]'),
('eb6a9948-37cd-45f9-96e6-060ce418fb3e','對月贊','釋月磵','宋','宋诗','song-poetry','','[]','白白是脫空，剛言標月指。',24,'全唐诗/poet.song.235000.json','["白白是脫空，剛言標月指。", "便恁麽回向，墮佗光影裏。"]'),
('b9c5fbe2-8367-4025-9acb-b49d032f967a','贊羅漢共一軸','釋月磵','宋','宋诗','song-poetry','','["\u8861\u5c71"]','成群作隊，指東話西。',38,'全唐诗/poet.song.235000.json','["成群作隊，指東話西。", "造妖捏怪，誑惑愚癡。", "神通妙用有誰知，天台月皎，南嶽雲垂。"]'),
('235d4e78-b9c3-4eac-98af-2f8697c91abe','贊豐干寒拾虎四睡圖','釋月磵','宋','宋诗','song-poetry','','[]','虎依人，人靠虎，一物我忘亦汝，肚裏各自惺惺。',37,'全唐诗/poet.song.235000.json','["虎依人，人靠虎，一物我忘亦汝，肚裏各自惺惺。", "且作團打覺睡，誰管人間今與古。"]'),
('cdb0ad0e-7b64-4ddf-ace4-c7e29fc06de2','贊童科安醫師','釋月磵','宋','宋诗','song-poetry','','[]','惟吾一指，造大極玄。',40,'全唐诗/poet.song.235000.json','["惟吾一指，造大極玄。", "視天下人，咸若小兒。", "起膏肓疾，猶談笑然。", "貌可丹青，玄孰傳焉。"]'),
('67371281-8513-41c5-88a4-e4353c4bbd32','崇寧可長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','參無所參，悟無所悟。',46,'全唐诗/poet.song.235000.json','["參無所參，悟無所悟。", "空手捏雙拳，要起破沙盆。", "門戶用盡拍盲，少喜多怒。", "也有一分長，甜瓜生苦瓠。"]'),
('6a0cc4d4-3233-4ecd-a723-94714337b063','崇報洪長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','跳出黄龍三重關，撞破天童生鐵網。',88,'全唐诗/poet.song.235000.json','["跳出黄龍三重關，撞破天童生鐵網。", "量太虛空爲十尺，秤須彌山作八兩。", "信緣隨處住院，爲人處惟拳與掌，當機佛祖難近傍。", "粗行拍盲，盡直北直南數來，更無此樣。", "崇報切自知機，莫學渠儂箇伎倆。"]'),
('2b0e328c-a397-405a-9f34-c96ccd318191','印甥請贊','釋月磵','宋','宋诗','song-poetry','','[]','行脚見淳祐諸老，住院歷南北兩朝。',102,'全唐诗/poet.song.235000.json','["行脚見淳祐諸老，住院歷南北兩朝。", "不守黄龍活業，不傳太白箕裘。", "爲人處慣向弓弦上結絲，橫機時每於險處斷橋。", "設出古老文章，解教夫子咂舌。", "擧示杜撰提唱，剛要達磨點頭。", "長處全無，拙處偏優。", "是爲楊岐十一世孫月磵比丘。"]'),
('526db59a-f1fc-4a65-aa2a-1ad677493af7','家兄同幀壽容','釋月磵','宋','宋诗','song-poetry','','[]','有髮兮誰兄，無髮兮誰弟。',56,'全唐诗/poet.song.235000.json','["有髮兮誰兄，無髮兮誰弟。", "不說道與禪，不談仁與義。", "澹然相對各成翁，誰管兩朝經亂治。", "丹青寫出付昇彪，大似空中插標記。"]'),
('f45edd20-62d3-49ed-98a0-937c32753d85','景德遂長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','禪學全無拍盲，第一住山活計。',88,'全唐诗/poet.song.235000.json','["禪學全無拍盲，第一住山活計。", "竹篦三尺，怒發時鞭得虛空粉碎，編辟時拶得石人腦裂。", "更有一般沒思忖處，陳年破砂盆，却要向景德鎮裏重新燒出。", "從頭至尾數來，大元國裏長老，烈烈挈挈無如你。"]'),
('0367c383-d05e-48e0-937e-c3fce4db16a6','崇都寺請贊','釋月磵','宋','宋诗','song-poetry','','[]','貌若寬閑，性尤剛急。',58,'全唐诗/poet.song.235000.json','["貌若寬閑，性尤剛急。", "不以佛法當人情，不以慈悲爲利益。", "爲人處熱喝嗔拳，雪霜中有春消息。", "正崇爲子却孝順，見斧擔重重添石。"]'),
('584230d3-992d-4053-9364-79743665657b','源侍者請贊','釋月磵','宋','宋诗','song-poetry','','[]','渠似我，我似渠。',31,'全唐诗/poet.song.235000.json','["渠似我，我似渠。", "子相似，恰相如如處。", "畢竟何如，甜瓜生得苦葫蘆。"]'),
('25a51e82-00df-4b46-bbdb-0e41823bca5c','崇勝東源長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','蒼苔裹枯松，白雲抱幽石。',32,'全唐诗/poet.song.235000.json','["蒼苔裹枯松，白雲抱幽石。", "面目儼然□，易見還難識。", "臨濟未是白拈賊。"]'),
('89c83f63-fb79-4e97-ab66-220bf525762b','薦福魯山長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','大江以東非生緣，大江以西非受經。',138,'全唐诗/poet.song.235000.json','["大江以東非生緣，大江以西非受經。", "行脚見宋朝三十七員惡知識，末後撞入天童布絲網裏。", "折倒平生，視佛祖若大寇讎，視衲僧若大冤憎。", "五處住山，百無一能。", "無補宗教，不上傳燈。", "効尤佛照授秀岩之法席，魯山其克荷負，而道德深愧乎五宿觀堂之老僧。", "誰費丹青，點涴太清。", "只好釣雪磯頭，終朝笑看遠山青。"]'),
('c726ada2-2f72-4586-a716-0c6d3c5ceee7','隠靜空巖長老請贊','釋月磵','宋','宋诗','song-poetry','','[]','受經黄龍，而不以爲家。',110,'全唐诗/poet.song.235000.json','["受經黄龍，而不以爲家。", "親見天童，而不傳其道。", "生宋紹定，閲七十曆，有雪盈顛。", "住番薦福，踰二十年，無功可考。", "以棒喝結衲子深冤，以懶拙當人間至寶。", "隠靜無端，憑妙峯邈出，類焉個枯橋。", "似者般無禪無道無能爲底長老，盡直北直南何處討。"]'),
('353e8f48-0127-41ca-a055-9c676dea5c8c','旌德道中即事','汪夢斗','宋','宋诗','song-poetry','','[]','天氣才晴便不同，輕輕拂面有和風。',32,'全唐诗/poet.song.235000.json','["天氣才晴便不同，輕輕拂面有和風。", "溪邊春事關心處，楊柳深青杏淺紅。"]'),
('95ea47ad-4970-47c8-a318-03d3b3b1a7bd','涇縣琴臺','汪夢斗','宋','宋诗','song-poetry','','[]','石臺突兀倚晴空，一带春江瀉玉虹。',32,'全唐诗/poet.song.235000.json','["石臺突兀倚晴空，一带春江瀉玉虹。", "千古佳名喚行客，騎魚何處訪琴公。"]'),
('ca1be982-1504-4a78-8976-7fa073b52233','當途道中社','汪夢斗','宋','宋诗','song-poetry','','[]','鵲信占新霽，朝暾起樹東。',48,'全唐诗/poet.song.235000.json','["鵲信占新霽，朝暾起樹東。", "春衫欺客冷，社甕憶鄉紅。", "溪長杏花水，路蒸蘭草風。", "午餐羹枸杞，扶弱有神功。"]'),
('1781d559-2df3-415c-8527-5daa21808bff','過江陵鎮登秦申王墳讀决策元功精忠粹德碑文有感近事而賦','汪夢斗','宋','宋诗','song-poetry','','[]','力成和議得休兵，痛駡猶煩諸老生。',32,'全唐诗/poet.song.235000.json','["力成和議得休兵，痛駡猶煩諸老生。", "拘執行人招覆滅，幸逃誅死罰殊輕。"]'),
('11e127c6-04ca-46c5-9ad6-807b69fc14ca','金陵上王煥卿提刑','汪夢斗','宋','宋诗','song-poetry','','[]','英蕩觀風下帝旁，六條察吏立臺霜。',64,'全唐诗/poet.song.235000.json','["英蕩觀風下帝旁，六條察吏立臺霜。", "中原自古聞王猛，一道而今有范滂。", "園館日和歸燕樂，江城春透露桃香。", "公餘無限離騷興，故許吟人拜下牀。"]'),
('5e95d0d2-0351-47f4-92ad-ff46421e3a95','奧屯周卿提刑去年巡歷績溪回日有詩留別今依韻和呈','汪夢斗','宋','宋诗','song-poetry','','[]','皇華曾爲歙山留，笑殺揚人汎汎舟。',64,'全唐诗/poet.song.235000.json','["皇華曾爲歙山留，笑殺揚人汎汎舟。", "偶話後天非定位，懸知此輩固清流。", "一燈雪屋蟲聲細，疋馬晴川草色秋。", "倚杖儒宮橋下水，夢魂須憶舊來遊。"]'),
('a13463cb-2ad4-4c32-9096-e545b374742a','金陵僦舟渡江至儀真登陸  其一','汪夢斗','宋','宋诗','song-poetry','','[]','風冷知日落，水寬得天多。',24,'全唐诗/poet.song.235000.json','["風冷知日落，水寬得天多。", "金陵懷古句，絕唱是西河。"]'),
('d063c92c-2326-4637-9e71-e822804ddc24','金陵僦舟渡江至儀真登陸  其二','汪夢斗','宋','宋诗','song-poetry','','[]','寒波白似面，遠岫劣於眉。',24,'全唐诗/poet.song.235000.json','["寒波白似面，遠岫劣於眉。", "江上無多作，淮南正要詩。"]'),
('9f201959-10fb-4305-87e1-a326f54e1979','金陵僦舟渡江至儀真登陸  其三','汪夢斗','宋','宋诗','song-poetry','','[]','事以詩書立，國惟仁義昌。',24,'全唐诗/poet.song.235000.json','["事以詩書立，國惟仁義昌。", "當年衣带水，元不管興亡。"]'),
('3d203166-9336-40dd-b51c-0dff34e012a0','金陵僦舟渡江至儀真登陸  其四','汪夢斗','宋','宋诗','song-poetry','','[]','舟人忽驚問，春事已平分。',24,'全唐诗/poet.song.235000.json','["舟人忽驚問，春事已平分。", "江水浸鈎月，晴空橫疋雲。"]'),
('7de47cda-18f8-4a08-854a-28ef7def8fd8','金陵僦舟渡江至儀真登陸  其五','汪夢斗','宋','宋诗','song-poetry','','[]','風順帆心飽，潮平棹尾收。',24,'全唐诗/poet.song.235000.json','["風順帆心飽，潮平棹尾收。", "擁書人自卧，一息到真州。"]'),
('2a4ac5b6-ba3a-487f-9d36-668e09786b70','金陵僦舟渡江至儀真登陸  其六','汪夢斗','宋','宋诗','song-poetry','','[]','天圍春漲闊，水展夕陽紅。',24,'全唐诗/poet.song.235000.json','["天圍春漲闊，水展夕陽紅。", "已是淮南客，常吟江左風。"]'),
('85fee070-3eb1-4bd9-ac9e-b025afb3810f','清明','汪夢斗','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','他鄉逢冷食，故國隔長江。',48,'全唐诗/poet.song.235000.json','["他鄉逢冷食，故國隔長江。", "薄雨膏猶膩，落紅香滿腔。", "客遊如夢醒，愁事被春降。", "正說揚州鶴，俄來雪一雙。"]'),
('ac06d8c9-47f0-47ca-a0db-0266583aded2','枕上漫成','汪夢斗','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','偶涉長江向北來，時寒江北較花遲。',64,'全唐诗/poet.song.235000.json','["偶涉長江向北來，時寒江北較花遲。", "一春十日九風雨，百歲半生多別離。", "佛剎疎鐘催客睡，酒樓戲鼓撓人詩。", "幽燕尚在黄雲外，僂指何時是到期。"]'),
('300b2cfa-e0c2-4442-ace3-8b88dcecd000','次韻陳孝先制機論學','汪夢斗','宋','宋诗','song-poetry','','[]','詞章記覽固虛文，兀坐枯禪亦異聞。',64,'全唐诗/poet.song.235000.json','["詞章記覽固虛文，兀坐枯禪亦異聞。", "萬事當如爐上雪，一心莫起鏡中雲。", "知行互進方爲學，理欲相參及早分。", "吾道但從平實看，求之空寂便紛紜。"]'),
('2b696aa1-a7fb-4694-8ab0-8e9b0e797970','寶應城北門外登崖散步','汪夢斗','宋','宋诗','song-poetry','','[]','夾道繁陰千步强，支筇聊當踏春陽。',32,'全唐诗/poet.song.235000.json','["夾道繁陰千步强，支筇聊當踏春陽。", "野花不識興亡事，故故撩人爲送香。"]'),
('f448023b-42f8-449b-b462-0c1c7bceaaaa','山陽寄陳月觀','汪夢斗','宋','宋诗','song-poetry','','[]','匆匆分手向天涯，便憶高齋聚首時。',64,'全唐诗/poet.song.235000.json','["匆匆分手向天涯，便憶高齋聚首時。", "繞榻圖書春睡醒，一燈風雨夜談遲。", "幽州此去三千里，行客當歸六月期。", "窗枕那堪秋思澹，瀹茶細與說相思。"]'),
('937d7345-2177-4fb1-8083-b9878b1b9806','風帆夜汎清河','汪夢斗','宋','宋诗','song-poetry','','[]','風飽晴川十幅蒲，月明乘興泛玻璃。',32,'全唐诗/poet.song.235000.json','["風飽晴川十幅蒲，月明乘興泛玻璃。", "舟人生路須加謹，却道今非比舊時。"]'),
('50ee258a-bfa2-4195-b217-35e383000a9c','舟次比屋','汪夢斗','宋','宋诗','song-poetry','','[]','當年圖上看中原，欲渡長淮夢斷魂。',32,'全唐诗/poet.song.235000.json','["當年圖上看中原，欲渡長淮夢斷魂。", "今日絕淮載詩去，輕舟已自入桃源。"]'),
('fcacac42-4fae-42f7-aa7b-4687e40a9e47','桃園縣過雀杼鎮即事','汪夢斗','宋','宋诗','song-poetry','','[]','草舍三家市，蘆林半里城。',48,'全唐诗/poet.song.235000.json','["草舍三家市，蘆林半里城。", "灘乾去船澀，溪浄露沙明。", "鳥跡不見過，蚌胎隨處生。", "水心石人立，遥望似相迎。"]'),
('bfd59299-bbd6-4136-9c0a-1fc136335117','舟中與安道手談遣日','汪夢斗','宋','宋诗','song-poetry','','[]','日長消困共枰棋，適興何須苦用機。',64,'全唐诗/poet.song.235000.json','["日長消困共枰棋，適興何須苦用機。", "舟窄不妨眠對局，暑輕已覺汗沾衣。", "身如禪定一榻上，心似遊絲千里飛。", "何似清吟發天籟，精神疎暢肉生肥。"]'),
('98fcbb55-0cb8-4fa2-ba50-db82d1195feb','夜泊宿遷上流','汪夢斗','宋','宋诗','song-poetry','','[]','舊國當年闊，暑風今日生。',24,'全唐诗/poet.song.235000.json','["舊國當年闊，暑風今日生。", "舟回溪幾曲，人卧月三更。"]'),
('88a4057d-3a75-4a5f-bc63-9b9f6bbc5411','下邳永豐橋舟過其下有感','汪夢斗','宋','宋诗','song-poetry','','[]','博浪沙中擊副車，却來跪履受編書。',32,'全唐诗/poet.song.235000.json','["博浪沙中擊副車，却來跪履受編書。", "欲從圯上尋黄石，今有何人孺子如。"]'),
('bcd9397d-1b40-4513-9c57-9f3ab1c80697','呂梁洪讀宣和碑','汪夢斗','宋','宋诗','song-poetry','','[]','水落石多舟去遲，亂河西渡讀殘碑。',32,'全唐诗/poet.song.235000.json','["水落石多舟去遲，亂河西渡讀殘碑。", "三亭二閘依然在，那得安流似舊時。"]'),
('64d00d55-3179-4078-b967-bdd01a99183f','彭城有感','汪夢斗','宋','宋诗','song-poetry','','[]','河邊不見舊黄樓，綠暗荒城四月秋。',32,'全唐诗/poet.song.235000.json','["河邊不見舊黄樓，綠暗荒城四月秋。", "風捲黄沙塵拂面，有人尚憶老坡不。"]'),
('6c17706c-ee45-4961-a423-2d6857af923c','弔后山','汪夢斗','宋','宋诗','song-poetry','','[]','生平不肯見王公，蒙被清吟道自尊。',32,'全唐诗/poet.song.235000.json','["生平不肯見王公，蒙被清吟道自尊。", "寂寞彭城非昔比，風流何處覓曾孫。"]'),
('d3e6146b-e796-4af6-b174-35a454b5b056','夜宿黄河','汪夢斗','宋','宋诗','song-poetry','','[]','輕舟自挽上危灘，不見黄河古水津。',64,'全唐诗/poet.song.235000.json','["輕舟自挽上危灘，不見黄河古水津。", "天上三更下弦月，夢中萬里異鄉魂。", "苦無濁酒澆勞役，喜有清飆濯暑袢。", "曉起掀篷明望眼，蹇馿載鵲過前村。"]'),
('80c2f845-1bd3-4cc1-8eae-884d7cfd8382','沛縣道中','汪夢斗','宋','宋诗','song-poetry','','[]','謾著青鞵過小灣，偶然清暑變輕寒。',32,'全唐诗/poet.song.235000.json','["謾著青鞵過小灣，偶然清暑變輕寒。", "山行却似江南景，更有羣鵝浴碧瀾。"]'),
('da76a5c0-211c-431a-aad1-e8a8a8f9b6e4','漢高祖歌風臺','汪夢斗','宋','宋诗','song-poetry','','[]','擊筑長歌意始真，斬蛇元是感鄉人。',32,'全唐诗/poet.song.235000.json','["擊筑長歌意始真，斬蛇元是感鄉人。", "大風不起人非昔，臺下滔滔泗水春。"]'),
('2d61780e-25af-4f78-9e2e-4e8a7b94ccbe','沛城北有伍員廟碑露立荒郊有感','汪夢斗','宋','宋诗','song-poetry','','[]','吳若未亡齊未寒，辭人微意寓毫端。',32,'全唐诗/poet.song.235000.json','["吳若未亡齊未寒，辭人微意寓毫端。", "當時借爲胥祠發，似誚諸人訃契丹。"]'),
('83efb75f-dd61-490e-af8d-e9561e906e03','東行魚臺縣界初聞鶑','汪夢斗','宋','宋诗','song-poetry','','[]','新綠陰陰夏氣清，犢車穿入別村行。',32,'全唐诗/poet.song.235000.json','["新綠陰陰夏氣清，犢車穿入別村行。", "家山今隔幾千里，始聽春鶑第一聲。"]'),
('5001889f-bf4d-4ba5-8344-e335fbff480c','登魚臺讀唐梁至金人碑有感','汪夢斗','宋','宋诗','song-poetry','','[]','石臺突兀鎮荒雲，廢寺淒涼石有文。',32,'全唐诗/poet.song.235000.json','["石臺突兀鎮荒雲，廢寺淒涼石有文。", "魯國遺風無彷彿，矢魚以後幾紛紛。"]'),
('5c884c2d-dee8-4ab8-a707-e6dea622a48f','明發魚臺至古城或云即舊濟州未詳','汪夢斗','宋','宋诗','song-poetry','','[]','箕斗澄暉缺月升，茅花夾轂雪中行。',32,'全唐诗/poet.song.235000.json','["箕斗澄暉缺月升，茅花夾轂雪中行。", "曉風凜凜寒城冷，濠裏荷錢無數生。"]'),
('649603aa-2446-4ec6-9fee-e16eb22181b8','車行濟州道中即事','汪夢斗','宋','宋诗','song-poetry','','[]','客裏休歌行路難，未容歸夢繞江南。',64,'全唐诗/poet.song.235000.json','["客裏休歌行路難，未容歸夢繞江南。", "荆筐蔽弩人媒雉，桃葉懸門女飯蠶。", "故國山河今尚在，殘春道路暑先酣。", "新詩收拾中州事，歸與鄉人細細談。"]'),
('da2c8812-c210-4ceb-b686-e259f7bddb99','汶上縣西門外有梁王彥章廟金人泰和中重修廟記存','汪夢斗','宋','宋诗','song-poetry','','[]','鐵鎗戰死後梁時，消得金人爲葺祠。',32,'全唐诗/poet.song.235000.json','["鐵鎗戰死後梁時，消得金人爲葺祠。", "近歲江頭幾符節，過來須也讀殘碑。"]'),
('ac58ef16-eddc-4f12-8896-b81eb79dd5df','東平府登飛雲樓啜茶','汪夢斗','宋','宋诗','song-poetry','','[]','過樓懶上最高梯，爲愛茶香試上嬉。',32,'全唐诗/poet.song.235000.json','["過樓懶上最高梯，爲愛茶香試上嬉。", "簷外衆山供遠碧，却思鄉景下樓遲。"]'),
('d026d3be-83fd-4a5a-a21f-d0c66b4be6dc','道過茌平縣感馬周事','汪夢斗','宋','宋诗','song-poetry','','[]','卧駕馿車入博州，青山淡淡夕陽愁。',32,'全唐诗/poet.song.235000.json','["卧駕馿車入博州，青山淡淡夕陽愁。", "翻思故國今何在，枉抱忠肝似馬周。"]'),
('a986fecc-5461-4a4d-b89b-2539c518b6a6','高唐州戲作','汪夢斗','宋','宋诗','song-poetry','','[]','錯賦巫山十二峯，西南與北偶名同。',32,'全唐诗/poet.song.235000.json','["錯賦巫山十二峯，西南與北偶名同。", "便饒真是陽臺路，行雨才收夢亦空。"]'),
('d292874f-06e4-4949-9d79-2b4406526571','道中不見山水','汪夢斗','宋','宋诗','song-poetry','','[]','有山無水山枯槁，有水無山水汗漫。',32,'全唐诗/poet.song.235000.json','["有山無水山枯槁，有水無山水汗漫。", "此處無山亦無水，風砂捲地鼻生酸。"]'),
('afda8287-d30a-4b62-b7d8-1967daa357c7','過御河有感','汪夢斗','宋','宋诗','song-poetry','','[]','轉漕東南由汴力，此河今日力猶多。',32,'全唐诗/poet.song.235000.json','["轉漕東南由汴力，此河今日力猶多。", "隋疲民力亡天下，却爲他人浚兩河。"]'),
('b25d6a75-8944-4f6b-8662-ba8ae8b794e1','景州道中','汪夢斗','宋','宋诗','song-poetry','','[]','驛路車聲軟，斜暉雨脚收。',24,'全唐诗/poet.song.235000.json','["驛路車聲軟，斜暉雨脚收。", "柳陰家曉鵲，桑椹醉春鳩。"]'),
('7733a7eb-cf26-4af6-9b31-ef731adc480e','雄州北城外過白溝河','汪夢斗','宋','宋诗','song-poetry','','[]','手斧當年自畫河，聖人微意不求多。',32,'全唐诗/poet.song.235000.json','["手斧當年自畫河，聖人微意不求多。", "如何王蔡忘前事，可謂貪他却著他。"]'),
('7d4d5470-1755-4562-9aa5-2168326e3b90','道中渴水','汪夢斗','宋','宋诗','song-poetry','','[]','轆轤無處汲甘泉，惱得相如肺疾生。',32,'全唐诗/poet.song.235000.json','["轆轤無處汲甘泉，惱得相如肺疾生。", "憶著江南山裏路，時時一酌骨毛清。"]'),
('74a03442-dd1a-4d4f-834d-330a73b14560','曉入涿州界看太行山','汪夢斗','宋','宋诗','song-poetry','','[]','曉風刮骨似嚴寒，漠漠吹沙塞鼻關。',32,'全唐诗/poet.song.235000.json','["曉風刮骨似嚴寒，漠漠吹沙塞鼻關。", "卧入范陽元不覺，醒來忽見太行山。"]'),
('173aac0b-5e91-42ee-bb93-47962fd4e217','連日曉行就車擁衾不得卧','汪夢斗','宋','宋诗','song-poetry','','[]','處處風吹碧草生，流星時渡絳河明。',32,'全唐诗/poet.song.235000.json','["處處風吹碧草生，流星時渡絳河明。", "上車却欲補殘睡，無數樹陰啼亂鶑。"]'),
('e90923fc-897f-4624-9606-89cd146a6556','宛平道中即事','汪夢斗','宋','宋诗','song-poetry','','[]','驚心卵石礙，劈面老沙吹。',24,'全唐诗/poet.song.235000.json','["驚心卵石礙，劈面老沙吹。", "越見天闊處，不見雲盡期。"]'),
('daa67d06-7b9a-47d2-965c-eeb478f157b6','入都門漫賦','汪夢斗','宋','宋诗','song-poetry','','[]','粉圍萬雉拱宸居，新邑由來草創初。',64,'全唐诗/poet.song.235000.json','["粉圍萬雉拱宸居，新邑由來草創初。", "省署朝衣雜貍鼠，市廛人跡混龍魚。", "望時已近行難到，在處皆寬住似疎。", "草舞南風半黄碧，客窗幽坐恰便書。"]'),
('03809f9c-9340-498e-b1dd-01794d1665c7','簡鄉人丘同知舜臣','汪夢斗','宋','宋诗','song-poetry','','[]','不愛一身死，以全千里生。',48,'全唐诗/poet.song.235000.json','["不愛一身死，以全千里生。", "羣言更廉潔，此事甚分明。", "心白天應見，官卑自莫爭。", "于公厚陰德，尚欲子孫榮。"]'),
('81f6e40c-c830-4ff7-98f4-4766e58b1c83','見禮部尚書謝公昌言','汪夢斗','宋','宋诗','song-poetry','','[]','曾將鴻筆冠羣英，自是峨眉第一人。',64,'全唐诗/poet.song.235000.json','["曾將鴻筆冠羣英，自是峨眉第一人。", "執志只期東海死，傷心老作北朝臣。", "叔孫入漢儀方制，箕子歸周範已陳。", "□□□□□□□，正須自愛不貲身。"]'),
('ca7d935f-aaf9-44e3-a0ca-e9e17f7cd4cf','經行舊城過宣聖廟欲看石鼓不得入','汪夢斗','宋','宋诗','song-poetry','','[]','牆院人家少市聲，高槐古柳綠初新。',64,'全唐诗/poet.song.235000.json','["牆院人家少市聲，高槐古柳綠初新。", "陰雲猶閣西山雨，城郭常吹東海塵。", "杏頰簪花紅照樹，蟲絲羅巷晝窺人。", "岐陽石鼓無由見，深鎖儒宮碧草春。"]'),
('fc1615c1-7be8-41e2-9e6b-7d30eb229ebd','端午','汪夢斗','宋','宋诗','song-poetry','','[]','辜負昌陽酒一盃，異鄉節物苦相催。',64,'全唐诗/poet.song.235000.json','["辜負昌陽酒一盃，異鄉節物苦相催。", "榴花未見已夏半，梅子空黄無雨來。", "下士蜀皇不復産，愛君屈子有餘哀。", "江南儘自多魚米，好趁凉風及早回。"]'),
('9246676c-de87-478f-9b10-852af02df29a','無題  其一','汪夢斗','宋','宋诗','song-poetry','','[]','磵邊竹樹絕幽香，燕坐雲根寫洞章。',32,'全唐诗/poet.song.235000.json','["磵邊竹樹絕幽香，燕坐雲根寫洞章。", "馬上行人重回首，只知草軟卧牛羊。"]'),
('d03b3b0f-5b52-4bc2-8bc5-fec31693db3a','無題  其二','汪夢斗','宋','宋诗','song-poetry','','[]','海風吹上一天秋，獨卧扁舟自在流。',32,'全唐诗/poet.song.235000.json','["海風吹上一天秋，獨卧扁舟自在流。", "傾盡酒壺人已醉，却橫長笛荻花洲。"]'),
('52c905a7-b048-454f-bb57-676d8496fc59','上趙簽推  其一','汪夢斗','宋','宋诗','song-poetry','','[]','名父由來産哲兒，一門忠孝藹芳菲。',64,'全唐诗/poet.song.235000.json','["名父由來産哲兒，一門忠孝藹芳菲。", "自從藩府馳朱轂，久缺庭闈戲綵衣。", "兵筦少淹當遂相，樊川已得未容歸。", "魯公居外周公內，清夜相思魂夢飛。"]'),
('76f92af9-8f2e-4a89-969e-c8eb0160bc35','上趙簽推  其二','汪夢斗','宋','宋诗','song-poetry','','[]','我本郎君屬部民，今朝堂上拜靈樁。',64,'全唐诗/poet.song.235000.json','["我本郎君屬部民，今朝堂上拜靈樁。", "閑閑而後無名手，寂寂之餘有此人。", "千里家書常訓子，一言心事在褆身。", "仙翁若問吾州政，萬碧樓空不染塵。"]'),
('5591dbe0-d517-4309-b29e-53ba2c7a46e7','富春方史君萬里與之別七年矣離亂之後不意得聚首於此一見道舊有感  其一','汪夢斗','宋','宋诗','song-poetry','','[]','兩邊髯鬢雪交明，一笑何期在客京。',64,'全唐诗/poet.song.235000.json','["兩邊髯鬢雪交明，一笑何期在客京。", "此會向來隨是夢，相逢喜定却還驚。", "清吟自足配嚴瀨，狂語常憂沈石城。", "我定先還故山去，先生恰有北燕行。"]'),
('cd8cd846-d6b2-4c45-8b70-7de9556d634e','富春方史君萬里與之別七年矣離亂之後不意得聚首於此一見道舊有感  其二','汪夢斗','宋','宋诗','song-poetry','','[]','少年紅燭照銀巵，頗憶沙河共客衣。',64,'全唐诗/poet.song.235000.json','["少年紅燭照銀巵，頗憶沙河共客衣。", "今說宣威麟可佩，爭如華表鶴來歸。", "秋香歙浦秔先熟，春早祁山筍更肥。", "茗飲蕭齋客見過，舊遊談麈雪霏霏。"]'),
('f8fd2cbd-d21b-4564-9f68-f64e4ff54378','富春方史君萬里與之別七年矣離亂之後不意得聚首於此一見道舊有感  其三','汪夢斗','宋','宋诗','song-poetry','','[]','衣冠屈辱但長吁，爲笑吾徒事業迂。',64,'全唐诗/poet.song.235000.json','["衣冠屈辱但長吁，爲笑吾徒事業迂。", "無救於亡焉用相，不知所任正非儒。", "天初生摯意有謂，人獨存箕道未孤。", "迓續斯文難別諉，願弘正學福寰區。"]'),
('0c5d322a-ec45-4582-80a2-a1068ce93044','暑中','汪夢斗','宋','宋诗','song-poetry','','[]','謾說江南暑鬰蒸，渠知此處烈於焚。',64,'全唐诗/poet.song.235000.json','["謾說江南暑鬰蒸，渠知此處烈於焚。", "團蠅對面如樓子，蠆蚤侵肌似錦文。", "病瘦带圍寬一尺，事荒才思退三分。", "夢魂自有清凉處，還看冰衣水皺裙。"]'),
('915ca0cf-8ffd-4734-a65a-99fdd5ee4f34','書感','汪夢斗','宋','宋诗','song-poetry','','[]','驅馳萬里且歸休，三十餘年只漫遊。',32,'全唐诗/poet.song.235000.json','["驅馳萬里且歸休，三十餘年只漫遊。", "已死舒何叫不起，霜松雪桂一山秋。"]'),
('ac6a40c5-96dc-45d5-af2e-0e9ba1637705','丘舜臣遣人還鄉托以家書時六月望因走筆寄主學胡君及士招學正諸同舍','汪夢斗','宋','宋诗','song-poetry','','[]','夢亦何曾渡白溝，今朝却作等閒遊。',64,'全唐诗/poet.song.235000.json','["夢亦何曾渡白溝，今朝却作等閒遊。", "橫雲鶴倦性猶野，嘶雨蟬哀信已秋。", "此事欲知詩儘有，西園才說肺先浮。", "歸途亦及中秋月，乘興同登何處樓。"]'),
('944d653d-dc85-41ee-b943-d6ad9cc8d33d','安道改授休寧尹令郎仲坦祁門尹再成小詩','汪夢斗','宋','宋诗','song-poetry','','[]','父子雙飛對對鳬，弦歌聲接倚州閭。',64,'全唐诗/poet.song.235000.json','["父子雙飛對對鳬，弦歌聲接倚州閭。", "身同華表歸家鶴，壽介庭闈潑甕蛆。", "薯斸率山寒玉挺，筍披閶水小犀株。", "羹餘親釜應分餉，爲攪饑腸幾卷書。"]'),
('2134b638-a1ae-4b0c-b41e-98764fc3a140','城中將相第宅樹之以木殊多茂盛因憶家園有賦','汪夢斗','宋','宋诗','song-poetry','','[]','屋頭花竹已成林，奪與燕山萬里心。',32,'全唐诗/poet.song.235000.json','["屋頭花竹已成林，奪與燕山萬里心。", "帝里雖云多勝宅，何須底事覓清陰。"]'),
('f34d8f59-04c7-4f18-b073-8e8c72a2863d','七月五夜枕上漫作悲秋一首時痔下猶未愈','汪夢斗','宋','宋诗','song-poetry','','[]','楚客悲秋已自愁，況於客病事悠悠。',64,'全唐诗/poet.song.235000.json','["楚客悲秋已自愁，況於客病事悠悠。", "金燈對我吟清夜，苔研賺人空白頭。", "猶許存名參釋老，那知有道本伊周。", "風翻木葉露初下，笑指家林歸去休。"]'),
('8e1fe0e1-1e4b-4b76-9211-ac3d89f1a208','巧節','汪夢斗','宋','宋诗','song-poetry','','[]','新凉遡晚風，一笑偶相同。',48,'全唐诗/poet.song.235000.json','["新凉遡晚風，一笑偶相同。", "有景如荒野，無雲障太空。", "涓涓渠水綠，樹樹蓼花紅。", "星會俄已過，風光歎轉蓬。"]'),
('86b2a833-9f80-46a3-be92-eaf46c9e212d','羈燕四十餘日歸興殊切口占賦歸  其一','汪夢斗','宋','宋诗','song-poetry','','[]','朝來收拾掛風蒲，肯效當年賤丈夫。',64,'全唐诗/poet.song.235000.json','["朝來收拾掛風蒲，肯效當年賤丈夫。", "尚有耕廬寄汾曲，豈無卜肆在成都。", "荷移凉意歸紅蓼，竹讓秋聲與碧梧。", "寂寞南朝亡國恨，當時爲不用真儒。"]'),
('6f3ad8d2-e755-4c04-830f-45fee5eab64f','羈燕四十餘日歸興殊切口占賦歸  其二','汪夢斗','宋','宋诗','song-poetry','','[]','水畔斜陽萬馬行，柳邊殘雨一蟬鳴。',64,'全唐诗/poet.song.235000.json','["水畔斜陽萬馬行，柳邊殘雨一蟬鳴。", "催人老去何忙甚，覺我新來太瘦生。", "不死雖然如管仲，有生終是愧淵明。", "商飆愈緊歸心切，莫把詩書博惡名。"]'),
('43796997-73e8-4c8b-b1fe-a39f568ced5e','羈燕四十餘日歸興殊切口占賦歸  其三','汪夢斗','宋','宋诗','song-poetry','','[]','士節陵夷久可憐，謂宜作氣一時伸。',64,'全唐诗/poet.song.235000.json','["士節陵夷久可憐，謂宜作氣一時伸。", "恰求諤諤廷中辯，亦似厭厭泉下人。", "身死首陽名不死，家貧陋巷道非貧。", "世推五運今何運，歸去何如老海濱。"]'),
('2f6eb42d-2584-4a88-9c18-ae9150f90cd2','羈燕四十餘日歸興殊切口占賦歸  其四','汪夢斗','宋','宋诗','song-poetry','','[]','三間小屋枕山邊，一縷沈烟謝老天。',64,'全唐诗/poet.song.235000.json','["三間小屋枕山邊，一縷沈烟謝老天。", "康節雖貧猶自樂，希夷當亂只高眠。", "道非日用常行外，心在吾身未有前。", "歸去重參教透徹，何須更用羨神仙。"]'),
('7ace21ac-727a-45ac-9b99-aee3a606e7a1','羈燕四十餘日歸興殊切口占賦歸  其五','汪夢斗','宋','宋诗','song-poetry','','[]','身到嬴秦古塞垣，茫茫禹迹故皆存。',64,'全唐诗/poet.song.235000.json','["身到嬴秦古塞垣，茫茫禹迹故皆存。", "近來粵客通南貨，舊日燕人祭北門。", "治極漢唐猶駁雜，功侔禹稷有根源。", "紀綱法度於何是，歸醉牀頭老瓦盆。"]'),
('60ae0783-6953-4b1f-b1d2-f53f9819a93e','羈燕四十餘日歸興殊切口占賦歸  其六','汪夢斗','宋','宋诗','song-poetry','','[]','留連荒邸況栖栖，席地跧蹲四體胝。',64,'全唐诗/poet.song.235000.json','["留連荒邸況栖栖，席地跧蹲四體胝。", "飲量素慳愁對酒，殺機元淺倦招棋。", "相傳帝統須求正，莫使王風久下衰。", "歸去林間洗雙眼，暮年要看太平時。"]'),
('283db061-3c8e-4bfc-9fd8-bac77553345f','羈燕四十餘日歸興殊切口占賦歸  其七','汪夢斗','宋','宋诗','song-poetry','','[]','世道茫茫未解憂，新凉行色且歸休。',64,'全唐诗/poet.song.235000.json','["世道茫茫未解憂，新凉行色且歸休。", "四年擾擾春如夢，五袠駸駸老轉愁。", "禹貢九州行半矣，周家十亂有人不。", "浣紗雲冷徽山月，不似林間樂一丘。"]'),
('6f18eef8-3702-4a7c-b86c-e8a3b63aaedd','羈燕四十餘日歸興殊切口占賦歸  其八','汪夢斗','宋','宋诗','song-poetry','','[]','商量何必又商量，休笑吾人議論長。',64,'全唐诗/poet.song.235000.json','["商量何必又商量，休笑吾人議論長。", "事欠剸裁多積壓，心猶疑忌少擔當。", "無由把袖舒衷憤，空負懸弧射四方。", "只恐秋風破茅屋，急歸爛賞木犀香。"]'),
('c3315100-1085-40b1-b703-869eebdd8820','次韻效都堂薰風詩','汪夢斗','宋','宋诗','song-poetry','','[]','輕飆鼓入五弦琴，都是重華育物心。',32,'全唐诗/poet.song.235000.json','["輕飆鼓入五弦琴，都是重華育物心。", "唐殿微凉只專嚮，何如四海共清陰。"]'),
('661c76de-ea26-412f-90b2-1b30ad1282fe','問候趙簽推','汪夢斗','宋','宋诗','song-poetry','','[]','龜疇五福屬鴻儒，壽骨清强病應無。',64,'全唐诗/poet.song.235000.json','["龜疇五福屬鴻儒，壽骨清强病應無。", "要識維摩今示病，當知涑水本來癯。", "心從空想塵無染，念到忘時氣自蘇。", "此說雖非儒所道，於中恐亦有工夫。"]'),
('abb92021-c230-4d0d-b6f7-81b3e300314e','送江東李宣副之官建鄴','汪夢斗','宋','宋诗','song-poetry','','[]','田里創殘疚正深，望醫起死息呻吟。',64,'全唐诗/poet.song.235000.json','["田里創殘疚正深，望醫起死息呻吟。", "神功那用千金藥，妙處都由一寸心。", "劍外空遺喬木望，江東將有憇棠陰。", "十分存省新甿了，歸轉洪鈞普作霖。"]'),
('801ea2bd-d1ac-4bad-ba55-42cb476c1dcf','八月十四夜月食','汪夢斗','宋','宋诗','song-poetry','','[]','盡日陰雲蔽太虛，夜深却見太陰虧。',32,'全唐诗/poet.song.235000.json','["盡日陰雲蔽太虛，夜深却見太陰虧。", "老天故露妖蟇惡，要索盧仝寸鐵詩。"]'),
('623bbbee-d7df-421e-967a-2e13663a2b92','寄安道','汪夢斗','宋','宋诗','song-poetry','','[]','世儒多誤入旁門，默坐求心謂道尊。',64,'全唐诗/poet.song.235000.json','["世儒多誤入旁門，默坐求心謂道尊。", "知不兼行無實力，體非有用是空言。", "窮探天命理爲主，盡得人彜性自存。", "寄語寒氈分鄭老，待提此話破昏昏。"]'),
('74ec8272-5303-4af1-a9ef-6665002963b8','風起揚埃如天舞','汪夢斗','宋','宋诗','song-poetry','','[]','卷地飛埃逐曉飆，盤旋曲折勢飄颻。',32,'全唐诗/poet.song.235000.json','["卷地飛埃逐曉飆，盤旋曲折勢飄颻。", "筵前舊說回風舞，今見娉婷楚女腰。"]'),
('9111fe36-f0ac-49bd-9517-2cba6bb5c146','別左司杜郎中','汪夢斗','宋','宋诗','song-poetry','','[]','相見匆匆即告歸，江南魚米儘堪娛。',64,'全唐诗/poet.song.235000.json','["相見匆匆即告歸，江南魚米儘堪娛。", "樹林浩有秋聲老，客路誰憐月影孤。", "班序自還君富貴，齋居猶著己工夫。", "他時重會無他說，敢問於仁已近無。"]'),
('1a36e7f1-c13d-43be-bf49-a47689375714','簡楊治中','汪夢斗','宋','宋诗','song-poetry','','[]','當年北騎壓杭城，奮起渡江尋舊盟。',64,'全唐诗/poet.song.235000.json','["當年北騎壓杭城，奮起渡江尋舊盟。", "本擬鄭僑成好去，寧知徐鉉播文名。", "從班真是覺來夢，別駕猶如退步行。", "上介尚能分閫去，不應班爵獨公輕。"]'),
('e5b92fa3-8e2b-438a-a830-0ffad2ff5c0a','別方萬里  其一','汪夢斗','宋','宋诗','song-poetry','','[]','異鄉成邂逅，却是受恩深。',48,'全唐诗/poet.song.235000.json','["異鄉成邂逅，却是受恩深。", "白雪千絲髮，青山一掬心。", "夢殘橫老淚，悲極輒高吟。", "此意都相似，鍾期合鑄金。"]'),
('c60868dd-e20e-4e5a-8394-2984a6137669','別方萬里  其二','汪夢斗','宋','宋诗','song-poetry','','[]','門外桑乾水，我行君尚留。',48,'全唐诗/poet.song.235000.json','["門外桑乾水，我行君尚留。", "話長見恨晚，情苦意如秋。", "此道今垂絕，何人可與謀。", "臨行重分首，吾教尚多憂。"]'),
('b86fb6f4-43a1-498b-b8f5-e36e8c2135ca','柯山趙公屢更麾節多在浙東西皆有美政德祐正爲浙東憲入景炎猶爲閩浙招捕今被召入覲從行幕客則吳元鎮與朱景日武博景日向在上庠亦辱識此來所館相去差遠至是出舊城方能報元鎮謁併言別故就訪景日不遇却因得見招捕公蒙謙接元鎮訝其無詩爲贄口占三首奉呈資一笑  其一','汪夢斗','宋','宋诗','song-poetry','','[]','淒涼路入古神州，況復驅車渡白溝。',64,'全唐诗/poet.song.235000.json','["淒涼路入古神州，況復驅車渡白溝。", "蜀主未能重造漢，商孫不免亦侯周。", "九重注想聞猶告，五事開陳動冕旒。", "耿耿胸中有餘意，西山老碧不勝秋。"]'),
('4bd5304d-dbc5-49ff-bdb2-2a9b4be30893','柯山趙公屢更麾節多在浙東西皆有美政德祐正爲浙東憲入景炎猶爲閩浙招捕今被召入覲從行幕客則吳元鎮與朱景日武博景日向在上庠亦辱識此來所館相去差遠至是出舊城方能報元鎮謁併言別故就訪景日不遇却因得見招捕公蒙謙接元鎮訝其無詩爲贄口占三首奉呈資一笑  其二','汪夢斗','宋','宋诗','song-poetry','','[]','遺愛曾留浙水濆，北方正自素相聞。',64,'全唐诗/poet.song.235000.json','["遺愛曾留浙水濆，北方正自素相聞。", "長途賡唱多名筆，舊府賓僚盡富文。", "往昔知音有吳季，從來難吏是朱雲。", "聯鑣向闕成嚴覲，拜得恩言定不羣。"]'),
('ebff5f13-00de-4faf-a71a-e5dce0c3b9bd','柯山趙公屢更麾節多在浙東西皆有美政德祐正爲浙東憲入景炎猶爲閩浙招捕今被召入覲從行幕客則吳元鎮與朱景日武博景日向在上庠亦辱識此來所館相去差遠至是出舊城方能報元鎮謁併言別故就訪景日不遇却因得見招捕公蒙謙接元鎮訝其無詩爲贄口占三首奉呈資一笑  其三','汪夢斗','宋','宋诗','song-poetry','','[]','當年不得拜前呵，相遇今時可奈何。',64,'全唐诗/poet.song.235000.json','["當年不得拜前呵，相遇今時可奈何。", "病骨已愁飛雪早，衰年敢謂見天多。", "既無上策裨朝論，惟有東還聽壤歌。", "出處從知元有分，忍言兼善脫槃邁。"]'),
('9aba6a62-0e78-4629-b5fd-ac134c64f0cf','上故相留公  其一','汪夢斗','宋','宋诗','song-poetry','','[]','蒼天有意不能違，行邁心摇賦黍離。',64,'全唐诗/poet.song.235000.json','["蒼天有意不能違，行邁心摇賦黍離。", "弼既遭艱尋罷政，質如在位必遲疑。", "身逢今日多休問，事在當年偶少思。", "緣是庚申輕放入，力爭不似甲辰時。"]'),
('0bf8766a-5532-49cf-abab-15476857b228','上故相留公  其二','汪夢斗','宋','宋诗','song-poetry','','[]','明倫一疏筆如椽，痛掃凶邪四海傳。',64,'全唐诗/poet.song.235000.json','["明倫一疏筆如椽，痛掃凶邪四海傳。", "故使北人騎屋望，時聞南面獨班宣。", "雖言上眷尤濃甚，只著前銜固愴然。", "舊日恩堂炊已熟，夕陽敗柳奈號蟬。"]'),
('8a83446b-3422-4378-8b93-a11a68c6a36c','留示逯雲甫秀才  其一','汪夢斗','宋','宋诗','song-poetry','','[]','萬里舟車要覓詩，衰年忍負始來時。',64,'全唐诗/poet.song.235000.json','["萬里舟車要覓詩，衰年忍負始來時。", "未成班氏兩京賦，僅見韓山一片碑。", "歸信正須傳雁帛，秋風不爲憶蓴絲。", "今朝再渡桑乾水，月朗風清誰繫思。"]'),
('0b8886a5-619e-476c-b500-004780c48902','留示逯雲甫秀才  其二','汪夢斗','宋','宋诗','song-poetry','','[]','遺山諸老號儒宗，竊與余懷正不同。',64,'全唐诗/poet.song.235000.json','["遺山諸老號儒宗，竊與余懷正不同。", "了得高吟猶小技，窮知實理是全功。", "生民皆本詩書出，宇宙元包性分中。", "來此無人同我意，拳拳望子革頹風。"]'),
('a904c15c-0f27-4484-86f1-9a7edce948b5','車出范陽界望太行已不見','汪夢斗','宋','宋诗','song-poetry','','[]','又別太行去，征衫浥淚班。',36,'全唐诗/poet.song.235000.json','["又別太行去，征衫浥淚班。", "仙游在北岳，騷興滿西山。", "世換碧如古，雲收意似閒。"]'),
('7924d718-0448-4bcd-ba85-4830a087d1ed','雄州回陽柳在城南郝莊有碑','汪夢斗','宋','宋诗','song-poetry','','[]','敗柳能消藥一圓，鵝黄裊裊復春妍。',32,'全唐诗/poet.song.235000.json','["敗柳能消藥一圓，鵝黄裊裊復春妍。", "世間真有回陽事，却道枯骸不解仙。"]'),
('d1f72990-7aa4-4c42-bbb9-388e04db0574','連日車行風寒','汪夢斗','宋','宋诗','song-poetry','','[]','不奈淒風透敝裘，高眠車上被蒙頭。',64,'全唐诗/poet.song.235000.json','["不奈淒風透敝裘，高眠車上被蒙頭。", "自憐病骨生來弱，莫恨客途寒可憂。", "雅操素持四不出，狂吟且和二宜休。", "家鄉才喜清無暑，露下芙蓉一院秋。"]'),
('78b0ed07-2f7e-48e9-a0a7-996db7c4a6e8','貝丘道中看王莽所塞黄河舊迹','汪夢斗','宋','宋诗','song-poetry','','[]','從來四瀆各入海，底事黄河今亂淮。',32,'全唐诗/poet.song.235000.json','["從來四瀆各入海，底事黄河今亂淮。", "新莽智欲出神禹，坐令四瀆名實乖。"]'),
('19b32dd4-d37c-4287-88f7-c192d0443a5c','東平道中追思來途','汪夢斗','宋','宋诗','song-poetry','','[]','去時薰入五絃琴，汶上繁陰暑氣清。',32,'全唐诗/poet.song.235000.json','["去時薰入五絃琴，汶上繁陰暑氣清。", "寂寞荒村驚葉落，又驅雙轂過龜陰。"]'),
('5fe63bf2-2e73-4c63-8eea-297169c75431','九日前一日過東平城中見賣糕有感','汪夢斗','宋','宋诗','song-poetry','','[]','獵獵霜飆颭菊枝，盤中粉餌趁時炊。',32,'全唐诗/poet.song.235000.json','["獵獵霜飆颭菊枝，盤中粉餌趁時炊。", "承平節物今猶見，却憶劉郎舊欠詩。"]'),
('a73e3882-7a65-4c4a-b3b3-555482c04ea8','汶陽重九','汪夢斗','宋','宋诗','song-poetry','','[]','燒燈纔了客天涯，秋過重陽未到家。',64,'全唐诗/poet.song.235000.json','["燒燈纔了客天涯，秋過重陽未到家。", "自歎滿梳搔白髮，不堪好酒對黄花。", "折腰肯使羞元亮，落帽多應罪孟嘉。", "寂寞汶陽溪上路，寒風拂柳晚陰斜。"]'),
('c9b2638f-56cd-4963-bdc4-eeddc1b1660e','濟州至魯橋鎮即事','汪夢斗','宋','宋诗','song-poetry','','[]','過了潘郎一句詩，塗中風雨尚垂垂。',64,'全唐诗/poet.song.235000.json','["過了潘郎一句詩，塗中風雨尚垂垂。", "少人耕處地最闊，多日陰時秋更悲。", "山向近來青淡淡，樹因遠看黑離離。", "魯橋有水租船去，明眼先朝一片碑。"]'),
('0ccc7615-24b9-4383-bea6-86b662323ae2','明發魯橋鎮舟行','汪夢斗','宋','宋诗','song-poetry','','[]','泗水阻小艇，孤汀恰水生。',48,'全唐诗/poet.song.235000.json','["泗水阻小艇，孤汀恰水生。", "一炊雲外熟，雙櫂雨中行。", "衣醭梅天潤，蓬疎臘月清。", "江南稍有侶，鵲報曉來晴。"]'),
('46fa24d5-0fdf-4d8b-bca4-d8d91eef01da','舟次耿山喜霽','汪夢斗','宋','宋诗','song-poetry','','[]','曉來乘雨過留城，屈指徐州一百程。',32,'全唐诗/poet.song.235000.json','["曉來乘雨過留城，屈指徐州一百程。", "到得耿山程已半，雲收特地放新晴。"]'),
('ff18cb14-d3b0-41ec-8f76-e41c7b7d3afb','向曉風順掛帆','汪夢斗','宋','宋诗','song-poetry','','[]','頑陰破處見秋空，十幅枯蒲飽晚風。',32,'全唐诗/poet.song.235000.json','["頑陰破處見秋空，十幅枯蒲飽晚風。", "驚得野鳬連族起，蓼花兩岸獻生紅。"]'),
('2135b871-01db-4f69-9580-1d1a29118b1f','睡中過彭城','汪夢斗','宋','宋诗','song-poetry','','[]','驚殘曉夢語啾啾，頻喚移篙看石頭。',32,'全唐诗/poet.song.235000.json','["驚殘曉夢語啾啾，頻喚移篙看石頭。", "已過徐州元不覺，依前不得上黄樓。"]'),
('2897f831-135b-4391-9906-22c8647eb952','重題呂梁洪','汪夢斗','宋','宋诗','song-poetry','','[]','新安江最險，此險越艱難。',48,'全唐诗/poet.song.235000.json','["新安江最險，此險越艱難。", "亂石紛如錯，涓流曲若環。", "危爭分寸地，只在折旋間。", "何似平夷了，輕舟利往還。"]'),
('ecc3f1fc-67a1-48b7-a918-3e2df720258d','月夜舟行晚發呂梁洪下近更餘到雙溝','汪夢斗','宋','宋诗','song-poetry','','[]','熒起長庚落，霽空秋意寬。',48,'全唐诗/poet.song.235000.json','["熒起長庚落，霽空秋意寬。", "水光涵月白，霜氣挾風寒。", "舟取北爲近，川流泗最安。", "鴈聲重嘹唳，莫是夜將闌。"]'),
('9cc00ced-bb82-44bf-97b9-729bf9c21618','舟過桃源至下流近申刻舟人欲取小清河出淮謂可省路四十里既入小清河乘潮亟行舟去如駃次早已至山陽','汪夢斗','宋','宋诗','song-poetry','','[]','前來不得由捷徑，今日才能據要津。',64,'全唐诗/poet.song.235000.json','["前來不得由捷徑，今日才能據要津。", "水趁晚潮勢殊順，岸陳秋綠迹相親。", "因知客路無多日，喜到家時恰小春。", "曉絕淮流却扶杖，逢人便謂即鄉人。"]'),
('9a415008-327b-46af-9123-5ed8bbf837e4','易舟泛邗溝有懷來塗','汪夢斗','宋','宋诗','song-poetry','','[]','過得淮來便是家，沿流草樹尚芳華。',32,'全唐诗/poet.song.235000.json','["過得淮來便是家，沿流草樹尚芳華。", "幽燕回首黄雲外，想見寒風舞雪花。"]'),
('034ec678-49e6-4403-a7e5-80f2f1599747','維揚見陳孝先制機辱授館因呈小詩見意','汪夢斗','宋','宋诗','song-poetry','','[]','倦客秋帆歸較遲，亦聞采藻魯侯池。',64,'全唐诗/poet.song.235000.json','["倦客秋帆歸較遲，亦聞采藻魯侯池。", "不煩下榻眠高士，寧復登樓卧小兒。", "病菊耐霜癯似我，寒風吹面鬢如絲。", "君非能出不能處，心事相同因得知。"]'),
('957634e2-96a0-4f39-beac-4bf8673311f6','呈隆興總管王都水友直  其一','汪夢斗','宋','宋诗','song-poetry','','[]','南朝舊名族，貴盛數諸王。',48,'全唐诗/poet.song.235000.json','["南朝舊名族，貴盛數諸王。", "亡國恨何極，餘生計尚長。", "風流豫章守，人物水曹郎。", "客裏吟尤苦，秋江卧夕陽。"]'),
('034f1254-2038-4420-9cf2-f414d6dceb0e','呈隆興總管王都水友直  其二','汪夢斗','宋','宋诗','song-poetry','','[]','當日鳳臺下，鹿鳴同著鞭。',48,'全唐诗/poet.song.235000.json','["當日鳳臺下，鹿鳴同著鞭。", "魚龍既懸絕，鷄犬竟難仙。", "危葉愁霜病，寒花紛晚妍。", "幽窗論舊事，客抱固淒然。"]'),
('f27aa82d-9608-43d7-b3aa-54b623dacd32','揚子橋','汪夢斗','宋','宋诗','song-poetry','','[]','又撐舴艋下邗溝，霽色橫空宿雨收。',32,'全唐诗/poet.song.235000.json','["又撐舴艋下邗溝，霽色橫空宿雨收。", "已入伊婁河裏去，來朝穩穩飯真州。"]'),
('1cde0b8b-effe-43cd-8a51-92ea1882106b','渡江至龍潭即事','汪夢斗','宋','宋诗','song-poetry','','[]','敗蘆衰柳落江隈，才見黄雲接畮堆。',64,'全唐诗/poet.song.235000.json','["敗蘆衰柳落江隈，才見黄雲接畮堆。", "舟趁瀾狂斜入浦，帆因風飽不依桅。", "青山數閲世興廢，白鳥靜窺人去來。", "地暖江南未吹雪，小春天氣正尋梅。"]'),
('c42c550b-96d2-44ed-a9d4-e8365bdc9d6f','竹篠村店肆筆','汪夢斗','宋','宋诗','song-poetry','','[]','西望武昌東夏口，下窺鐵甕固依然。',64,'全唐诗/poet.song.235000.json','["西望武昌東夏口，下窺鐵甕固依然。", "英雄爭戰幾編史，狂客浮遊一葉船。", "把酒臨風懷古處，題詩記我過江年。", "謾言足跡半天下，未必詩名所在傳。"]'),
('994ce2d0-5976-48d7-a00d-0e76bed888dd','上宣副定甫十二韻','汪夢斗','宋','宋诗','song-poetry','','[]','建鄴古都會，東南氣勢雄。',144,'全唐诗/poet.song.235000.json','["建鄴古都會，東南氣勢雄。", "宣流分漢使，禮樂有周公。", "自是通儒術，元非急治功。", "一江秋色外，九郡月明中。", "雲澤遍田里，聲華徹昊穹。", "藩方小盤薄，廊廟即舂容。", "力可安燕祚，學能傳孔宗。", "經綸方寸起，勳德古人同。", "妄息五官寂，靈存萬慮空。", "井寒那起浪，木靜不驚風。", "定者心之主，行兮用以充。", "蒼生望霖雨，寧久蟄泥龍。"]'),
('8f78fe16-3fcc-4a92-984c-a8cb3631f801','送宗人熙甫入都','汪夢斗','宋','宋诗','song-poetry','','[]','栖栖我輩只如斯，壯矣如君百倍宜。',64,'全唐诗/poet.song.235000.json','["栖栖我輩只如斯，壯矣如君百倍宜。", "若是胸襟合西豹，未應位置下丘遲。", "波涵雁影日欲落，霜浄蟬枝風亂吹。", "一路盡皆懷古處，任城多有漢時碑。"]'),
('a7319bb0-e0e1-4bb9-9f34-f0c5f356013d','登雨華臺讀馬華國碑','汪夢斗','宋','宋诗','song-poetry','','[]','寒江如夢夕陽斜，休笑諸賢誤晉家。',32,'全唐诗/poet.song.235000.json','["寒江如夢夕陽斜，休笑諸賢誤晉家。", "雨打風吹碑已泐，英辭空自雨天華。"]'),
('d63b946d-9795-4a40-b3dd-a7897ec65df3','呈金陵教授陳宜之鉞前進士三人居慈湖','汪夢斗','宋','宋诗','song-poetry','','[]','文物依然故燕園，扶持云是有師門。',64,'全唐诗/poet.song.235000.json','["文物依然故燕園，扶持云是有師門。", "□花似醒醉夫夢，頖藻如招騷客魂。", "門戶固緣太丘重，鄉人素仰后山尊。", "曹溪一滴西江漲，欲乞開堂舊偈翻。"]'),
('e040da77-31a1-4316-95f5-c348b2346b19','題鄉友葉景星號洪堂因所居之村而名','汪夢斗','宋','宋诗','song-poetry','','[]','心胸欲閎肆，意氣要恢張。',48,'全唐诗/poet.song.235000.json','["心胸欲閎肆，意氣要恢張。", "力可弘吾道，方能大此堂。", "簾開容燕入，庭闊受花香。", "於以警爲學，非惟志故鄉。"]'),
('0d04c22f-7f81-4dcd-9bd7-6e799d16f7c3','當塗轎行口占','汪夢斗','宋','宋诗','song-poetry','','[]','筍輿咿軋亂山隈，擁鼻清吟當探梅。',64,'全唐诗/poet.song.235000.json','["筍輿咿軋亂山隈，擁鼻清吟當探梅。", "我已少知憂責少，人皆喜慰遠鄉回。", "樹猶綠暗知霜薄，雲漸紅深欲雪來。", "自說江南好風景，江南尤更有奇才。"]'),
('caa14c81-a131-448b-a8dd-f94f62d643fb','南園歌傷吳履齋舊景','汪夢斗','宋','宋诗','song-poetry','','["\u897f\u6e56"]','寂寞南園今如此，主人一斥循州死。',270,'全唐诗/poet.song.235000.json','["寂寞南園今如此，主人一斥循州死。", "南園如此未足悲，宗周隨歌黍離離。", "丞相當年坐黄閣，正是北兵渡荆鄂。", "不知宣閫有何功，却以鈞軸遜狡童。", "丞相身謀固已失，坐此謀失亡人國。", "梅花嶺外羈魂哀，薊門降王亦再來。", "南園池館不似舊，百花憔悴竹樹瘦。", "不堪回首望錢塘，宮闕傾頹禁苑荒。", "鄙夫姦人如王蔡，又無惠卿才可愛。", "丞相有見非不長，而乃升之中書堂。", "我行南園淚雨下，不免寒心怒欲駡。", "不特要寫平泉詩，更復要草連宮辭。", "嗚呼吳丞相，手提雙筆巖廊上。", "藝皇有訓垂日星，非讀書人毋用相。", "博飲好色不肖子，可以公台作邊賞。", "履翁之計早出此，老骨不死椒花瘴。", "西湖一碧無片塵，南園花草千年春。"]'),
('6ff5d15d-d9a8-4fc9-b187-cbeade847adc','雨中曉行','汪夢斗','宋','宋诗','song-poetry','','[]','馬上鷄聲黄葉村，擁衾人卧閉柴門。',32,'全唐诗/poet.song.235000.json','["馬上鷄聲黄葉村，擁衾人卧閉柴門。", "征裘塵土休煩洗，留取燈前看涴痕。"]'),
('dd2c4db8-06c2-4249-a432-482e1dd877f7','寧川道中口占','汪夢斗','宋','宋诗','song-poetry','','[]','緩兀吟鞍去，鞭長袖裏垂。',48,'全唐诗/poet.song.235000.json','["緩兀吟鞍去，鞭長袖裏垂。", "烟分村遠近，水見地高卑。", "風緊鳥飛疾，川寒魚上遲。", "擁爐坐殘雪，久已數歸期。"]'),
('7444285a-8e2a-4203-8bcc-a2971703f517','入叢山隘見雪','汪夢斗','宋','宋诗','song-poetry','','[]','天公有意相歸程，曉起千峯照眼明。',32,'全唐诗/poet.song.235000.json','["天公有意相歸程，曉起千峯照眼明。", "一白自能遮百醜，只疑風味太清生。"]'),
('b8c8c2fc-fc08-414e-81b7-24edfbc04679','崇德道中','汪夢斗','宋','宋诗','song-poetry','','[]','忽憶西窗晝掩扉，却緣殘照水邊歸。',32,'全唐诗/poet.song.235000.json','["忽憶西窗晝掩扉，却緣殘照水邊歸。", "杜陵夔府坡南海，都似西窗此夕暉。"]'),
('a1d96b5a-b828-4353-9a17-edcd8d98def6','思家五首竹枝體  其一','汪夢斗','宋','宋诗','song-poetry','','[]','六旬餘父身長健，九十重親髮不華。',32,'全唐诗/poet.song.235000.json','["六旬餘父身長健，九十重親髮不華。", "高堂無人供滫瀡，如何遊子不思家。"]'),
('3cd5cea2-8118-4dcc-89a1-560163a472b6','思家五首竹枝體  其二','汪夢斗','宋','宋诗','song-poetry','','[]','淮陰母家田未買，汾曲先廬屋已斜。',32,'全唐诗/poet.song.235000.json','["淮陰母家田未買，汾曲先廬屋已斜。", "人生墓宅頗關念，如何遊子不思家。"]'),
('71aa126d-47a5-44b4-b666-1028c8bf14d8','思家五首竹枝體  其三','汪夢斗','宋','宋诗','song-poetry','','[]','婦挼草汁浴蠶子，婢炙松明治枲麻。',32,'全唐诗/poet.song.235000.json','["婦挼草汁浴蠶子，婢炙松明治枲麻。", "東阡西陌要耕麥，如何遊子不思家。"]'),
('99b73480-5453-45ab-855b-f3f5a7eb78e3','思家五首竹枝體  其四','汪夢斗','宋','宋诗','song-poetry','','[]','兒多廢學自澆花，女近事人今抱牙。',32,'全唐诗/poet.song.235000.json','["兒多廢學自澆花，女近事人今抱牙。", "兒女長成憂失教，如何遊子不思家。"]'),
('3f941481-1ecf-4e7d-874d-cec1009b8670','思家五首竹枝體  其五','汪夢斗','宋','宋诗','song-poetry','','[]','荷凈軒前水浮鴨，翠眉亭下柳藏鴉。',32,'全唐诗/poet.song.235000.json','["荷凈軒前水浮鴨，翠眉亭下柳藏鴉。", "亦要丁寧春照管，如何遊子不思家。"]'),
('534e26c9-ef29-434a-98f3-c15b147787eb','跋忠愍公送婿邢德昭歸婺女詩後','釋自閑','宋','宋诗','song-poetry','','[]','玉潔冰清五十六，北山草木亦含芳。',32,'全唐诗/poet.song.235000.json','["玉潔冰清五十六，北山草木亦含芳。", "自如胡李堪同傳，璧合珠聯有耿光。"]'),
('49233b11-b846-4945-be01-2fd1177228a6','張天師正殿','黄仲元','宋','宋诗','song-poetry','','[]','至人學道師赤松，神姿逸氣心芙蓉。',160,'全唐诗/poet.song.235000.json','["至人學道師赤松，神姿逸氣心芙蓉。", "手五明扇腰雌雄，憑空架鐵超鴻濛。", "玉距痕深雕鎪工，巨迹千古鎮蜍峰。", "狂颶怒濤鏁魚龍，夜醒月凉水笙鏞。", "騎吏無鞍鸞鶴從，朝侍玉堂朵雲紅。", "天樂隠隠聲徹空，俗耳可聞不可逢。", "渺視齊州等蠛蠓，滄海有時揚塵風。", "獨此瓊館留人封，神仙之說非夢夢。", "士民尸祝社稷同，椒醑鞠𦜕瓜棗供。", "余非紫陽山人翁，若爲詩之銘新宮。"]'),
('ee818cbd-004f-4fe2-b4d6-f90c42137870','九日山','趙崇源','宋','宋诗','song-poetry','','[]','九日登臨老奈何，强將幽恨寄悲歌。',64,'全唐诗/poet.song.235000.json','["九日登臨老奈何，强將幽恨寄悲歌。", "疲欹巾帽愁風動，病著饑腸厭酒多。", "東嶺荒榛藏馬鬣，西巖空榻鏁蛛窠。", "獨憐堂下千章木，跨歷齊梁未改柯。"]'),
('ef8f2deb-bcd6-4b9d-9063-315854aeba03','秋浦樓義訓','趙溍','宋','宋诗','song-poetry','','[]','人生五馬貴，豈直榮其身。',192,'全唐诗/poet.song.235000.json','["人生五馬貴，豈直榮其身。", "千里民社寄，委任至不輕。", "西風塞棗紅，邊備最爲急。", "軍政無他長，事事須責實。", "公足以服衆，謙足以來賢。", "善政培根本，寬民乃其先。", "人生皆有性，感動須誠慤。", "當知愚而神，勿以術籠絡。", "夫人當壯歲，血氣未易平。", "喜怒不可從，反而求諸心。", "賞罰國之權，毋以逞私欲。", "斷者不可續，黥者親族辱。", "忠孝關大節，清白守家傳。", "汝看簡冊載，不以名利言。", "吾年七十餘，自覺猶矍鑠。", "勉力報君恩，步步踏實着。"]'),
('665b93d4-75af-49d7-ba5a-b7785786337f','焦山頑石偈','趙溍','宋','宋诗','song-poetry','','[]','丹石無光古剎存，蘆沙漁鼓□朝昏。',64,'全唐诗/poet.song.235000.json','["丹石無光古剎存，蘆沙漁鼓□朝昏。", "江淮門戶天分合，日月軒窗海吐吞。", "山足半沉曾瘞鶴，雲腰中斷可呼猿。", "丁寧爲我留佳處，茅屋三間護竹根。"]'),
('58a3eb86-e2e7-4405-a036-5a4e77d38097','寄詩交顧梅山','楊鎮','宋','宋诗','song-poetry','','[]','誰與吟翁氣味同，松梢明月竹梢風。',32,'全唐诗/poet.song.235000.json','["誰與吟翁氣味同，松梢明月竹梢風。", "能詩多是窮人事，不到窮時詩不工。"]'),
('da7ef1e3-477f-4f12-a3ae-e6976ce3a6bf','江上秋感','房元龍','宋','宋诗','song-poetry','','[]','淘盡英雄氣未平，西風觸緒倍心驚。',64,'全唐诗/poet.song.235000.json','["淘盡英雄氣未平，西風觸緒倍心驚。", "愁人髮湧三千丈，國士胸吞十萬兵。", "杜老裁詩多慷慨，祖生擊楫自縱橫。", "芙蓉摇落哀鴻切，無那滔滔日夜聲。"]'),
('4f22ca51-7413-4d7f-8c87-aa9997dc7e35','題馬伏波像','董烈','宋','宋诗','song-poetry','','[]','眉目真如畫，英姿迥不凡。',48,'全唐诗/poet.song.235000.json','["眉目真如畫，英姿迥不凡。", "識高能擇主，功大不勝讒。", "馬革忠何壯，壺頭怒尚銜。", "誰甘騎款段，長服野人衫。"]'),
('75b03517-3adf-4ec1-8204-8bf20a2f57cc','謁朱夫子祠','林天瑞','宋','宋诗','song-poetry','','[]','天下有明月，人世苦昏昏。',48,'全唐诗/poet.song.235000.json','["天下有明月，人世苦昏昏。", "山色無今古，谷雲常吐吞。", "微言誰與析，妙理獨難論。", "萬樹秋風老，先生道自尊。"]'),
('0c731c32-fe38-4307-928d-d3d4608a0485','武夷即事','林天瑞','宋','宋诗','song-poetry','','[]','長卿非慢世，陶令已辭官。',48,'全唐诗/poet.song.235000.json','["長卿非慢世，陶令已辭官。", "解組投蓮社，逢人戴鶡冠。", "青天不可問，白髮若爲看。", "偶遇壺丘子，皈心授大丹。"]'),
('dd3efb36-6c81-4fe3-836b-4c58d0acebb3','搗油翁','陳諤','宋','宋诗','song-poetry','','[]','忽遇深山避世翁，居然沮溺古人風。',32,'全唐诗/poet.song.235000.json','["忽遇深山避世翁，居然沮溺古人風。", "老來一出爲身計，不滿先生一笑中。"]'),
('4d27a3fc-1897-48db-baf1-3389aebcb00f','襄鄂百詠','陳諤','宋','宋诗','song-poetry','','[]','久戍蕃兵已念家，將軍何不奏胡家。',32,'全唐诗/poet.song.235000.json','["久戍蕃兵已念家，將軍何不奏胡家。", "今朝忽報嚴圍解，白雪紛紛亦散花。"]'),
('d52ea931-7b7d-4293-860c-c707da788993','怡堂','劉祖尹','宋','宋诗','song-poetry','','[]','結廬投老瞯羣峯，隠隠松杉曲徑通。',64,'全唐诗/poet.song.235000.json','["結廬投老瞯羣峯，隠隠松杉曲徑通。", "剩種池邊千纛竹，近營林下一巢風。", "欹眠盡絕春來夢，趺坐閑看月墮空。", "檢點吾生諸事了，子孫更與護其終。"]'),
('873c975c-a723-4ebd-a7dc-a86d13d848d8','復瀘凱歌  其一','梅應春','宋','宋诗','song-poetry','','[]','重壁山前瑞色開，浮環夜渡捷騎來。',32,'全唐诗/poet.song.235000.json','["重壁山前瑞色開，浮環夜渡捷騎來。", "一旗金鼓轅門曉，喚得滿城生意回。"]'),
('a9a81f45-2046-43cb-b9d7-dd8e1e255b9e','復瀘凱歌  其二','梅應春','宋','宋诗','song-poetry','','[]','休訝朝家奏報遲，平生忠孝鬼神知。',32,'全唐诗/poet.song.235000.json','["休訝朝家奏報遲，平生忠孝鬼神知。", "但留一片丹心在，會有天回地轉時。"]'),
('a3311ccb-88fe-468f-b22f-be0641bb5a4d','元兵俘至合沙詩寄仲子','陳文龍','宋','宋诗','song-poetry','','[]','斗壘孤危勢不支，書生守志誓難移。',64,'全唐诗/poet.song.235000.json','["斗壘孤危勢不支，書生守志誓難移。", "自經溝瀆非吾事，得死封疆是此時。", "須信纍臣堪釁鼓，未聞烈士樹降旗。", "一門百指淪胥北，惟有丹衷天地知。"]'),
('ee27aacf-6ac8-4851-8db3-9cab0411fa1a','自述','甘泳','宋','宋诗','song-poetry','','[]','總角希聞道，殘生乃付詩。',48,'全唐诗/poet.song.235000.json','["總角希聞道，殘生乃付詩。", "未曾前輩識，敢辱近人知。", "飄泊身餘健，蕭閒鬢欲衰。", "一簾書四壁，寒日在清池。"]'),
('306768c5-716d-4523-b785-13341e51f259','過南湖','甘泳','宋','宋诗','song-poetry','','[]','忽有一事礙胸次，擺脫不去呼酒來。',64,'全唐诗/poet.song.235000.json','["忽有一事礙胸次，擺脫不去呼酒來。", "溟溟濛濛混沌在，坦坦蕩蕩虛空開。", "精神一生留筆墨，形骸昨夜爲尊罍。", "年年看梅今白髮，晴日江路行莓苔。"]'),
('d79b905c-4a54-4471-88f3-c871aee3021b','與危見心同和完顔御史沂聯步踏月韻','甘泳','宋','宋诗','song-poetry','','[]','明月送人歸，明月照人宿。',24,'全唐诗/poet.song.235000.json','["明月送人歸，明月照人宿。", "月落夢醒時，清霜壓寒屋。"]'),
('f251f0fd-1630-4173-a948-46bd327b3ec3','晚立黄洲','甘泳','宋','宋诗','song-poetry','','[]','今度闌干倚，蒼茫入暮天。',48,'全唐诗/poet.song.235000.json','["今度闌干倚，蒼茫入暮天。", "碧溪分市井，華屋亂雲烟。", "鐘隔春來樹，燈流夜去船。", "惜哉題柱壯，琴動鳳凰絃。"]'),
('9999af99-c22a-41ea-b15d-246d99b1f6ec','小絕','甘泳','宋','宋诗','song-poetry','','[]','一夜睡不著，小窗天忽明。',24,'全唐诗/poet.song.235000.json','["一夜睡不著，小窗天忽明。", "林塘寒鳥聚，聽得最初聲。"]'),
('2448ebe2-297c-4d2d-8ba6-f7d960d204de','陪完顔御史行金石臺分韻得丞字','甘泳','宋','宋诗','song-poetry','','[]','勝景踰千載，吾人得共登。',48,'全唐诗/poet.song.235000.json','["勝景踰千載，吾人得共登。", "五峯交地勢，一水合沙稜。", "荆國成何事，浮丘無異能。", "山頭有田父，未必識中丞。"]'),
('c051ed7d-e03c-4705-b183-4bb8b394e005','歸來','甘泳','宋','宋诗','song-poetry','','[]','謂我猶羈旅，歸與已的然。',48,'全唐诗/poet.song.235000.json','["謂我猶羈旅，歸與已的然。", "風霜高枕外，江海小詩邊。", "達摩移華夏，莊周侮聖賢。", "向來知此事，未敢棄予年。"]'),
('0c113f5c-7602-4c72-873c-9e4610cdd59c','秋風詞','甘泳','宋','宋诗','song-poetry','','[]','昨夜西風來，人間雨如海。',154,'全唐诗/poet.song.235000.json','["昨夜西風來，人間雨如海。", "山摇摇，秋灑灑。", "早起□□輪，老紅竟何在，惟有殘雲漠漠弄凉態。", "千林萬葉，淅瀝作聲。", "豈無綠色，奈何凋零。", "四時更變化，宋玉胡爲愁，直須痛飲千斛酒。", "亦不知有春，亦不知有秋，鴻濛適我汗漫遊。", "絕憐九辨大蕭索，爭與蟲聲起籬落。", "東溪子，今夕呼月當中天，看我大醉西風前。", "便令秋滿八千歲，我醉依然月下眠。"]'),
('f767441b-f2d0-4952-b083-def5bca02e33','燒香寺','甘泳','宋','宋诗','song-poetry','','[]','暑熱不可度，須此日暮凉。',204,'全唐诗/poet.song.235000.json','["暑熱不可度，須此日暮凉。", "况爾得佳友，共約棲禪房。", "行吟發幽興，空闊入水鄉。", "蕭散意自適，輕風動衣裳。", "誰歟遠有望，烟影生冥茫。", "已復入古寺，樹色交青蒼。", "虛廊絕蚊蛾，可近燈燭光。", "蓮花生清池，靜坐乃聞香。", "尊卑就次序，肴核羅杯觴。", "嗟此坐中人，聲名托文章。", "雲霄縱高步，山林倏潛藏。", "況遇知己飲，豁達傾肺腸。", "撫掌發一笑，神思驚軒昂。", "酣歌興未已，下趁青苔荒。", "仰視天無塵，素月升東牆。", "百年亦如寄，萬事何其長。", "慎勿忘今夕，嘉話連僧房。"]'),
('e49ec67d-e936-4a1b-9f4e-8a3b9d3dd8b2','夜坐','甘泳','宋','宋诗','song-poetry','','[]','林風自瀟瀟，山雨時灑灑。',24,'全唐诗/poet.song.235000.json','["林風自瀟瀟，山雨時灑灑。", "丈夫七尺軀，地爐使吾矮。"]'),
('48ef4d0c-a4a9-4fa3-82a3-4ab22b067274','早睡','甘泳','宋','宋诗','song-poetry','','[]','病來貪睡早，推月出山前。',24,'全唐诗/poet.song.235000.json','["病來貪睡早，推月出山前。", "月色不相捨，小窗還自妍。"]'),
('3f0047a5-3de2-4393-aa8d-066de7c4736a','酒醒','甘泳','宋','宋诗','song-poetry','','[]','酒醒桂花發，狂歌對花前。',24,'全唐诗/poet.song.235000.json','["酒醒桂花發，狂歌對花前。", "鄰家大駡我，夜半驚人眠。"]'),
('fcbba59e-8d37-4460-8b88-17c537b69d62','書生','甘泳','宋','宋诗','song-poetry','','[]','踉蹡趣講席，讀誦鬭高聲。',24,'全唐诗/poet.song.235000.json','["踉蹡趣講席，讀誦鬭高聲。", "我亦曾如此，而今白髮生。"]'),
('c75bc6ae-f899-4602-8d73-9200c039a8d6','暫憩','甘泳','宋','宋诗','song-poetry','','[]','平生湖海遊，南北東西路。',24,'全唐诗/poet.song.235000.json','["平生湖海遊，南北東西路。", "幾度夢殘時，雲深不知處。"]'),
('697fd074-a407-49ef-8c4c-64c2b6749a7a','歸舟二首  其一','甘泳','宋','宋诗','song-poetry','','[]','片帆懸空秋滿腹，凉月淡淡天無波。',32,'全唐诗/poet.song.235000.json','["片帆懸空秋滿腹，凉月淡淡天無波。", "平生湖海元龍意，早入西風漁櫂歌。"]'),
('c0b7a5df-84ce-4f0e-884a-3a1f656e83a9','歸舟二首  其二','甘泳','宋','宋诗','song-poetry','','[]','天壤豈無蘇季子，恨我不識韓荆州。',32,'全唐诗/poet.song.235000.json','["天壤豈無蘇季子，恨我不識韓荆州。", "遥山蒼蒼暮雲碧，何許一笛蘆花秋。"]'),
('805d50f3-f664-4f20-8d6b-b9cad5e43b02','下豫州','甘泳','宋','宋诗','song-poetry','','[]','壯懷忍共白雲閒，孤負僧房屋半間。',32,'全唐诗/poet.song.235000.json','["壯懷忍共白雲閒，孤負僧房屋半間。", "賣却牢愁三萬斛，載將明月入西山。"]'),
('53e2659b-01de-445b-b35b-872119f987f0','托意','甘泳','宋','宋诗','song-poetry','','[]','舊時燈火不知年，托意篇章末世傳。',32,'全唐诗/poet.song.235000.json','["舊時燈火不知年，托意篇章末世傳。", "胸次只今無此事，聽風聽雨過殘年。"]'),
('80dd606e-6ea1-4299-bcd4-de10789a648a','新春','甘泳','宋','宋诗','song-poetry','','[]','花紅柳綠也逢時，潤色青春有小時。',32,'全唐诗/poet.song.235000.json','["花紅柳綠也逢時，潤色青春有小時。", "人世苦無吾輩在，東風寥落亦堪愁。"]'),
('bffa2fe0-5402-4869-b24d-c17d2c71cf6d','看梅','甘泳','宋','宋诗','song-poetry','','[]','獨坐匆匆不自適，出門偶見梅花開。',32,'全唐诗/poet.song.235000.json','["獨坐匆匆不自適，出門偶見梅花開。", "自從開闢到今日，此是東風第幾回。"]'),
('88ca4dff-5dc8-46ce-b335-9bb6f2ff7258','古意五首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','迢迢長安道，古堠雙復隻。',72,'全唐诗/poet.song.235000.json','["迢迢長安道，古堠雙復隻。", "游子辭家去，去去何所適。", "素商昔轉玄，朱羲今由白。", "悠悠世路艱，江湖虎豹宅。", "楊朱泣途窮，魯叟悲麟獲。", "願言弛負擔，歸與慰岑寂。"]'),
('c6f8b477-6195-4cdf-9a8f-a15c5b2162dc','古意五首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','亹亹天上雲，滔滔海中波。',60,'全唐诗/poet.song.235000.json','["亹亹天上雲，滔滔海中波。", "時哉不我與，况復未息戈。", "浮氛冒曾嶺，君去將如何。", "君吟行路難，妾思扊扅歌。", "積憂儻心痗，采蕨南山阿。"]'),
('8a2271b3-1740-4cc8-8383-cf05b296ad5e','古意五首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','悠悠君何之，煢煢妾影隻。',60,'全唐诗/poet.song.236000.json','["悠悠君何之，煢煢妾影隻。", "蕭蕭兩鬢絲，寒衣不堪織。", "縱使堪織衣，練能成幾尺。", "西窗暗雨鳴，孤燈耿復滅。", "君心如妾心，妾心匪木石。"]'),
('950ec5a9-ba4b-4c7d-9c38-42dc59c7d4c8','古意五首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','皎皎天上月，輝光燭蓬門。',60,'全唐诗/poet.song.236000.json','["皎皎天上月，輝光燭蓬門。", "蓬門亦何有，古鏡堂上懸。", "妾心如古鏡，磨盡明不昏。", "君心鏡上塵，磨去不復存。", "猗嗟賤妾心，與君難具論。"]'),
('1ff243b3-be52-4351-b4a8-055194c5c691','古意五首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','憶妾初嫁時，感君塗蔇茨。',96,'全唐诗/poet.song.236000.json','["憶妾初嫁時，感君塗蔇茨。", "嫁君未三載，君行河北陲。", "長庚耿天際，飯粟羹伏雌。", "君云去不遠，五月當來歸。", "聞君往從軍，裘馬事輕肥。", "蓬蒿沒深巷，風露凄妾衣。", "夫君豈不念，將由道路逶。", "道路或孔邇，妾憂寧不知。"]'),
('b76c4610-ac70-4652-9638-a7a7f726bcb2','吳郡齋遣懷','俞德鄰','宋','宋诗','song-poetry','','[]','齋居苦無悰，散屧步芳圃。',108,'全唐诗/poet.song.236000.json','["齋居苦無悰，散屧步芳圃。", "花柳度暖風，莓苔滋宿雨。", "疊嶂隠簷牙，幽禽哢林莽。", "池光瓦蔽虧，日氣石吞吐。", "迥眺覿層城，狂歌隘天宇。", "倏歡景已流，俄思愁復聚。", "楚奏鍾儀悲，越吟莊舄苦。", "人情異窮達，土思渺今古。", "信美非吾鄉，歸心屬蘭杜。"]'),
('de900716-3541-4dee-8602-2312691f32b7','龔聖予號翠巖晚歲更號巖翁爲賦','俞德鄰','宋','宋诗','song-poetry','','[]','春風桃李顔，歲寒松柏心。',120,'全唐诗/poet.song.236000.json','["春風桃李顔，歲寒松柏心。", "達人步大方，靜愛無絃琴。", "無絃豈堪聽，絃外多遺音。", "世涂甚風水，對面商與參。", "孤芳忌羣處，散材辭衆侵。", "霜降水歸源，日旭星就陰。", "浮華剝落盡，古道誰復今。", "吾家鴈山下，翠巘高千岑。", "清秋灝氣塞，萬里纖埃沈。", "安得與君去，結架聆清吟。"]'),
('a1a3c790-f477-4915-9673-77e9ca6b13d9','閒居遣懷三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','莓牆蔭薜蘿，中有一畝宅。',60,'全唐诗/poet.song.236000.json','["莓牆蔭薜蘿，中有一畝宅。", "花竹分四時，野鳥鳴格磔。", "浩歌引清觴，微風岸低幘。", "百骸任舒伸，一笑天地窄。", "剝啄誰叩門，門外有佳客。"]'),
('23273f5f-c72c-4ff3-ae76-9dc353867b53','閒居遣懷三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','坐中有佳客，尊中有美酒。',48,'全唐诗/poet.song.236000.json','["坐中有佳客，尊中有美酒。", "酒美客更佳，一醉亡何有。", "醉餘送客去，新月挂疎柳。", "明日欲重來，已戒應門走。"]'),
('3dadba5b-1271-44dd-ba6c-519905be2082','閒居遣懷三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','客至固自佳，客去亦不惡。',60,'全唐诗/poet.song.236000.json','["客至固自佳，客去亦不惡。", "起舞弄清影，明月勸孤酌。", "一杯復一杯，輕颸動修薄。", "擾擾百年間，誰能得此樂。", "酒醒日射窗，推窗見梅落。"]'),
('040076d5-227f-40a5-9f69-0c1e0d5074e8','聞角','俞德鄰','宋','宋诗','song-poetry','','[]','角聲嗚咽梅花老，遠客夜長風草草。',64,'全唐诗/poet.song.236000.json','["角聲嗚咽梅花老，遠客夜長風草草。", "起傾凍酒澆愁胸，愁思轉多杯恨小。", "人生石火斯須期，月轉樓西角又吹。", "咍臺一枕華胥夢，明日看山笏拄頤。"]'),
('4a51d24f-efe1-462a-b897-a2af94d08626','遣興十首呈孟兵部使君  其一','俞德鄰','宋','宋诗','song-poetry','','[]','來日悲苦短，頹齡恨將侵。',60,'全唐诗/poet.song.236000.json','["來日悲苦短，頹齡恨將侵。", "西山産靈藥，暇日聊與尋。", "䔿薈蔚𡾰嵼，兔狐走高岑。", "洪厓去不返，羨門杳無音。", "竚立長太息，誰哉知我心。"]'),
('9b7c7b80-9341-4d30-b1e1-caf895c59f4c','遣興十首呈孟兵部使君  其二','俞德鄰','宋','宋诗','song-poetry','','[]','雉鳴朝求雌，木壞疾無枝。',84,'全唐诗/poet.song.236000.json','["雉鳴朝求雌，木壞疾無枝。", "仁心秉君子，小弁怨何磯。", "在昔共世子，待烹慰驪姬。", "亦有魯閔氏，朔風衣單衣。", "二賢豈不怨，仁義固良知。", "夐夐彼投兔，䔩䔩奔鹿斯。", "道死尚或墐，况乃天性爲。"]'),
('2b78d913-ad2a-4c26-b9e2-9b5a8f30374f','遣興十首呈孟兵部使君  其三','俞德鄰','宋','宋诗','song-poetry','','[]','豕交食弗愛，獸畜愛弗敬。',48,'全唐诗/poet.song.236000.json','["豕交食弗愛，獸畜愛弗敬。", "烈士死一言，利祿安足競。", "陛戟覲伏波，井蛙敗人興。", "不見古公子，親御侯生乘。"]'),
('17dc0d58-115c-4ba8-8428-c0b10619c835','遣興十首呈孟兵部使君  其四','俞德鄰','宋','宋诗','song-poetry','','[]','雞鳴食孟門，指鹿相秦室。',48,'全唐诗/poet.song.236000.json','["雞鳴食孟門，指鹿相秦室。", "所以有志士，林樊屏轍跡。", "得時貴行道，枉尋豈直尺。", "無爲趙孟間，笑此陳蔡厄。"]'),
('245931d0-0272-461a-8a1d-8e309ca3f917','遣興十首呈孟兵部使君  其五','俞德鄰','宋','宋诗','song-poetry','','[]','翛翛瓊田鶴，高步何頎頎。',60,'全唐诗/poet.song.236000.json','["翛翛瓊田鶴，高步何頎頎。", "霜毛映寒月，丹頂含晴暉。", "胡不乘軒車，俛啄前谿爲。", "谿水清且淪，白石亦粼粼。", "雖無魚蝦味，且免雞鶩嗔。"]'),
('938cdc34-17c4-419a-8bbf-65275e35f845','遣興十首呈孟兵部使君  其六','俞德鄰','宋','宋诗','song-poetry','','[]','趙子有古心，眂世澹如寄。',48,'全唐诗/poet.song.236000.json','["趙子有古心，眂世澹如寄。", "青編對朝夕，黄花當姬侍。", "海上逐臭人，紛紛笑厓異。", "焉知四五間，政在薛公輩。"]'),
('9bc7e2ca-3130-41ec-88be-d912a557450e','遣興十首呈孟兵部使君  其七','俞德鄰','宋','宋诗','song-poetry','','[]','俗子塵滿襟，門外紛偪塞。',72,'全唐诗/poet.song.236000.json','["俗子塵滿襟，門外紛偪塞。", "髯龔詩中英，高卧翠巖側。", "風雲入古硯，鳥烏窺凍壁。", "似聞中饋虛，桑麻欠機織。", "母氏聖且善，門閭望朝夕。", "擇婦要得人，在德不在色。"]'),
('f730a93b-502e-4394-bb1e-5ef757070e7f','遣興十首呈孟兵部使君  其八','俞德鄰','宋','宋诗','song-poetry','','[]','卯金我石友，胸次如阮嵇。',48,'全唐诗/poet.song.236000.json','["卯金我石友，胸次如阮嵇。", "灌園西郊外，竹徑風煙迷。", "我宅今易主，政擬尋幽棲。", "卜鄰儻有分，當在西枝西。"]'),
('7ce8c1a3-44ad-4a64-97e6-054bff82c8a3','遣興十首呈孟兵部使君  其九','俞德鄰','宋','宋诗','song-poetry','','[]','我昔愛君直，蚤慧機雲比。',72,'全唐诗/poet.song.236000.json','["我昔愛君直，蚤慧機雲比。", "一別復幾時，使我費懷企。", "夢中往相尋，宛在水中沚。", "水中多鳧鷖，水邊鳴鳩飛。", "天雨逐婦去，天晴呼婦歸。", "鳧鷖政自樂，鳩婦吁可悲。"]'),
('7a943aa1-e010-42da-a1e9-40306ef1dc30','遣興十首呈孟兵部使君  其一○','俞德鄰','宋','宋诗','song-poetry','','[]','逄蒙學羿射，殺羿射始神。',48,'全唐诗/poet.song.236000.json','["逄蒙學羿射，殺羿射始神。", "羿兮信有罪，蒙哉真忍人。", "世涂昏若漆，對面越與秦。", "眼中今歷歷，欲語愁余嗔。"]'),
('9ed2def2-99d2-48f6-8dfb-4478b5a06ed1','石門洞','俞德鄰','宋','宋诗','song-poetry','','[]','衙衙雙石撐青空，澗鳴瀑吼驚魚龍。',96,'全唐诗/poet.song.236000.json','["衙衙雙石撐青空，澗鳴瀑吼驚魚龍。", "維舟支筇步山徑，山黑鬼嘯猿啼風。", "雲巢雪屋數羽士，玉函寶笈繙晨鐘。", "天寒木落山露骨，日月隠隠行空濛。", "九衢黄埃沒馬腹，一家歌笑百家哭。", "雖然是山猛虎多，猶勝人間賦蛇毒。"]'),
('d02a36c9-fefa-4582-906b-9d53d3daa15a','靈烏','俞德鄰','宋','宋诗','song-poetry','','[]','靈烏太多知，庭樹久棲寄。',84,'全唐诗/poet.song.236000.json','["靈烏太多知，庭樹久棲寄。", "主人閔烏靈，遺食寓仁意。", "烏亦感主恩，啞啞動鳴喙。", "心知主厭聞，冀主早自計。", "大忠易爲僇，至靈乃凶類。", "折翅會有期，卷舌良自愧。", "終當爲主鳴，誰與喂羹胾。"]'),
('a9651ade-e68b-45e4-b203-55dc996b3f74','贈成雷師','俞德鄰','宋','宋诗','song-poetry','','[]','妖氛塞乾坤，乘罅毒黔首。',156,'全唐诗/poet.song.236000.json','["妖氛塞乾坤，乘罅毒黔首。", "膏肓不可鍼，靈文洩樞斗。", "雷師爛柯仙，造化默授受。", "捕蛟笞鬼神，宛似彌明叟。", "雷霆指顧間，雲雨翻覆手。", "携詩走江湖，萬里屈伸肘。", "平生劉伯龍，貽笑今已久。", "誰能煩律令，三揖費蕉柳。", "嗟嗟世涂艱，魑魅白晝吼。", "藍色雜曼膚，睒眒眩妍醜。", "我欲掃除之，荒郊乏荆帚。", "何當襲師術，轟霆震枯朽。", "坐使四海清，物物躋仁壽。"]'),
('ea0c102e-073f-4342-be64-01aec9f1caea','壽沿江黄制置七首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','商巖賚良弼，周嶽生甫申。',72,'全唐诗/poet.song.236000.json','["商巖賚良弼，周嶽生甫申。", "一賢關世運，六合歸吾仁。", "英英丹霞翁，異代獨儗倫。", "騎驎下帝所，仗鉞清塞塵。", "塞塵行且清，器農不器兵。", "廊廟端紱冕，永永扶休明。"]'),
('cfa97140-4246-4620-9c04-26f7da9a763d','壽沿江黄制置七首  其二','俞德鄰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曾城護六朝，長江渺萬里。',60,'全唐诗/poet.song.236000.json','["曾城護六朝，長江渺萬里。", "紫蓋照東南，屏蔽獨此恃。", "連營步騎屯，列遂芻糧峙。", "填拊茲匪輕，倚毗良有以。", "願言策殊勳，千歲光竹史。"]'),
('faf16d61-c2d5-4162-8116-1bc0c1a62064','壽沿江黄制置七首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','軍中用范老，幕下羅歐陽。',60,'全唐诗/poet.song.236000.json','["軍中用范老，幕下羅歐陽。", "玉人不受縶，白駒猶在場。", "乃知古君子，致泰由包荒。", "山深草木萃，海闊珍怪藏。", "周公昔吐哺，鳴鳳紛高岡。"]'),
('28073380-d693-49c9-b9dd-aa253ed6d949','壽沿江黄制置七首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','越流飲醇酎，街亭正軍律。',48,'全唐诗/poet.song.236000.json','["越流飲醇酎，街亭正軍律。", "勸懲妙微機，今古軌轍一。", "韓昭戒夢言，荀攸貴深密。", "此事難語人，端居幸時繹。"]'),
('ba560b2a-ceed-4ed6-b6f1-8b126415b9e8','壽沿江黄制置七首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','父母斯民寄，斯心斯民心。',60,'全唐诗/poet.song.236000.json','["父母斯民寄，斯心斯民心。", "仁哉彼君子，天地融一襟。", "得情貴勿喜，顧畏如弗任。", "神明次公政，所至留棠陰。", "寧使民覿德，茲言良足欽。"]'),
('a05e28d0-dbcb-4c5f-98c3-92a3694b47aa','壽沿江黄制置七首  其六','俞德鄰','宋','宋诗','song-poetry','','[]','五龍閲古今，顔貌儼童孺。',72,'全唐诗/poet.song.236000.json','["五龍閲古今，顔貌儼童孺。", "亦有赤松子，駕鴻凌紫霧。", "靜心遺紛華，定力養沖素。", "因知龜鶴年，非以服食護。", "公身天地身，出處繫王度。", "願言保千齡，持用答三顧。"]'),
('14f108bf-53b9-4a4b-972b-9827713999fa','壽沿江黄制置七首  其七','俞德鄰','宋','宋诗','song-poetry','','[]','走也晚聞道，曳裾登師門。',72,'全唐诗/poet.song.236000.json','["走也晚聞道，曳裾登師門。", "師門岌數仞，冠珮何誾誾。", "拂拭長光賈，吹噓憐苦辛。", "永言一飯報，睠然清渭濱。", "燕飛認巢穩，馬瘦思草春。", "何當入鈞播，坱圠知無垠。"]'),
('fe033be2-819c-404c-a612-bbd209a33e7d','題劉同知所藏春山訪隠圖','俞德鄰','宋','宋诗','song-poetry','','[]','環洲玲瓏徑深窈，巉巖翠壁摩蒼顥。',96,'全唐诗/poet.song.236000.json','["環洲玲瓏徑深窈，巉巖翠壁摩蒼顥。", "幽人結屋倚陰厓，雲木烟蘿互縈繞。", "維舟散屧欲往從，山深樹密無行蹤。", "徘徊谿橋自嘆息，安得上下如雲龍。", "古云大隠隠朝市，市朝亦有居巢子。", "胡然見面不見心，咫尺娟娟隔春水。"]'),
('ca0f7563-c358-4a01-b033-e7f012e806a5','贈雷巖趙相士','俞德鄰','宋','宋诗','song-poetry','','[]','雷填填，雨冥冥，千巖萬壑白晝暝。',185,'全唐诗/poet.song.236000.json','["雷填填，雨冥冥，千巖萬壑白晝暝。", "真人宴坐神不驚，一瞬百怪無留形。", "風休電止天宇浄，頂笠挑包談性命。", "龍鉛虎汞世莫知，更說榮枯動人聽。", "壺子久不作，季咸亦已矣。", "杜德衡氣無二機，弟靡波流寧底止。", "矧伊浮世上，旋轉如飛蓬。", "死生夢蝶成蝶夢，禍福得馬失馬翁。", "羊裘垂釣或諫議，不龜手藥忽取封。", "相形相不盡，相心心莫窮。", "雷巖雷巖，不如歸卧巖之下，吾亦柴桑稅吾駕。", "明月投人戒暗投，美玉匵藏須待賈。"]'),
('54733354-c3ad-40a5-8623-370138b616e1','題補蹠翁圖','俞德鄰','宋','宋诗','song-poetry','','[]','聖月無盈虧，劫燼有新故。',120,'全唐诗/poet.song.236000.json','["聖月無盈虧，劫燼有新故。", "嗟嗟補蹠翁，乃復不早悟。", "爲王雖云樂，萬幾實心蠹。", "世尊愍衆生，引手弘六度。", "以我智慧燈，照彼八正路。", "令於淤泥中，識此清浄土。", "我本有髮僧，靜參無二句。", "拊圖對青山，了然見心素。", "從茲謝筆墨，白雲共朝暮。", "剝啄誰扣門，法喜慎勿語。"]'),
('11d25b43-ea08-44da-b96e-76742d2c04d3','爲馬受益題韓滉畫子母牛圖','俞德鄰','宋','宋诗','song-poetry','','[]','老犍耕餘飽枯䕸，呼牸引犢緣欹厓。',80,'全唐诗/poet.song.236000.json','["老犍耕餘飽枯䕸，呼牸引犢緣欹厓。", "犢兒母懷不父懷，母子僔沓形離𠇗。", "牧童生來識牛意，倦拋臺笠曲肱睡。", "爾牛不寢亦不訛，我亦無夢遊南柯。", "歸來短衣不掩骭，却笑漫漫歌夜半。"]'),
('19d369d8-7172-45de-a7c4-9000cf888ced','甲戌遊旴江六月二十二日發武林','俞德鄰','宋','宋诗','song-poetry','','[]','威弧慘無光，城烏啄大屋。',228,'全唐诗/poet.song.236000.json','["威弧慘無光，城烏啄大屋。", "淮雲蒼莽間，十載幾荼毒。", "憂心甫殷殷，又復正陽築。", "正陽亦何許，地接英與六。", "傳聞夜點兵，文書下機速。", "揮汗起負戈，部伍競馳逐。", "平明驅出城，令嚴秋氣肅。", "豈不實苦辛，主憂固臣辱。", "前年戍襄樊，去年戍郢復。", "白骨秋野橫，青燐陰房煜。", "生還偶然爾，忍怨征行促。", "所悲世路艱，無罪罹殺戮。", "潢池弄盜兵，綠林仇餉肉。", "茫茫畿甸間，風塵涴人目。", "聖明撫遐荒，先事清輦轂。", "干戈動邦內，豈計顓臾蹙。", "扶顛要得人，撥亂如轉燭。", "秋山翡翠青，秋水蒲桃綠。", "去去取封侯，勿羨牧羊僕。"]'),
('bf01aee5-b589-47f1-a5b4-2b55d017cf12','甲戌秋過丫頭巖有感','俞德鄰','宋','宋诗','song-poetry','','[]','昔年北兵滸黄渡，官軍一萬丫巖駐。',210,'全唐诗/poet.song.236000.json','["昔年北兵滸黄渡，官軍一萬丫巖駐。", "巖前十里無人煙，焉知今日重生聚。", "老翁殷勤指長孫，生時開慶方改元。", "今年裹頭明年娶，感荷太平天子恩。", "傳聞鼎湖龍又逝，空餘弓劍留人世。", "天上唯多三數公，社稷蒼生誰早計。", "老翁憂時色枯槁，羸卧巖前分犢草。", "京師來往千萬人，欲問明時知者少。", "嗣皇繼聖生神靈，西陲何事猶徵兵。", "襄樊未復郢又急，正陽新築淮未平。", "吾儕紅額今有幾，青袍白馬紛紛是。", "巖前鬼燐陰雨青，老翁說著心膽驚。", "願君努力扶休明，翁也菁羹橡飯安餘生。"]'),
('472506d0-50ce-47f2-90de-374b5aa46a4d','甲戌六月十四日月食過半七月十四日抵廣信月巖有感而作','俞德鄰','宋','宋诗','song-poetry','','[]','昔聞月巖巖上月，無今無古無圓缺。',112,'全唐诗/poet.song.236000.json','["昔聞月巖巖上月，無今無古無圓缺。", "天無二日月有二，此豈鬼剔神剜出。", "我從前月客帝京，月明忽苦蝦蟇精。", "爾時見天會事發，誓取妖蟇膏寸鐵。", "不知巖月當此時，上睹月食悲不悲。", "我行過此三歎息，此月不食彼月食。", "再拜山靈問川后，妖蟇到底受磔否。"]'),
('cf2bb9f5-8174-47d9-a674-46026b29739a','仙人巖即事','俞德鄰','宋','宋诗','song-poetry','','[]','夕陽隔溪明薜蘿，數峯谿畔青嵯峨。',224,'全唐诗/poet.song.236000.json','["夕陽隔溪明薜蘿，數峯谿畔青嵯峨。", "層霄彷彿相盪摩，谿流洶湧通銀河。", "金支翠旗颭山阿，風傳霧樂鏘鑾鉌。", "雲封巖竇生靈禾，仙靈蛻久留仙艖。", "弈枰丹竈斲月柯，漥尊土缶石臼磨。", "苔剜蘚刻千歲過，護以鬼物煩撝訶。", "谿南谿北夔罔多，鯶魴鱣鮪蛟黿鼉。", "雷聲吭磕涷雨𩃱，仙筇九節扶下坡。", "紅妝半醉誰嬌娥，容顔二八細馬馱。", "下馬避雨吳歈歌，蘭麝馥郁飄綺羅。", "靈簫學道蠲煩痾，湘浦解佩聲瑳瑳。", "雙成飲罷鳴雲龢，藍橋一醉朱顔酡。", "扶桑暘谷同碧渦，玄書寶文傳豈譌。", "浮生百歲如飛梭，當歡不歡奈老何。"]'),
('af0376bd-0412-4065-9759-526d70fc1db6','爲孟希聖題孛落鵪鶉畫扇','俞德鄰','宋','宋诗','song-poetry','','[]','下車式怒蛙，爲愛蛙有氣。',96,'全唐诗/poet.song.236000.json','["下車式怒蛙，爲愛蛙有氣。", "秋風化爲鶉，迺復有鬭志。", "叢叢槲葉邊，身睨而視。", "雖非紀渻雞，宛類浮圖鷙。", "因知氣苟存，百變終不惴。", "斯人倘若斯，似可敵王愾。", "云胡萬夫特，甘受巾幗遺。", "鶉兮爾固微，或者寧不愧。"]'),
('4d4e214c-0e7f-46b8-924f-290efd602a30','吳江夜泊','俞德鄰','宋','宋诗','song-poetry','','[]','扁舟渺何之，洶洶吳江水。',120,'全唐诗/poet.song.236000.json','["扁舟渺何之，洶洶吳江水。", "走馬見新堤，垂虹失舊址。", "戰艘列旌旗，隨風紛旖旎。", "須臾暝色至，悲笳數聲起。", "椎髻黄鬚兒，臂槍挾弧矢。", "篙夫趣登舟，掩篷不敢視。", "但聞深夜中，刁斗鳴不已。", "及明問前途，山長川瀰瀰。", "我生苦漂零，十載行萬里。", "焉知及茲晨，憂傷淚如洗。"]'),
('0904e348-8a73-4cdd-bff1-f56f8a9a5eba','過釣臺','俞德鄰','宋','宋诗','song-poetry','','[]','行色苦迢遞，人煙渺淒涼。',96,'全唐诗/poet.song.236000.json','["行色苦迢遞，人煙渺淒涼。", "泊舟值嚴瀨，濯纓感滄浪。", "赤符讖龍鬭，白水瞻鳳翔。", "淳風協玄德，客星隠寒芒。", "桑溟忽變易，草木猶芬芳。", "嗟予遘迍蹇，垂老悲興亡。", "溪湍兀小艇，嵐氣昏戰場。", "安得釣臺釣，尚友狂奴狂。"]'),
('99ba1b6c-7e77-4fc2-b3d2-bd55b4cf4795','蘭溪叟','俞德鄰','宋','宋诗','song-poetry','','[]','戎戎溪市暗，翳翳山雲昏。',144,'全唐诗/poet.song.236000.json','["戎戎溪市暗，翳翳山雲昏。", "驚雷趣凍雨，頃刻如翻盆。", "潦漲蛟蜃作，厓裂魑魅奔。", "遊子亦惝怳，舍櫂投孤村。", "及明浮霽色，步入蘭江門。", "烈風煽劫火，百室一二存。", "忽逢病羸叟，呻吟行路難。", "問之苦何疾，滿體催租瘢。", "千村盡荆杞，何以輸王官。", "嗟我擇術闇，半生誤儒冠。", "濟世雖有志，老去徒悲酸。", "對此重惻怛，凜凜毛生寒。"]'),
('ad24bdfa-fff6-4058-a5cf-fd795a58fe44','龍門嶺','俞德鄰','宋','宋诗','song-poetry','','[]','沮洳棧道濕，慘澹旌竿暮。',96,'全唐诗/poet.song.236000.json','["沮洳棧道濕，慘澹旌竿暮。", "經行茲山中，髣髴龍門句。", "借問山何名，亦以龍門故。", "祝融鞭火虯，正晝紛馳騖。", "乾坤一洪鑪，何適非窘步。", "况茲履嵌岑，豺狼隘前路。", "及暮雲氣陰，霈然灑甘霔。", "迺知天地仁，不待蒼生訴。"]'),
('0979c09d-5ca1-442c-ae39-56a25b24b1f0','麗陽祠','俞德鄰','宋','宋诗','song-poetry','','[]','峭壁出蒙蘢，澄溪深漭潒。',156,'全唐诗/poet.song.236000.json','["峭壁出蒙蘢，澄溪深漭潒。", "碧瓦映朱扉，雕甍燦金榜。", "巫覡紛後先，苾芬盛肸蠁。", "云此麗陽祠，桂籍夙所掌。", "當時逢掖士，祈禬何穰穰。", "歘然夢寐通，其應捷影響。", "我學非時須，青紫絕妄想。", "及茲值艱虞，乾坤倦摇蕩。", "山行愁虎狼，川游畏夔罔。", "故鄉隔三秋，煙塵極坱莽。", "神兮罔時怨，訶護迄來往。", "中夜若有聞，縹渺隘雲仗。", "及明泛逆溪，祥飈送雙槳。"]'),
('6fc5a86e-2266-46e7-994f-5ecec9d5f084','前哀哉行','俞德鄰','宋','宋诗','song-poetry','','[]','妾家淛水東，一門十朱輪。',180,'全唐诗/poet.song.236000.json','["妾家淛水東，一門十朱輪。", "男多止一女，鍾愛歸妾身。", "七歲誦經史，十歲學補紉。", "十五事機杼，二十供藻蘋。", "不忍嫁張掖，愛我歸寧頻。", "去年邊事起，處處驚爲燐。", "盡室遯空谷，雷雨彌半旬。", "狐兔伴我食，虎狼爲我鄰。", "羣盜政猖獗，白晝昏埃塵。", "驚憂轉成疾，抱痛不敢呻。", "傳聞官軍至，草木生歡欣。", "豈料反縱暴，舞戈獵生人。", "倉皇不得避，驅斥行海濱。", "避寇寇幸免，依人人不仁。", "哀哉有如此，妾生何不辰。"]'),
('6c7f6e0a-effa-47d2-b6cc-06da09ce5830','後哀哉行','俞德鄰','宋','宋诗','song-poetry','','[]','前年强寇至，倉忙避空谷。',132,'全唐诗/poet.song.236000.json','["前年强寇至，倉忙避空谷。", "我里數百家，及歸半魚肉。", "去年南軍來，詎意行殺戮。", "縱暴與寇等，十家九家哭。", "今年迎北軍，膜拜卷兩足。", "死者歸塗泥，存者依草木。", "驚魂苦未定，乃復遭驅逐。", "凄凄廛市間，寒月照逃屋。", "乾坤等覆持，聖明均喣育。", "而我天降凶，伊誰怨荼毒。", "哀哉勿重陳，回首訴力牧。"]'),
('a5f4f5f8-4430-4dc4-8a4b-0420cc4799d0','秋夜雜興三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','客舍坐不寐，隠隠聞秋碪。',84,'全唐诗/poet.song.236000.json','["客舍坐不寐，隠隠聞秋碪。", "清露月中下，凉颸開我襟。", "明河斜欲落，斗柄橫嶔崟。", "寒螿亦何事，徹夜長悲吟。", "起坐萬感集，松泉響天琴。", "海闊闊有涯，山高高有岑。", "客懷浩無極，及此秋夜深。"]'),
('17e9edf1-80c1-4b6a-aad8-b4e3064c6978','秋夜雜興三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','凉風起秋夜，露冷梧葉飛。',84,'全唐诗/poet.song.236000.json','["凉風起秋夜，露冷梧葉飛。", "棘林照熠燿，促織無停機。", "窗前有孤鵩，鳴嘯聲譩譩。", "援琴鼓清商，哀怨凝金徽。", "伯牙久不作，至音知者稀。", "徒令世俗耳，增此兒女悲。", "棄置復棄置，明月斜侵帷。"]'),
('5fa44c7f-e5da-4e49-9f7a-267a722ffee7','秋夜雜興三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','明月何皎皎，流光入城闉。',120,'全唐诗/poet.song.236000.json','["明月何皎皎，流光入城闉。", "永懷遼鶴去，及歸無故人。", "故人亦何許，往事不忍陳。", "龍逝鼎河寂，麟傷周道湮。", "桑溟變俄頃，干戈徧穹垠。", "眼中萬年少，談笑乘朱輪。", "王侯與卿士，零落隨埃塵。", "興亡固有數，貴賤亦有因。", "狐裘冬則御，桃笙夏乃珍。", "萬事每如此，毋爲徒苦辛。"]'),
('f994e3d0-52aa-417f-99c2-7ae073626011','常州天慶觀畫龍二世傳仙筆一點睛乘雷電飛去一經兵火亦不復存','俞德鄰','宋','宋诗','song-poetry','','[]','毘陵天慶宮中壁，夭趫雙龍勢千尺。',128,'全唐诗/poet.song.236000.json','["毘陵天慶宮中壁，夭趫雙龍勢千尺。", "鬐圓尾壯角浪平，目深鼻豁鱗纖密。", "一龍點睛已飛去，電掣金蛇雷破柱。", "一龍舊壁尚蜿蜒，朝昏恍惚騰雲霧。", "黑風動地劫火燔，鬼神糜爛龍崩奔。", "蒼生百萬化魚肉，𥁃池觱沸骸陵屯。", "靈物去留應有數，戛銅吹竹誰韶頀。", "會歸罨畫吸清谿，一雨八荒均布濩。"]'),
('265f81bc-00a2-402d-b673-0414ca365258','獨孤檜','俞德鄰','宋','宋诗','song-poetry','','[]','烈帝祠中獨孤檜，鬰鬰亭亭一車蓋。',96,'全唐诗/poet.song.236000.json','["烈帝祠中獨孤檜，鬰鬰亭亭一車蓋。", "根盤九地蟄蛟螭，幹聳層霄浮霮䨴。", "朔風贔屭塵晝昏，炎炎譌火連空燔。", "一蛇騰驤赤帝子，將軍舌齶空驚反。", "天愁地泣鬼神怒，元緒老桑哀莫訴。", "斤斧侵尋歲月枯，寂寞半心承雨露。"]'),
('9a37ba18-91e8-464c-b314-32c0f52380c2','春怨','俞德鄰','宋','宋诗','song-poetry','','[]','垂楊带雨煙沈沈，綺窗翠幕清晝陰。',32,'全唐诗/poet.song.236000.json','["垂楊带雨煙沈沈，綺窗翠幕清晝陰。", "琵琶撥盡誰知音，一聲望帝春事深。"]'),
('eb82309c-7089-473b-b641-a5385b0da22b','鵓鴣詞','俞德鄰','宋','宋诗','song-poetry','','[]','鵓鴣鵓鴣，爾拙無伍。',346,'全唐诗/poet.song.236000.json','["鵓鴣鵓鴣，爾拙無伍。", "朝飛何從來，暮宿何處所。", "飲啄不自營，日日呱呱叫春雨。", "沙場鬼哭天沈陰，澤國夔魈夜相語。", "一聲兩聲雲冥冥，三聲四聲水建瓴。", "十聲百聲大雨車軸下，千聲萬聲江翻海漲鼇宮傾。", "羲和推車不敢出，鮫人畏濕綃機停。", "淤泥三尺百賈卧，十家一二炊煙青。", "鵓鴣鵓鴣喚雨又不已，教爾閉觜不閉觜。", "再拜拜天公，箋詞小心風。", "雨師屏翳，雲師豐隆。", "鵓鴣爾何物，盜天之柄裒頑凶。", "天晴呼婦雨逐婦，寄巢生子隨西東。", "願天敕后羿，挾矢操强弓。", "射逐九州外，勿使孳尾添雌雄。", "天關九重暗氛霧，鵓鴣飛來復飛去。", "黔黎𫙺𫙺生魚頭，鵓鴣猶自鳴不休。", "重爲告曰，鵓鴣鵓鴣，爾形甚眇，爾聲孔悲。", "爾鳴不止，爾心何爲。", "伊昔黄帝作，鳳凰巢阿閣。", "此時無爾鳴，五風十雨天下樂。", "又聞有虞氏，韶成鳳凰至。", "此時無爾鳴，風雨弗迷天下治。", "爾今雖彊顔，不如闔口歸深山。"]'),
('c2371ad1-744e-41a8-8d10-0a2a20bf7fdc','送丹山林秀才','俞德鄰','宋','宋诗','song-poetry','','[]','燕臺築黄金，致士合隗始。',144,'全唐诗/poet.song.236000.json','["燕臺築黄金，致士合隗始。", "子留既朞月，及歸乃白士。", "豈伊賦萬言，不直一杯水。", "提携古錦囊，尚詫驪珠比。", "得非坐詩窮，顦顇至於此。", "丈夫貴出世，卿相偶然爾。", "晝繡豈必榮，韋布何足恥。", "僞遊淮陰縛，紿載晁錯死。", "所以賢達人，咄咄從黄綺。", "丹山有源泉，清可以洗耳。", "丹山有奇石，堅可以礪齒。", "去去勿咨嗟，時止固應止。"]'),
('3a803241-3ab0-4a03-bf13-063a2a02746f','次韻陳靜佳治中九日見寄','俞德鄰','宋','宋诗','song-poetry','','[]','凉飈滌殘暑，霽宇藹清氣。',120,'全唐诗/poet.song.236000.json','["凉飈滌殘暑，霽宇藹清氣。", "悠然采黄華，誰望白衣至。", "江州老使君，懷人寤不寐。", "清尊遠送將，驚呼候門稚。", "一醉得我生，五斗寧復計。", "衰榮本無期，出處各有意。", "醒者彼自醒，醉者彼自醉。", "醒醉更相嗤，死生同一寄。", "嗟嗟戲馬臺，千古誇勝地。", "誰知柴桑翁，醉中有真味。"]'),
('829447ce-8986-4f95-a187-8c294c6b0451','題寒江聽雨圖','俞德鄰','宋','宋诗','song-poetry','','[]','江風渺雲鴻，江雨濕煙樹。',48,'全唐诗/poet.song.236000.json','["江風渺雲鴻，江雨濕煙樹。", "扁舟出波濤，悠然於此住。", "掩篷卧看書，不受蛟龍怖。", "焉知臨流人，擾擾需翁渡。"]'),
('6dd0fc85-3a0b-4fcb-a09e-2b52f77e546a','聶道錄和王寅甫外郎雪詩因次韻仍依白戰體','俞德鄰','宋','宋诗','song-poetry','','[]','黑螭駕趣玄冥來，朔風捲地飛塵埃。',224,'全唐诗/poet.song.236000.json','["黑螭駕趣玄冥來，朔風捲地飛塵埃。", "江南澶漫數十郡，太半化作昆明灰。", "窮陰用壯勢獵獵，田父嚇嚇何時哉。", "龍公行雪亦詫事，縹緲落屑隨飈回。", "八荒炫晃盡一色，羽衛隔遠空黄臺。", "閉門窮巷獨僵卧，餓死已分如墨胎。", "譁譁傳誦汝潁句，凍口久合逌然開。", "當年白戰禁體物，練絮玉月銀梨梅。", "醉翁仙去不可作，欲追勝賞誰傳杯。", "荒丘坳垤陷猊虎，老樹𠗉𠗨封莓苔。", "風塵澒洞詩事廢，巨筆把槊無雄材。", "嗟余客路二千里，夢寐無復斑衣萊。", "何當賓日照暘谷，蘇息困約無繩菑。", "會趨賓館賀元獻，不敢合閙騷樽罍。"]'),
('bff21185-aae1-40e5-b895-23e675b7c6db','望夫石','俞德鄰','宋','宋诗','song-poetry','','[]','朝望夫，暮望夫。',44,'全唐诗/poet.song.236000.json','["朝望夫，暮望夫。", "望夫夫不至，江樹煙模糊。", "一朝化爲石，誰知望夫苦。", "獨有堅貞心，千古復萬古。"]'),
('6685410d-74e5-4a6f-9712-3d962df6853b','三五七言詩','俞德鄰','宋','宋诗','song-poetry','','[]','守錢虜，抱官囚。',36,'全唐诗/poet.song.236000.json','["守錢虜，抱官囚。", "銅山富埒國，金印班徹侯。", "宛其死矣人入室，不義而富嘻雲浮。"]'),
('d3e30a62-f6c5-4ff1-970c-f3cdb0f1fb96','次韻陳彥實遊羅漢寺','俞德鄰','宋','宋诗','song-poetry','','[]','林泉近城市，而無城市人。',156,'全唐诗/poet.song.236000.json','["林泉近城市，而無城市人。", "携壺散游屧，心境同一春。", "何必事幽討，辭家入西秦。", "西秦苦迢遞，勞我金閨身。", "不如遠公社，醉倒人不嗔。", "百年電明滅，萬事蠖屈伸。", "所以古達士，死葬陶者鄰。", "或者爲甕盎，尚得日飲醇。", "豈比夷與齊，忍饑以求仁。", "吾生幸未化，有酒勿厭頻。", "一杯復一杯，浩歌落梁塵。", "但問客醉醒，不問疎與親。", "君看北邙墓，松柏多爲薪。"]'),
('cc951117-decf-4597-b0ad-ae69c13fe60a','陳登父和再用韻奉答共說江南杜禪','俞德鄰','宋','宋诗','song-poetry','','[]','煌煌光明宮，中有西方人。',156,'全唐诗/poet.song.236000.json','["煌煌光明宮，中有西方人。", "當年修何道，辛苦踰十春。", "道成就空滅，姬周遽嬴秦。", "空令億萬劫，稽首金色身。", "我無忍辱行，獨立招衆嗔。", "常願習浄業，趺坐脚不伸。", "向來宿木下，亦頗鐘梵鄰。", "傲睨遠公社，沈冥栗里醇。", "終然守陋巷，尚友顔生仁。", "豈伊石頭路，行行欠頻頻。", "百年三萬日，奄忽如飈塵。", "癡人昧非想，念念生疎親。", "何當見佛影，國清甘爨薪。"]'),
('59ed72ef-97d6-42bf-8f28-1e6cc5badf3e','次韻陳登父風雨枕上書懷','俞德鄰','宋','宋诗','song-poetry','','[]','霧氣黯層峯，雨聲諠萬瓦。',96,'全唐诗/poet.song.236000.json','["霧氣黯層峯，雨聲諠萬瓦。", "蘧然夢華胥，茲寐殆非假。", "寐久失晨興，喔喔鄰雞鳴。", "雞鳴雞自鳴，我本忘吾形。", "忘形豈徇物，況乃真坦率。", "人生壽百年，能得幾日月。", "日月去堂堂，河流逝活活。", "覺悟不早計，龜筒恐難脫。"]'),
('987c8a31-09c9-4aa5-91fd-9c4a3b981569','舟行','俞德鄰','宋','宋诗','song-poetry','','[]','扁舟夾港下，漕渠溢春水。',132,'全唐诗/poet.song.236000.json','["扁舟夾港下，漕渠溢春水。", "水邊兩翁仲，閲人亦多矣。", "其中鬰佳城，寂寞向千祀。", "岡巒失故態，草木罹新燬。", "緬想窀穸初，鳴笳汎清汜。", "送車數千兩，夾道陳簠簋。", "歲月迅不留，嗟嗟遽如此。", "因知人間世，變化倏忽耳。", "金箱貯茂陵，籧篨槃石子。", "貴賤雖不侔，腐壞畧相似。", "踟躕復踟躕，蒙莊信達士。"]'),
('b58e0d9e-ba71-47fc-80b4-3008770c32e5','題郭元德所藏龔聖予瘦馬圖','俞德鄰','宋','宋诗','song-poetry','','[]','吾聞神駿之肋十有五，雄姿矯矯騰龍虎。',226,'全唐诗/poet.song.236000.json','["吾聞神駿之肋十有五，雄姿矯矯騰龍虎。", "四蹄踣鐵尾捎風，藐視崑崙薄玄圃。", "何時歷塊誤一蹶，棄置荒林翳榛莽。", "思昔先朝十二閑，駓駰騏駱充其間。", "此馬當時最倜儻，流沙萬里來函關。", "祇今淪落歸人世，何人保養思終惠。", "髯龔前身李伯時，殷勤染翰憐權奇。", "崚嶒瘦骨見者歎，度越駑駘猶萬萬。", "天上房星久已空，此圖此馬俱難逢。", "主人愛圖如愛馬，收拾瓌文爲模寫。", "我知髯龔欲畫時，天地黯黲風煙悲。", "離離禾黍今如此，誰識羸驂真騄駬。", "明年野外春草平，瑶池八駿還爭鳴。", "此時更倩髯龔筆，一掃籋雲龍八尺。"]'),
('c599a1f2-0353-48ce-8907-494e76c24b1d','京口遣懷呈張彥明劉伯宣郎中并諸友一百韻','俞德鄰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','壞雲覆紫微，疾風捲黄屋。',288,'全唐诗/poet.song.236000.json','["壞雲覆紫微，疾風捲黄屋。", "生靈半塗炭，社稷竟傾覆。", "借問誰厲階，往事具可復。", "穆陵握乾符，丁揆覆鼎餗。", "北兵渡滸黄，沔鄂盛諠讟。", "漣海蕩爲墟，交廣駭斡腹。", "兀然天柱摇，凜甚國脈蹙。", "明詔起臣潛，扶顛秉鈞軸。", "將帥一奮呼，江漢奏清肅。", "維時望公閭，高譽儗方叔。", "遄歸持相印，景定實初卜。", "百寮逆近郊，至尊畧邊幅。", "策勳告廟庭，陳樂備敔柷。", "煌煌福華編，傳者筆爲禿。", "焉知事夸毗，欲掩天下目。", "得政曾幾何，故老盡斥逐。", "哀哀杞天崩，度皇繼歷服。", "定策比周召，卜世過郟鄏。", "萬微委巖廊，十年卧林麓。", "金屋貯娉婷，羽觴醉醽醁。", "伍符日空虛，郿鄔富儲蓄。", "紛紛輕薄徒，睒眒希自鬻。", "荃蕙化爲茅，龜玉毀於櫝。", "怡然談笑間，禍機已潛伏。"]'),
('9935a4f1-7cf5-4222-afe1-f99433692e5c','宿高郵露筋','俞德鄰','宋','宋诗','song-poetry','','[]','午發淮子口，晚泊露筋北。',192,'全唐诗/poet.song.236000.json','["午發淮子口，晚泊露筋北。", "舟人指靈祠，欲語輒歎息。", "伊昔避亂初，女郎實英特。", "行行侍丘嫂，日暮雲氣黑。", "嫂兮宿鄰莊，我寧止路側。", "我生雖不辰，秉身貴弗㥾。", "草深聚蚊虻，中夜紛鼓翼。", "吮血噆人膚，其毒甚沙蜮。", "女郎不肯顧，筋露身亦踣。", "至今是邦人，廟貌嚴血食。", "惜哉歲月深，姓氏不可識。", "維士有百行，維女獨四德。", "貞潔一以虧，姬姜徒國色。", "所以古婦人，送迎不踰閾。", "嗟嗟露筋事，可爲百世則。", "胡然世俗人，所重在傾國。"]'),
('8333af4d-0d1c-45f3-a2fb-3ea750c0dd77','次韻答王國華','俞德鄰','宋','宋诗','song-poetry','','[]','甚矣吾衰矣，懷哉予歸哉。',192,'全唐诗/poet.song.236000.json','["甚矣吾衰矣，懷哉予歸哉。", "雀蜃不能化，何用充海淮。", "王郎東魯秀，玉質離氛埃。", "青絲絡白馬，嘯吟浮玉隈。", "餘子錄錄耳，誰敢相朋儕。", "一朝款柴戶，嚴若問子來。", "又疑蒙穀士，汗漫期九垓。", "嗟我晚聞道，可人常永懷。", "亂後苦契闊，襟抱無由開。", "常深越鳥志，自靦莊櫟材。", "感子慰離索，駕言且勿催。", "人生駒過隙，髮白不再孩。", "雞鳴舜爲善，犬放軻所哀。", "文字乃其閏，末俗供驩咍。", "朂哉聖賢事，充此天降才。", "贈言愧斐率，過此誰能裁。"]'),
('d1a1718c-db28-4e26-b6c0-97c4f52dec52','贈朐山孫畫師','俞德鄰','宋','宋诗','song-poetry','','[]','少年酷愛山，移家入山住。',156,'全唐诗/poet.song.236000.json','["少年酷愛山，移家入山住。", "朅來廛市中，塵土涴巾屨。", "有時擬山遊，大笑出門去。", "二毛颯垂領，乃乏濟勝具。", "歸來笏拄頤，意欲凌風翥。", "朐山有佳人，以我愛山故。", "九曲武夷溪，移將置縑素。", "禽鳥紛飛翔，煙雲莽回互。", "林深虎豹藏，石怪龍蛇騖。", "對此竟忘疲，興與精靈聚。", "想當槃礴臝，下筆有神助。", "不然方丈間，那有許奇趣。", "安得絹千疋，煩君畫瑶圃。"]'),
('8c9d4615-1a71-4e9c-a4f7-e20617a38d56','雙清堂詩爲石民瞻賦','俞德鄰','宋','宋诗','song-poetry','','[]','黄塵沒馬腹，洪濤噴鷁首。',144,'全唐诗/poet.song.236000.json','["黄塵沒馬腹，洪濤噴鷁首。", "是身如轉蓬，隨風任飛走。", "歸來丘壑中，高袖拄笏手。", "牀頭一束書，壁下一壺酒。", "暴背對青山，杖藜從白叟。", "乃知羲皇上，何嘗離北牖。", "民瞻真可人，青歲紆墨綬。", "一朝拂衣去，歸種彭澤柳。", "蕭然林下意，今無古或有。", "富貴等浮雲，斯須變蒼狗。", "終南政自佳，不作捷徑不。", "仁者贈以言，立名要不朽。"]'),
('fa67b516-895b-44ef-96b7-7e3d48426b8b','山陽客中雜言四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','三載行萬里，勞生真轉蓬。',96,'全唐诗/poet.song.236000.json','["三載行萬里，勞生真轉蓬。", "轉蓬去日遠，何時歸本叢。", "萬古一生死，趨競徒怱怱。", "況復遭喪亂，天地多秋風。", "退無鹿門隠，進乏麟閣功。", "一歲復一歲，倏忽成衰翁。", "嵇康殊寡識，陶潛真固窮。", "蕭然北窗下，瓶粟從屢空。"]'),
('fdd2b6d7-4916-4941-a973-dec8af029c1e','山陽客中雜言四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','秋帆泊淮浦，小山倏春風。',132,'全唐诗/poet.song.236000.json','["秋帆泊淮浦，小山倏春風。", "春風到花柳，青青間深紅。", "散屧慰寂寞，道與征夫逢。", "爲言喪亂後，十室八九空。", "村墟暗荆杞，渚澤哀飛鴻。", "奈何數下令，科歛紛錯重。", "語已仰天歎，泣涕霑其胸。", "嗚呼天地德，微小無不容。", "貴人豈不仁，視汝如蒿蓬。", "會聞賢刺史，撫汝如漢龔。", "征夫甫收泣，悍吏來自東。"]'),
('30e1c210-3b5a-4f51-b31c-e4e4cc8e7abe','山陽客中雜言四首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','衰年逢世變，人事如蟣蝨。',96,'全唐诗/poet.song.236000.json','["衰年逢世變，人事如蟣蝨。", "憂端常澒洞，頭垢不暇櫛。", "檣烏終歲飛，况復無寧日。", "方春暫返櫂，浹辰卧蓬蓽。", "天風倏吹衣，輕易復一出。", "旅巢乏安枝，如意十不一。", "七秩能幾何，日月過箭疾。", "夜深不成眠，吟蟲助唧唧。"]'),
('ec65c8fd-5bb0-4182-9362-a12a82c595f4','山陽客中雜言四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','淮城酒味薄，酸澀如敗虀。',96,'全唐诗/poet.song.236000.json','["淮城酒味薄，酸澀如敗虀。", "一千沽一斗，聊欲紓慘悽。", "壺傾不成醉，羈思終轉迷。", "因思古達士，山林卜幽棲。", "暴背坐捫蝨，看雲閒杖藜。", "理亂耳不聞，其樂無端倪。", "紛紛彼俗子，諂笑勞夏畦。", "安知萬世下，清風想夷齊。"]'),
('34f4f70a-081c-4358-9c10-a49cef6cc926','以竹院逢僧爲韻集杜工部句贈鶴林老別流禪師四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','卜居期靜處，采藥山北谷。',48,'全唐诗/poet.song.236000.json','["卜居期靜處，采藥山北谷。", "鶴下雲汀近，逕轉山田熟。", "回首望松筠，登危聚麋鹿。", "興深終不渝，日暮倚修竹。"]'),
('e3a182c8-2863-4f8e-8a33-42501d9ae737','以竹院逢僧爲韻集杜工部句贈鶴林老別流禪師四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','松門耿疎影，天黑閉春院。',48,'全唐诗/poet.song.236000.json','["松門耿疎影，天黑閉春院。", "長風中怒號，白日遞隠見。", "惠遠德過人，秀發吾所羨。", "晤語契深心，風牀展書卷。"]'),
('675a6daa-1d6f-4579-9c07-736ee4fbd6a6','以竹院逢僧爲韻集杜工部句贈鶴林老別流禪師四首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','道林才不世，離別重相逢。',48,'全唐诗/poet.song.236000.json','["道林才不世，離別重相逢。", "會面慰我久，觀身向酒慵。", "寂寥人散後，結構坐來重。", "況乃氣清爽，娟娟林表峯。"]'),
('8557a6a7-b3b9-4bf1-a37e-bc13aa5e9434','以竹院逢僧爲韻集杜工部句贈鶴林老別流禪師四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','浮生如過隙，世故莽相仍。',48,'全唐诗/poet.song.236000.json','["浮生如過隙，世故莽相仍。", "畧稅林下鞅，遠訪雲端僧。", "願聞第一義，將衰棲大乘。", "清談有滋味，小子得無承。"]'),
('b276d526-bdfb-486d-8366-9574b5a960ca','題王謝燕游圖爲楊少監作 王茂弘','俞德鄰','宋','宋诗','song-poetry','','[]','犧牛石馬出寶圖，百年江左一夷吾。',72,'全唐诗/poet.song.236000.json','["犧牛石馬出寶圖，百年江左一夷吾。", "西風不受元規污，八鑾指日還舊都。", "天時人事重嗚呼，翠幢金節聊燕娛。", "堂堂玉立森戟鬚，猶似拱揖稱蘭闍。", "公乎公乎真丈夫。"]'),
('ccc6e362-44e0-4567-8d8d-042a76b51145','題王謝燕游圖爲楊少監作 謝安石','俞德鄰','宋','宋诗','song-poetry','','[]','夕陽亭中語未已，一合乾坤匝瘡痏。',72,'全唐诗/poet.song.236000.json','["夕陽亭中語未已，一合乾坤匝瘡痏。", "瘡生望公公不起，携妓東山玩山水。", "神州陸沈寧不恥，正頼絲竹陶寫耳。", "淮淝風鶴繇密指，固應孩視桓元子。", "吁嗟公乎真傑士。"]'),
('38280b1a-f91e-42b3-81f9-26e7d3084d38','暇日飲酒輒用靖節先生韻積二十首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','世路日已迫，吾行將安之。',60,'全唐诗/poet.song.236000.json','["世路日已迫，吾行將安之。", "醉鄉無畔岸，俗似太古時。", "一廛昔願受，或者當在茲。", "在茲竟卜築，何爲復狐疑。", "但得酒杯在，無螯還可持。"]'),
('42097e6f-3b32-4ecc-96cd-8aeb27fd432d','暇日飲酒輒用靖節先生韻積二十首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','鼓刀戰牧野，采薇餓西山。',48,'全唐诗/poet.song.236000.json','["鼓刀戰牧野，采薇餓西山。", "出處各有意，喋喋俱空言。", "不如得美酒，一醉終餘年。", "賢愚死則已，死去知誰傳。"]'),
('e38ffb11-b9a5-4daa-a939-6f82934074e5','暇日飲酒輒用靖節先生韻積二十首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','嗜酒有何好，酒酣見真情。',60,'全唐诗/poet.song.236000.json','["嗜酒有何好，酒酣見真情。", "忍斷杯中物，而留身後名。", "名譽外物爾，醉乃得此生。", "神完氣不懾，墜車終莫驚。", "何必事輕舉，崆峒師廣成。"]'),
('80fcf888-74be-43c6-9b78-84aef48587f6','暇日飲酒輒用靖節先生韻積二十首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','餌香魚深逝，弋篡鴻高飛。',72,'全唐诗/poet.song.236000.json','["餌香魚深逝，弋篡鴻高飛。", "商皓雖寂寞，幸免阬焚悲。", "云何客卿輩，逐去還依依。", "一朝歎黄犬，骨肉異所歸。", "貴盛能有幾，轉盼倏已衰。", "衰榮苟如此，得酒無相違。"]'),
('2d33d749-8568-4e25-a058-77e94e925223','暇日飲酒輒用靖節先生韻積二十首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','山林厭岑寂，城市嗟庳諠。',60,'全唐诗/poet.song.236000.json','["山林厭岑寂，城市嗟庳諠。", "醉鄉有佳趣，其地幽且偏。", "清商叩前林，白雲依遠山。", "漁樵二三子，朝暮相往還。", "舉酒坐爭席，亦復多至言。"]'),
('4a61c524-9fd9-4670-bc6a-2fa947a40eb9','暇日飲酒輒用靖節先生韻積二十首  其六','俞德鄰','宋','宋诗','song-poetry','','[]','毀以是爲非，譽以非爲是。',48,'全唐诗/poet.song.236000.json','["毀以是爲非，譽以非爲是。", "是非自有真，不在譽與毀。", "譽堯復毀桀，兩忘固佳耳。", "不見繒布紋，眼醉眩成綺。"]'),
('5eb1a2d9-dfd7-4c4f-b69c-6cefb641d4ea','暇日飲酒輒用靖節先生韻積二十首  其七','俞德鄰','宋','宋诗','song-poetry','','[]','三閭愛秋菊，浥露餐落英。',60,'全唐诗/poet.song.236000.json','["三閭愛秋菊，浥露餐落英。", "獨醒鄙衆醉，乃覺非人情。", "楚亡如厦仆，一木那支傾。", "離騷固憤切，聒聒如蛩鳴。", "餔糟何必惡，一醉觀我生。"]'),
('711f12b8-8552-42f3-a56f-da0032744a19','暇日飲酒輒用靖節先生韻積二十首  其八','俞德鄰','宋','宋诗','song-poetry','','[]','霜松無悴色，春花有餘姿。',60,'全唐诗/poet.song.236000.json','["霜松無悴色，春花有餘姿。", "勿以春花妍，棄彼霜松枝。", "悠悠風塵中，始見達士奇。", "公田可種秫，絃歌聊爾爲。", "意倦即歸去，五斗何能羈。"]'),
('fc792ed1-f7ed-4897-84a4-189a343a18b0','暇日飲酒輒用靖節先生韻積二十首  其九','俞德鄰','宋','宋诗','song-poetry','','[]','凉飈起木末，尊酒聊獨開。',96,'全唐诗/poet.song.236000.json','["凉飈起木末，尊酒聊獨開。", "開尊念故友，亦復傷我懷。", "翻然蹈東海，甘與時世乖。", "豈比爲佞者，日夕常栖栖。", "如何事與跡，零落歸塗泥。", "誅奸無董狐，志怪空齊諧。", "安知萬世下，善惡無謬迷。", "不如日飲酒，勿使腸九回。"]'),
('53c9e180-aa73-4dbc-9d32-9f4ab5e90130','暇日飲酒輒用靖節先生韻積二十首  其一○','俞德鄰','宋','宋诗','song-poetry','','[]','輕風颺高幟，摇摇城西隅。',60,'全唐诗/poet.song.236000.json','["輕風颺高幟，摇摇城西隅。", "杖藜沽一醉，雨霽泥滿塗。", "欲借東家馿，泥滑不敢驅。", "歸來取敗榼，悵然瀝其餘。", "一醉不易得，醉鄉真可居。"]'),
('61e3614d-1b5a-4702-b50a-8f57c4a96150','暇日飲酒輒用靖節先生韻積二十首  其一一','俞德鄰','宋','宋诗','song-poetry','','[]','昔爲饑所驅，束書涉遠道。',72,'全唐诗/poet.song.236000.json','["昔爲饑所驅，束書涉遠道。", "俯仰四九年，少壯忽已老。", "引杯沃衰顔，杯盡顔復槁。", "人生如電露，安得長美好。", "所以彼至人，達生以爲寶。", "形全精不虧，高蹈八極表。"]'),
('6c7b3f81-57c6-40b9-8325-629146ffd81b','暇日飲酒輒用靖節先生韻積二十首  其一二','俞德鄰','宋','宋诗','song-poetry','','[]','醉中忘世事，猶有酒醒時。',72,'全唐诗/poet.song.236000.json','["醉中忘世事，猶有酒醒時。", "未醒輒復醉，乃得與世辭。", "伯倫頌酒德，佳趣端在茲。", "云何禮法士，聞風獨遲疑。", "濁酒聊可恃，淵明不吾欺。", "去去勿復道，有酒吾中之。"]'),
('51aaf57f-3010-424a-8737-625cedc7cec6','暇日飲酒輒用靖節先生韻積二十首  其一三','俞德鄰','宋','宋诗','song-poetry','','[]','百年三萬日，已入桑榆境。',60,'全唐诗/poet.song.236000.json','["百年三萬日，已入桑榆境。", "沈醉復幾時，而令終日醒。", "爰絲飲亡何，此事要心領。", "有錐姑處囊，無用求脫穎。", "霧豹亦何辜，傷生在文炳。"]'),
('940c3376-cae3-4947-b7d6-d4307f0d8489','暇日飲酒輒用靖節先生韻積二十首  其一四','俞德鄰','宋','宋诗','song-poetry','','[]','淵明昔閒居，偶爾白衣至。',60,'全唐诗/poet.song.236000.json','["淵明昔閒居，偶爾白衣至。", "開尊得美酒，忽焉遂復醉。", "醉語聊自娛，辭多失詮次。", "安知後千年，乃爲世所貴。", "詩雖有餘音，酒亦有真味。"]'),
('145c55e6-ca5a-4745-a9ef-a3b1ed532ea7','暇日飲酒輒用靖節先生韻積二十首  其一五','俞德鄰','宋','宋诗','song-poetry','','[]','凄凉三徑中，中有一畝宅。',60,'全唐诗/poet.song.236000.json','["凄凉三徑中，中有一畝宅。", "庭多鳥雀喧，巷絕車馬跡。", "卧病與世疎，俯仰踰半百。", "何以銷我憂，美酒浮大白。", "獨欠高陽徒，臨風增惋惜。"]'),
('84918298-eda2-4cec-a47c-562fbc221a50','暇日飲酒輒用靖節先生韻積二十首  其一六','俞德鄰','宋','宋诗','song-poetry','','[]','昔我事决科，窮年抱六經。',72,'全唐诗/poet.song.236000.json','["昔我事决科，窮年抱六經。", "桑溟忽已變，栖栖竟無成。", "歸來請學稼，平賈充過更。", "徽絃挂空壁，襏襫留前庭。", "中夜耿不寐，惟有寒螿鳴。", "不頼一尊酒，何以紓吾情。"]'),
('915a8dd0-eb95-4db3-b639-21494f932225','暇日飲酒輒用靖節先生韻積二十首  其一七','俞德鄰','宋','宋诗','song-poetry','','[]','園中有佳菊，含英待秋風。',48,'全唐诗/poet.song.236000.json','["園中有佳菊，含英待秋風。", "惜哉無美酒，對此時一中。", "誰如王刺史，殷勤遣龐通。", "悵望復悵望，雲山挂天弓。"]'),
('b6b1c199-ee52-47a6-80f4-e0e4157990bc','暇日飲酒輒用靖節先生韻積二十首  其一八','俞德鄰','宋','宋诗','song-poetry','','[]','五十近衰境，所戒當在得。',60,'全唐诗/poet.song.236000.json','["五十近衰境，所戒當在得。", "永懷叔節輩，三者一不惑。", "寸田日敷菑，常恐易茅塞。", "猶思普天下，無有禁酒國。", "一醉終餘生，不語亦不默。"]'),
('153da0f7-9b24-467d-a7e6-25c2189ded52','暇日飲酒輒用靖節先生韻積二十首  其一九','俞德鄰','宋','宋诗','song-poetry','','[]','在昔盛壯時，爲貧亦求仕。',84,'全唐诗/poet.song.236000.json','["在昔盛壯時，爲貧亦求仕。", "終然返故廬，謀道不謀己。", "豈不憂饑寒，折腰固吾恥。", "左手招夷齊，右手揖綺里。", "何必駟馬車，策勳耀前紀。", "時行吾則行，時止吾則止。", "行止未有涯，醉鄉差可恃。"]'),
('af7715d3-1927-44d4-a06c-ab7ed2e7c8c0','暇日飲酒輒用靖節先生韻積二十首  其二○','俞德鄰','宋','宋诗','song-poetry','','[]','道喪聖復遠，姦僞紛亂真。',120,'全唐诗/poet.song.236000.json','["道喪聖復遠，姦僞紛亂真。", "山林有逸士，但飲曹參醇。", "寧著潛夫論，有死不美新。", "豈不羨爵位，比肩羞董秦。", "生爲朝中英，死爲泉下塵。", "奄忽隨物化，營營徒爾勤。", "不如寓之酒，日與糟丘親。", "秋渠溜宿雨，園蔬含土津。", "西郊澄霽景，柴車行可巾。", "有客乃竟醉，不問何許人。"]'),
('0230dc81-ae68-483f-8db7-475402674569','課僕詣田所偶用淵明庚戌歲九月中于西田穫早稻韻','俞德鄰','宋','宋诗','song-poetry','','[]','人生念何事，方寸纏憂端。',120,'全唐诗/poet.song.236000.json','["人生念何事，方寸纏憂端。", "憂端日澒洞，胡不思自安。", "富貴等電露，變滅無留觀。", "百畝雖已隘，朝耕夕復還。", "秋風穡寶實，十口無饑寒。", "何爲苦役役，而欲事所難。", "所以沮溺徒，不受名利干。", "行藏隨用舍，千載師孔顔。", "作勞有餘暇，柴門晝常關。", "斗酒且自勞，此外無足歎。"]'),
('438fcaea-cfcf-4833-b169-f18b0f82c148','連雨獨坐旅樓有作','俞德鄰','宋','宋诗','song-poetry','','[]','淫雨彌半月，河流漲通衢。',168,'全唐诗/poet.song.236000.json','["淫雨彌半月，河流漲通衢。", "舊畿十萬家，太半憂爲魚。", "旅樓起復卧，神氣鬰不舒。", "牀牀苦漏濕，豈暇論侏儒。", "緬懷十載間，洚水頻三吳。", "三吳莽一壑，平陸紛施罛。", "老羸委溝谿，少壯泣路隅。", "鬻賣及男女，庶幾活須臾。", "民窮已到骨，乃復剝其膚。", "自天發明斷，元惡隨就誅。", "疇咨用稷契，躋世當黄虞。", "政擬瘡痍瘳，詎意疾痛呼。", "陰陽繫調燮，此理信不誣。", "寄言秉鈞者，治安宜早圖。"]'),
('3ed9dd7e-ecec-4631-b781-529d0b1c08e4','爲郭元德題和靖探梅圖','俞德鄰','宋','宋诗','song-poetry','','[]','祥符真人調玉燭，四海八荒春意足。',224,'全唐诗/poet.song.236000.json','["祥符真人調玉燭，四海八荒春意足。", "孤山山小不容春，十月梅花破寒玉。", "風流詩老癖愛梅，拂曉騎馿度山曲。", "呼童忍凍折南枝，香滿吟窗伴幽獨。", "到今寫入畫圖中，骨冷神清炯雙目。", "蕩蕩巍巍堯舜天，外臣巢許誰羈束。", "前年我亦訪湖山，山色湖光竟塵俗。", "荒墳三尺走狐狸，那復寒泉薦秋菊。", "真祠併入梵王家，香月亭前馬牛牿。", "水邊籬落忽橫枝，遥睇猶艱况斤斸。", "雞園釋子皆鷹騰，挾彈揚鞭驟平陸。", "倉皇走避尚遭嗔，蹇衛何堪共馳逐。", "三百年間一夢同，人與梅花幾榮辱。", "拊圖三歎復何言，天外飛來兩黄鵠。"]'),
('4b67d8f7-c408-4d18-bc22-a138f2e571ab','次韻蕭靜安元夕書感','俞德鄰','宋','宋诗','song-poetry','','[]','鼇山倚晴昊，龍燈照澄川。',144,'全唐诗/poet.song.236000.json','["鼇山倚晴昊，龍燈照澄川。", "良宵重三五，輦路凝非烟。", "一從桑溟改，春花謝芳妍。", "銅駝暗荆杞，觸目興悲憐。", "芸芸百千態，悠悠二八年。", "金吾縱弛柝，相府誰歌蓮。", "九衢燈火市，愁雲瞀窮天。", "管寧東入海，樂毅北去燕。", "伊誰載美酒，醉我東風前。", "晨策散廣隰，晚屧周囂廛。", "所嗟世路迫，人事多變遷。", "歸來卧蓬蓽，聊復草我玄。"]'),
('6c716539-d455-4b5b-af92-efdb31762e65','小樓詩爲湯計議作','俞德鄰','宋','宋诗','song-poetry','','[]','英英人中豪，歲月閲江浪。',156,'全唐诗/poet.song.236000.json','["英英人中豪，歲月閲江浪。", "胡然構小樓，不卧百尺上。", "跂予一登臨，規制差可尚。", "座中容六客，窗外羅萬象。", "雲烟互吐吞，岡阜相背向。", "誰云眼界窄，頗覺形神王。", "乃知人間世，小大俱幻妄。", "壺公家一壺，維摩室方丈。", "擬茲十二樓，鐘鼎視杯盎。", "鵬鷃同一適，椿菌偶殊狀。", "何必事翬飛，肆目逞雄壯。", "深紅屋角花，淺碧盆池漲。", "且當共倚闌，爛漫倒春釀。"]'),
('d861a416-0fe9-40b5-a1a4-2401f8c77195','郭元德席上賦紅牡丹分韻得粉字五言十韻','俞德鄰','宋','宋诗','song-poetry','','[]','桑田變滄溟，黍宮雜蒿堇。',120,'全唐诗/poet.song.236000.json','["桑田變滄溟，黍宮雜蒿堇。", "霜臺得奇葩，誰寄天津隠。", "褰帷窺董園，撥根認洛墳。", "亭亭一萼春，風露洗塵坌。", "朱纓粲赤瑛，絳蠟照紅粉。", "莊嚴富貴姿，漏洩造化藴。", "主人戲斑衣，領客醉芳醖。", "喬梓森南山，知謂遊隠弅。", "綴席已形穢，哦詩謾營吻。", "起舞呼烏烏，君當恕楊惲。"]'),
('31412eb7-2ae5-4b9d-889a-420722fdc813','贈月篷戴相士','俞德鄰','宋','宋诗','song-poetry','','[]','雙眸炯炯秋篷月，十載聲名動京闕。',176,'全唐诗/poet.song.236000.json','["雙眸炯炯秋篷月，十載聲名動京闕。", "隆準龍顔曾爲開，麞頭鼠目誰攖揬。", "我聞論相先論心，此語古傳非恍惚。", "閭閻談笑覓侯封，渭水垂綸飄白髮。", "膾肝盜跖以壽終，趙蓋楊韓膏斧鉞。", "相形相心兩莫憑，使我向空書咄咄。", "年來四海一鼓鼙，蕭艾騰芳蘭茝歇。", "宣室寧無賈誼思，侯門半却禰衡謁。", "君歸若見袁李徒，造化韞藏須剞劂。", "我今自分老山林，渴飲壑冰饑食蕨。", "但煩一語抱璞人，莫學卞和遭再刖。"]'),
('69947e07-d18a-460d-add8-a01bfc9c1a9b','跋韓仲文所藏史共山草書','俞德鄰','宋','宋诗','song-poetry','','[]','公孫大娘舞劍器，張顛早悟回翔意。',176,'全唐诗/poet.song.236000.json','["公孫大娘舞劍器，張顛早悟回翔意。", "學書學劍雖不侔，用志凝神固無二。", "瓘也得筋靖得肉，聖趣誰能一蹴至。", "我生憂患緣知書，教兒僅使通名氏。", "春蚓秋蛇自結蟠，莫向兵曹甘委贄。", "烟薰屋漏玉軸妝，何許天風劃飛墜。", "讀一遺二口若鉗，大草閒臨真自愧。", "雖然非古空壯雄，要是逢場聊作戲。", "魯公懷素俱已仙，世指周奴笑羊婢。", "詎誇棄筆如丘山，夭閼剡藤煩嘆喟。", "捲還鯨錦心和平，塵席藜羹固吾事。"]'),
('c9910cf2-dc71-4b69-b982-2e16a5b60b7c','古意八首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','丹穴九苞鳳，荆州一角麟。',48,'全唐诗/poet.song.236000.json','["丹穴九苞鳳，荆州一角麟。", "聖明久不作，舉世誰見珍。", "紛紛賀厦雀，廼復爲嘉賓。", "嘉賓蓄爾輩，麟鳳何由馴。"]'),
('87cc390f-228b-413f-97a2-6af12cbb9095','古意八首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','真玉名以石，貞士誣以詐。',48,'全唐诗/poet.song.236000.json','["真玉名以石，貞士誣以詐。", "古今率皆然，何事獨悲咤。", "嗟哉爾卞和，智乃在葵下。", "曷不韞匵藏，待此連城賈。"]'),
('bf876238-5971-4357-84bc-d8a6d8b57afd','古意八首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','麾戈指白日，駕鴻淩紫煙。',48,'全唐诗/poet.song.236000.json','["麾戈指白日，駕鴻淩紫煙。", "終然竟無補，空羨龜鶴年。", "古來有介士，采薇首陽巔。", "雖非鍊五石，名與日月懸。"]'),
('68714dc7-7877-4944-8ed3-e0902a157d35','古意八首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','孔明感三顧，幡然扶漢家。',48,'全唐诗/poet.song.236000.json','["孔明感三顧，幡然扶漢家。", "一朝赤星隕，竟使蜀婦髽。", "雄圖雖未竟，萬世常咨嗟。", "老瞞志意滿，一笑蠻觸蝸。"]'),
('70eeda97-a014-48bd-a41a-42a771d0174b','古意八首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','宋人得燕石，寶爲希世珍。',48,'全唐诗/poet.song.236000.json','["宋人得燕石，寶爲希世珍。", "周客掩口笑，乃復遭怒嗔。", "闒茸竟尊顯，賢聖多隠淪。", "人物顧所遇，何事徒悲辛。"]'),
('b907abe2-cc07-406d-9d42-6a7d8b94f1e2','古意八首  其六','俞德鄰','宋','宋诗','song-poetry','','[]','突决華棟焚，燕雀自娛樂。',48,'全唐诗/poet.song.236000.json','["突决華棟焚，燕雀自娛樂。", "風橫喬木巔，藤蘿尚棲託。", "鳳鳥固識時，朝菌不知朔。", "佌佌何人斯，胸次爾齷齪。"]'),
('122211ef-cb89-4be2-96e0-c6afb20b2e1c','古意八首  其七','俞德鄰','宋','宋诗','song-poetry','','[]','神龍失靈淵，翳形在勺水。',48,'全唐诗/poet.song.236000.json','["神龍失靈淵，翳形在勺水。", "勺水不可容，又復制螻蟻。", "一朝駕大霆，膚寸雲萬里。", "始知勺水龍，沛雨有如此。"]'),
('df6678d9-db49-4ec4-8e03-faed1c311fee','古意八首  其八','俞德鄰','宋','宋诗','song-poetry','','[]','鼓鐘樂爰居，藻梲居大蔡。',48,'全唐诗/poet.song.236000.json','["鼓鐘樂爰居，藻梲居大蔡。", "雲壑駘背人，一生饜粗糲。", "長鑱耕黄獨，短蓑釣清瀨。", "富貴等浮雲，達生誰芥蔕。"]'),
('dc6a7480-90b6-4fce-a152-2c9df9113b51','贈丹陽邢尉','俞德鄰','宋','宋诗','song-poetry','','[]','孟郊尉溧陽，曹務緣詩廢。',192,'全唐诗/poet.song.236000.json','["孟郊尉溧陽，曹務緣詩廢。", "徘徊金瀨傍，府以假尉代。", "一生坐詩窮，酸寒見餘態。", "邢君世業儒，才猷乃十倍。", "吏隠黄綬間，詩亦性所愛。", "羸驂京峴游，古錦奚奴佩。", "扣門索我詩，丁寧至於再。", "我老學殖荒，久嗟詩力退。", "腸肚縱煎煼，落筆與時背。", "况復風雅衰，淫哇亂鄘邶。", "濟南名士多，此語出前輩。", "我昔交數公，夢寐想風裁。", "西窗剪殘燭，顧影寸心痗。", "北渚凌清河，平疇接海岱。", "子行賦歸與，我實增感慨。", "爲吾謝故人，德音幸時逮。"]'),
('0174acd8-756b-4db1-944f-a412818675f1','貓燕行','俞德鄰','宋','宋诗','song-poetry','','[]','燕飛畫梁貓越屋，飛走性殊豈相毒。',208,'全唐诗/poet.song.236000.json','["燕飛畫梁貓越屋，飛走性殊豈相毒。", "饑貓攫燕欲何爲，燕比他禽况無肉。", "可憐乳燕未出巢，探頭伺乳聲嘲嘲。", "母去不歸子饑餓，柔而害物嘻汝貓。", "汝貓不仁燕何罪，我思里人爲心痗。", "父逃官逋母繫官，悍吏催錢夜打門。", "一朝母作溝中瘠，三女一子家四壁。", "官司株逮尚不休，諸孤駢首爲纍囚。", "傳聞詔書復逃戶，日夜煢煢望其父。", "父存父歿竟不知，此冤此苦蘇何時。", "皇天覆幬均四海，人靈萬物爲物宰。", "民之無祿天薦瘥，况此微物知奈何。", "呼童屑米哺乳燕，一夜哀傷淚如綫。"]'),
('db4a9428-dc64-488d-b619-e4c9578f730a','沽酒行','俞德鄰','宋','宋诗','song-poetry','','[]','去年斗酒貫三百，路逢麴車常嘖嘖。',213,'全唐诗/poet.song.236000.json','["去年斗酒貫三百，路逢麴車常嘖嘖。", "朝來啜虀暮食鹽，汲井煎茶待佳客。", "爾時石秫十二千，仍更五千糴石麥。", "米麴柴薪價倍增，酒價雖增欲誰責。", "昨秋一稔天所憐，甌窶刈穫過良田。", "大麥小麥今又熟，麟經髣髴書有年。", "年登米麥塞市廛，官酒定價那增錢。", "一朝酒家悉閉戶，斗酒更欲沽二千。", "道逢醉者驚相顧，老夫倉忙問其故。", "答云近日添課程，去城十里皆官庫。", "豈惟酒價今日增，明日十千賣石醋。", "乞漿得酒良已難，或者乞醯鄰亦怒。", "君不見昔時三百青銅沽一斗，坊外酒徒猶忍口。"]'),
('99236634-ff11-42ed-8cb8-93968f6f5c7a','陪趙明叔侍御遊茅山次韻二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','夷言衛侯說，土風鍾儀操。',84,'全唐诗/poet.song.236000.json','["夷言衛侯說，土風鍾儀操。", "百年等逆旅，南北俱勞勞。", "何如事幽討，杖藜舒鬰陶。", "上山拾瑶草，下山折藑茅。", "尋我煙霞朋，締此金石交。", "胡然自局趣，顧影悲繫匏。", "歸去來山中，山中有松醪。"]'),
('c3550b90-5cf2-4dbb-b92b-cb824c728509','陪趙明叔侍御遊茅山次韻二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','繡衣漢使者，斧鉞嘗再操。',84,'全唐诗/poet.song.236000.json','["繡衣漢使者，斧鉞嘗再操。", "六條讋吏膽，一飯思民勞。", "翩然拂衣去，訪此華陽陶。", "蒼烟鬰松檜，白雲露菅茅。", "重岡暖靄合，平疇遠風交。", "我愛龍池水，願君酌霜匏。", "商巖沛霖雨，越流化醇醪。"]'),
('3155311d-769a-4848-b8c6-e49c7094b2a3','次韻麟洲龍仁夫遊三茅山','俞德鄰','宋','宋诗','song-poetry','','[]','朝行良常南，暮息良常北。',144,'全唐诗/poet.song.236000.json','["朝行良常南，暮息良常北。", "山水互縈紆，松篁相依綠。", "尚擬效古人，夜遊迭秉燭。", "嗟我獨何爲，紅塵走車軸。", "有如嗜飲者，性命寄芳醁。", "時於茅檐下，支頤望浮玉。", "或夢泊西巖，汲湘然楚竹。", "終然纏世故，欲往竟未卜。", "安得乘天風，翩翩出囂俗。", "士生一世間，衣食貴裁足。", "誰爲翔蒿鷃，誰爲沖霄鵠。", "誓將與子游，保此受命獨。"]'),
('9feaa84a-e2c8-4ccd-847b-2e075eefe71a','次韻龍仁夫種菊二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','憂來感人心，把菊行東籬。',120,'全唐诗/poet.song.236000.json','["憂來感人心，把菊行東籬。", "悠然南山句，憶此刪後詩。", "詩亡絕遺響，菊在餘幽姿。", "麟洲有達士，與菊心相期。", "左揖隆中老，右揖綿上推。", "汎此忘憂物，聊以供吾私。", "真樂未易識，勝事空自知。", "金風摵摵鳴，金英粲粲垂。", "我欲從子醉，不羨高陽池。", "焉知義熙後，此會非今時。"]'),
('f2ae8850-57f5-4f09-8851-062dbc472ac0','次韻龍仁夫種菊二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','種菊東籬下，菊密荒疎籬。',120,'全唐诗/poet.song.236000.json','["種菊東籬下，菊密荒疎籬。", "掇英浥墜露，想像淵明詩。", "猗嗟子龍子，磊落山林姿。", "欽翹二三客，異郡同襟期。", "而我何爲者，俛首供丁推。", "寧復飲我酒，歡飫均嬿私。", "乃知意氣合，豈計新相知。", "蹇予久衰曳，素髮颯已垂。", "何能借九翮，一朝奮天池。", "但當對菊飲，與君賡醉時。"]'),
('5f02eace-6904-406f-a7cb-08474d4cfd9d','題白廷玉所藏白馬圖','俞德鄰','宋','宋诗','song-poetry','','[]','八尺龍駒蹄削玉，霜毛雪鬣超凡俗。',96,'全唐诗/poet.song.236000.json','["八尺龍駒蹄削玉，霜毛雪鬣超凡俗。", "驕嘶顧影食場苗，朝暮逍遥在空谷。", "詔書歘下徵騏驎，香街紫陌驚行人。", "金環壓轡出天廄，不數駓駱驪騮駰。", "三品豆芻飽終日，終日不鳴鳴輒黜。", "何如不縶亦不維，騰霧籋雲全玉質。"]'),
('22067c6c-56ab-4d5d-a183-e13ad52e952d','次韻陳彥實醉中雜言','俞德鄰','宋','宋诗','song-poetry','','[]','悠悠廣陌塵，冉冉征途客。',108,'全唐诗/poet.song.236000.json','["悠悠廣陌塵，冉冉征途客。", "征途渺無際，人壽不滿百。", "百年復幾何，鬢髮早已白。", "髮白無由玄，擾擾終奚益。", "富貴勢熏天，忽作冷灰寂。", "突兀樹豐碑，猶有金石厄。", "所以賢達人，萬古等朝夕。", "俯仰宇宙間，但恨酒杯窄。", "持杯輒酣歌，那暇寸陰惜。"]'),
('9d63211a-ce35-444c-91bf-3ef1a30f8762','水墨蘭','俞德鄰','宋','宋诗','song-poetry','','[]','三閭一朝蛻，九畹千載荒。',60,'全唐诗/poet.song.236000.json','["三閭一朝蛻，九畹千載荒。", "茫茫天壤內，春在桃李場。", "幽蘭有貞質，轉泛欺衆芳。", "寧受緇塵染，尚餘風露香。", "乃知德勝色，不采庸何傷。"]'),
('b6985353-5790-4d26-a68f-ee561e8c0288','病中謝親友四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','昔年居窮巷，門多長者轍。',72,'全唐诗/poet.song.236000.json','["昔年居窮巷，門多長者轍。", "一病逾十旬，意可雀羅設。", "往來問死生，多謝跡不絕。", "販夫逢僕隸，慰問猶切切。", "嗟我何人斯，才薄德又劣。", "何以報諸公，寸心常激烈。"]'),
('ab26ce1d-b1ba-4209-b2d6-7c79904d2e90','病中謝親友四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','生平性嗜客，病不廢應酬。',72,'全唐诗/poet.song.236000.json','["生平性嗜客，病不廢應酬。", "終然瘦骨立，欲語氣不收。", "客多語嘈雜，兩耳鳴啾啾。", "登牀就偃息，客語或未休。", "客意豈不佳，而我自作憂。", "奈何坐客去，牀下多鬭牛。"]'),
('b0bf803d-ad38-4ec6-883b-55f2056476eb','病中謝親友四首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','病骨瘦崚嶒，僵卧難帖席。',72,'全唐诗/poet.song.236000.json','["病骨瘦崚嶒，僵卧難帖席。", "一夕三四遷，起坐長太息。", "大患緣有身，無身更何疾。", "從今事委蛻，夢覺非所擇。", "須臾忽蘧然，又到華胥國。", "何處發晨鐘，耿耿霜月白。"]'),
('0de6f529-6d76-4660-84f7-67392ab32876','病中謝親友四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','一病連三月，肥甘寧得知。',84,'全唐诗/poet.song.236000.json','["一病連三月，肥甘寧得知。", "醫復戒食鹽，鹽食非所宜。", "素餐幸無刺，餐素將何疑。", "因思喪亂際，黎民多阻饑。", "朝餐乃木葉，暮食乃樹皮。", "我今食無鹽，早晚白玉炊。", "稽首謝蒼天，揆分忱過之。"]'),
('317928f7-3962-42ba-9a4d-e8e68665cfb9','金山寺','俞德鄰','宋','宋诗','song-poetry','','[]','僧舍高低見，潮音曉夜聞。',48,'全唐诗/poet.song.236000.json','["僧舍高低見，潮音曉夜聞。", "仙凡一水隔，淮浙半江分。", "鶻冷山腰月，龍噓海角雲。", "瞿曇端不動，人世幾紛紛。"]'),
('4c05bcbf-d8b0-4d81-abb9-d703eba3608f','曲肱','俞德鄰','宋','宋诗','song-poetry','','[]','門掩青苔硯掩塵，曲肱隠几自觀身。',64,'全唐诗/poet.song.236000.json','["門掩青苔硯掩塵，曲肱隠几自觀身。", "已憐白髮無公道，獨喜清風似故人。", "躍馬卧龍俱寂寞，盟鷗狎鷺莫逡巡。", "東屯澗水通畦稻，植杖看耘意更真。"]'),
('b1feb985-787a-4c6d-bd8b-1b30e0dfc55f','舟過桐廬作','俞德鄰','宋','宋诗','song-poetry','','[]','三年常作客，幾度溯前川。',48,'全唐诗/poet.song.236000.json','["三年常作客，幾度溯前川。", "山合疑無路，谿回別有天。", "虹分遥電雨，風裊近虛烟。", "歸路知多少，啼鵑雲樹邊。"]'),
('d1b2b099-1d3f-4e0b-a5e4-6dca3c7e48c6','陳索郎灘','俞德鄰','宋','宋诗','song-poetry','','[]','去國踰千里，辭家過十程。',48,'全唐诗/poet.song.236000.json','["去國踰千里，辭家過十程。", "飯炊雲子白，酒醉索郎清。", "柂捩秋江駛，帆開暮靄輕。", "聖明方在御，何地不升平。"]'),
('e8ffd379-ce48-46f0-83ee-7068ae4f59f6','行壽昌道中','俞德鄰','宋','宋诗','song-poetry','','[]','山邑少桑麻，清谿卷素沙。',48,'全唐诗/poet.song.236000.json','["山邑少桑麻，清谿卷素沙。", "岸崩橋半斷，村僻路三叉。", "廢渡留芳草，深溝卧古槎。", "老翁苔石坐，猶自問京華。"]'),
('6188f6eb-9f8f-4fde-8c3b-2e5f6d1cb380','庚午讀邸報','俞德鄰','宋','宋诗','song-poetry','','[]','西北干戈猝未闌，蒼生誰與破愁顔。',64,'全唐诗/poet.song.236000.json','["西北干戈猝未闌，蒼生誰與破愁顔。", "甫聞高議雲臺上，又見投身瘴海間。", "天地十年氛霧暗，江湖萬里鬢毛斑。", "欲尋酩酊判豪飲，郊外旗亭半掩關。"]'),
('03a768fd-dfac-458d-8690-25f2fe69dfaf','聞築鹿門','俞德鄰','宋','宋诗','song-poetry','','[]','干戈又繞鹿門西，清夢猶應憶鼓鼙。',64,'全唐诗/poet.song.236000.json','["干戈又繞鹿門西，清夢猶應憶鼓鼙。", "可歎遭逢誇二鳥，却令經濟屬三犀。", "腐儒闇事惟蒿目，聖哲知幾莫噬臍。", "坱莽氛埃何日浄，春江飛雨漲芹泥。"]'),
('0967951d-db8c-4a1d-b35a-ad161ad19147','金陵板橋別弟','俞德鄰','宋','宋诗','song-poetry','','[]','江郊憶舊廬，送爾復躊躇。',48,'全唐诗/poet.song.236000.json','["江郊憶舊廬，送爾復躊躇。", "別慣不形夢，情多懶寄書。", "江湖歸棹遠，風雨夜牀疎。", "杯酒慈顔悅，離愁頼掃除。"]'),
('0fbf9d32-a095-4ac2-bebe-98c87e0aca8d','古寺','俞德鄰','宋','宋诗','song-poetry','','[]','古寺接荒城，浮圖倚太清。',48,'全唐诗/poet.song.236000.json','["古寺接荒城，浮圖倚太清。", "松環嵐翠蔚，泉激澗虹明。", "僧定花開落，人行鳥送迎。", "西枝如可卜，吾欲證無生。"]'),
('1881991b-ee98-40d4-966b-bc324697a343','秋日客中','俞德鄰','宋','宋诗','song-poetry','','[]','楓落秋江塞鴈賓，客懷依舊憶鱸蓴。',64,'全唐诗/poet.song.236000.json','["楓落秋江塞鴈賓，客懷依舊憶鱸蓴。", "百年三萬六千日，半世東西南北人。", "滿目空村爭虎豹，何時高閣繪麒麟。", "由來管葛皆天意，霄漢泥塗任此身。"]'),
('018a7fdc-201f-42d4-82a9-61fa0c9998fd','書齋','俞德鄰','宋','宋诗','song-poetry','','[]','寂寂書齋萬慮空，恍然赤甲古城東。',64,'全唐诗/poet.song.236000.json','["寂寂書齋萬慮空，恍然赤甲古城東。", "鳥呼幽夢日方午，花惱醉吟春正中。", "軍將送茶驚諫議，門生載酒過揚雄。", "能詩識字皆爲累，閒殺江頭獨釣翁。"]'),
('d363d1e2-fcf1-425a-a031-dd6b39cc5878','贈靜齋趙使君淮','俞德鄰','宋','宋诗','song-poetry','','[]','兩翁今古妙經綸，續續家聲屬後昆。',64,'全唐诗/poet.song.236000.json','["兩翁今古妙經綸，續續家聲屬後昆。", "黑髮珥貂依日月，金羈絡馬半乾坤。", "千年带礪河山在，一脈詩書禮樂存。", "我本信菴門下士，祇今彈鋏向誰門。"]'),
('c827477d-6fe6-4333-bc6a-5b2b7cf99182','常山道中','俞德鄰','宋','宋诗','song-poetry','','[]','縣古浮梁外，沙平草樹秋。',48,'全唐诗/poet.song.236000.json','["縣古浮梁外，沙平草樹秋。", "遠山明去鷺，驟雨咽鳴鳩。", "岸狹水痕漲，雲歸暝色愁。", "誰憐蘇季子，塵土涴貂裘。"]'),
('09c2f8a0-5d50-47e6-99a6-66f3ae8c4ae9','鷺鷥林','俞德鄰','宋','宋诗','song-poetry','','[]','客久倦嶔崟，尋幽洗客襟。',48,'全唐诗/poet.song.236000.json','["客久倦嶔崟，尋幽洗客襟。", "青煙楊柳岸，白酒鷺鷥林。", "當戶孤峯秀，環溪萬玉陰。", "留連不忍別，月澹砌蛩吟。"]'),
('bfd728b5-85a2-47db-8220-2e507be523f1','白兔山菴','俞德鄰','宋','宋诗','song-poetry','','[]','清江田舍已悠悠，謾結茅茨傍小丘。',64,'全唐诗/poet.song.236000.json','["清江田舍已悠悠，謾結茅茨傍小丘。", "月冷雪窗迷扑握，山連煙草叫軥輈。", "了知世事同槐蟻，何有機心到海鷗。", "却笑東坡老居士，一生隨處賈胡留。"]'),
('a374243c-438e-4f5f-b580-46be03f2dbd6','次韻朱子厚九月十一日見寄三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','三載干戈隔勝遊，江山依舊鬰相繆。',64,'全唐诗/poet.song.236000.json','["三載干戈隔勝遊，江山依舊鬰相繆。", "蛩吟砌壁莓苔古，鴈落汀沙草木秋。", "畫角飄江猶北固，白雲飛岫認東甌。", "凭高望遠心如醉，風岸烏巾雪滿頭。"]'),
('f3c18ff5-1537-4abc-8c4a-320cbd470246','次韻朱子厚九月十一日見寄三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','凄凉風雨暗山薇，夢裏歸與迄未歸。',64,'全唐诗/poet.song.236000.json','["凄凉風雨暗山薇，夢裏歸與迄未歸。", "禮樂不存三代遠，江山如故六朝非。", "讀書老去翻成癖，煮字從來不救饑。", "短褐長鑱真活計，載芟何日詠春祈。"]'),
('74c1c3f3-0340-440b-bc7b-11fa110057cf','次韻朱子厚九月十一日見寄三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','冷雨凄風萬木飛，年來世事不勝悲。',64,'全唐诗/poet.song.236000.json','["冷雨凄風萬木飛，年來世事不勝悲。", "青山白水新安道，雲夢綠林夔府詩。", "耆舊飄零今有幾，乾坤翻覆政緣誰。", "鬢絲一夜三千丈，甚矣吾衰如此衰。"]'),
('ab128ed3-34bd-4d34-a6c8-2d6f2a1c7587','登六和塔','俞德鄰','宋','宋诗','song-poetry','','[]','僧舍倚松北，浮圖界竹西。',48,'全唐诗/poet.song.236000.json','["僧舍倚松北，浮圖界竹西。", "江通嚴瀨遠，雲壓越山低。", "槐里三原隔，襄城七聖迷。", "臨風悲往事，月落凍烏啼。"]'),
('c67d3ce6-96c2-4979-8f34-81875b66a3ab','客中別友','俞德鄰','宋','宋诗','song-poetry','','[]','語別莫怱怱，情懷彼此同。',48,'全唐诗/poet.song.236000.json','["語別莫怱怱，情懷彼此同。", "山川秋色裏，風雨客愁中。", "故國俱離黍，勞生共轉蓬。", "鼓鼙聲一概，何處是遼東。"]'),
('25a0389f-e589-4fa5-9327-addd83f4e97a','次韻簡黄監簿淳宗三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','流年暗數手中蓍，短髮鬖髿每自悲。',64,'全唐诗/poet.song.236000.json','["流年暗數手中蓍，短髮鬖髿每自悲。", "金甲牙旗非昨夢，黄虀白米慰朝饑。", "山河萬里歸新主，湖海三年隔故知。", "惟有浣花堂上燕，春來依舊不相遺。"]'),
('602c8d22-c363-44f1-b085-dfd071a26a41','次韻簡黄監簿淳宗三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','桂樹團團滿故山，一尊風月羨君閒。',64,'全唐诗/poet.song.236000.json','["桂樹團團滿故山，一尊風月羨君閒。", "交遊副墨洛誦裏，詩句生民清廟間。", "我輩無才難用世，故人厚祿竟何顔。", "西樓十二闌干月，清夢應須共往還。"]'),
('79f2a409-58e6-4bd6-bbee-c96b7506a22b','次韻簡黄監簿淳宗三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','化鶴遼東老令威，舊家華表未能歸。',64,'全唐诗/poet.song.236000.json','["化鶴遼東老令威，舊家華表未能歸。", "三千里客貢禹恨，四十九年蘧瑗非。", "事與心違多感慨，人隨世易重歔欷。", "黄華老盡秋容淡，何日西山薄采薇。"]'),
('ede8cc96-7701-4a66-b29a-7ff7083c073f','次韻碧窗聶道錄','俞德鄰','宋','宋诗','song-poetry','','[]','胸蟠今古袖披披，老作黄冠恐未宜。',64,'全唐诗/poet.song.236000.json','["胸蟠今古袖披披，老作黄冠恐未宜。", "遼鶴不歸人已換，濠魚自樂子焉知。", "瓠留西域青精飯，杖削東川紫玉皮。", "我似淵明君陸靜，相看一笑儼前時。"]'),
('a62be398-4a79-474d-a7cc-4952ae944029','雪','俞德鄰','宋','宋诗','song-poetry','','[]','卧聽窗外撲春蟲，逗曉緌緌攪太空。',64,'全唐诗/poet.song.236000.json','["卧聽窗外撲春蟲，逗曉緌緌攪太空。", "萬逕千山孤鳥絕，八荒四海一雲同。", "寒聲靜起瀌浮外，生意深藏肅殺中。", "乘興俓思游剡曲，狼烽明滅又天東。"]'),
('60888b8b-0531-4fde-afea-cf8dec65f4e8','哭涂移愚教授','俞德鄰','宋','宋诗','song-poetry','','[]','北固登山屐，西園載酒船。',48,'全唐诗/poet.song.236000.json','["北固登山屐，西園載酒船。", "論心今一世，握手後千年。", "湖海風波惡，乾坤雨露偏。", "無因見宿草，流淚漲黄泉。"]'),
('9d6a4e40-04b0-4bc4-a13d-96b13efe57fb','春日苦雨二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','礮車雲起走豐隆，河伯重驅十二童。',64,'全唐诗/poet.song.236000.json','["礮車雲起走豐隆，河伯重驅十二童。", "山竅號風雷破柱，海門翻浪雨飛空。", "一春狂犬吠日出，三月老農愁歲終。", "斗米換衾寧計直，却疑家近漏天東。"]'),
('5e8665c7-3f71-4989-b7a0-14f3dc4e9ed8','春日苦雨二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','日日盲風怪雨間，百花顦顇委蓁菅。',64,'全唐诗/poet.song.236000.json','["日日盲風怪雨間，百花顦顇委蓁菅。", "鮫人停杼疑翻海，河伯移宮欲近山。", "裹飯有誰來問病，挑燈老我獨愁顔。", "九疇何日重浮洛，川鎖支祁鼎鑄姦。"]'),
('2eec56f6-d0cd-4d14-9437-bf1c6cd2dd1e','金壇邑中作','俞德鄰','宋','宋诗','song-poetry','','[]','菰蒲風起雨濛𩆓，萬室參差浸碧瀾。',64,'全唐诗/poet.song.236000.json','["菰蒲風起雨濛𩆓，萬室參差浸碧瀾。", "一鶴歸來城郭改，二龍飛去洛波寒。", "松迷舊逕猶存寺，蛙聒新畬總爲官。", "却喜故家文獻在，半從鞍馬半儒冠。"]'),
('63270d55-9608-4002-a832-99f6ac46e149','次韻陳登父桃花','俞德鄰','宋','宋诗','song-poetry','','[]','臺隸羣芳散綺葩，繁枝密幹蔚交加。',64,'全唐诗/poet.song.236000.json','["臺隸羣芳散綺葩，繁枝密幹蔚交加。", "武陵溪畔秦人洞，濯錦江頭杜老家。", "風攪亂紅春過雨，露滋微艷曉籠霞。", "長安重到應惆悵，寂寞玄都燕麥斜。"]'),
('945dc7d7-dd37-4020-8f9b-e051e64850ca','贈蔣文學三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','車聲馬跡任營營，蘆溆襄羊境最清。',64,'全唐诗/poet.song.236000.json','["車聲馬跡任營營，蘆溆襄羊境最清。", "萬卷圖書雙鬢老，五湖煙浪一舟輕。", "忘機已信馴鷗狎，洗耳那愁鬭蟻驚。", "更喜甌窶秧水足，倚風扶杖看春耕。"]'),
('02b612f1-6104-4741-ba2a-12df2960a3ec','贈蔣文學三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','龐眉鶴髮一詩翁，肯伴漁夫理釣筒。',64,'全唐诗/poet.song.236000.json','["龐眉鶴髮一詩翁，肯伴漁夫理釣筒。", "蘆溆柳塘新漲外，竹籬茅舍晚烟中。", "鄉書再捧衣猶白，村酒頻沽頰借紅。", "萬事無言歸一笑，仲車元不是真聾。"]'),
('aacf3ba9-cabc-4b64-b908-ca20799e7878','贈蔣文學三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','憶昔携書衮繡堂，扁舟曾此濯滄浪。',64,'全唐诗/poet.song.236000.json','["憶昔携書衮繡堂，扁舟曾此濯滄浪。", "蒼龍飛去未成雨，老鶴重來知幾霜。", "人物半凋嗟世事，典刑猶在得詩章。", "何當去卜西枝隠，同汎漁舟夜擊榔。"]'),
('cf44fd01-3b96-47da-8102-3134e8e50f2c','記夢','俞德鄰','宋','宋诗','song-poetry','','[]','雲封槐里黯平蕪，無復魚燈照玉鳬。',64,'全唐诗/poet.song.236000.json','["雲封槐里黯平蕪，無復魚燈照玉鳬。", "樂奏馬驚猶奮鬣，鼎成龍去莫攀胡。", "老歸燕國常悲隴，夢斷滎河偶得圖。", "淳景布衣今白髮，西風搔首獨踟躕。"]'),
('b19a4c5d-fc11-4d4b-b4c0-450581ee4a39','午睡','俞德鄰','宋','宋诗','song-poetry','','[]','赤米黄虀雪白鹽，圖書滿架絕韜鈐。',64,'全唐诗/poet.song.236000.json','["赤米黄虀雪白鹽，圖書滿架絕韜鈐。", "百年無補孔融愧，三葉不遭顔賜潛。", "去住任如巢幕燕，間關誰學上竿鮎。", "幽居暇日知何事，一半清談半黑甜。"]'),
('62f62df2-b72d-42cc-9d0f-665bf903cfd3','泛湖','俞德鄰','宋','宋诗','song-poetry','','[]','閒居散人事，一舸泛長湖。',48,'全唐诗/poet.song.236000.json','["閒居散人事，一舸泛長湖。", "夜雨半篙荇，春風十幅蒲。", "功名槐國夢，身世輞川圖。", "艤岸逢林叟，清談日又晡。"]'),
('abcee85a-05bc-4d77-8428-1f18b8af9e0e','金壇郊外','俞德鄰','宋','宋诗','song-poetry','','[]','散屧過平堤，前村雨一犁。',48,'全唐诗/poet.song.236000.json','["散屧過平堤，前村雨一犁。", "草荒翁仲立，樹密鷓鴣啼。", "野色連天遠，溪光隔岸迷。", "干戈猶未息，何處足幽棲。"]'),
('664b2478-b7c0-4782-b3eb-062b4e24cb83','八月十五夜','俞德鄰','宋','宋诗','song-poetry','','[]','捲盡頑雲玉漏中，月華如水浸層空。',64,'全唐诗/poet.song.236000.json','["捲盡頑雲玉漏中，月華如水浸層空。", "一輪圓缺常時見，萬里陰晴此夜同。", "突兀樓臺猶昔日，高低禾黍自秋風。", "轉蓬地遠歸心折，尚想霓裳舞舊宮。"]'),
('364090cd-e9ba-4f34-9084-68148f90c21a','觀潮','俞德鄰','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','彊弩驅潮水爲東，昔年此地識英雄。',64,'全唐诗/poet.song.236000.json','["彊弩驅潮水爲東，昔年此地識英雄。", "素車白馬空明上，青蓋紅旗滅沒中。", "十萬軍聲西塞月，三千鯤浪北溟風。", "乘槎有約終須去，見說銀潢與海通。"]'),
('c9223943-dc0c-4b56-a873-9e9a6d771f6a','古琴一張徽絃不具持贈劉漢卿經歷因賦','俞德鄰','宋','宋诗','song-poetry','','[]','枯桐三尺蹙龍紋，爨下薪焦偶未焚。',64,'全唐诗/poet.song.236000.json','["枯桐三尺蹙龍紋，爨下薪焦偶未焚。", "七竅已開猶渾沌，一絲不掛絕聲聞。", "至音澹薄何如默，大道希夷豈在文。", "持贈要知絃外趣，美哉斯意憶河汾。"]'),
('44f344f6-5dc9-46c1-9b82-c11fb1db2310','閒居即事','俞德鄰','宋','宋诗','song-poetry','','[]','塵外江村野老家，窮年兀兀笑盤蝸。',64,'全唐诗/poet.song.236000.json','["塵外江村野老家，窮年兀兀笑盤蝸。", "素琴橫膝一尊酒，紗帽籠頭七椀茶。", "編竹作橋看蟻渡，種花成塢聽蜂衙。", "閒中自有經綸事，寄語時人莫笑譁。"]'),
('e871fea3-2b4c-4d1b-9dbb-7a1f6f3c7ba8','次韻陳登父小樓述懷','俞德鄰','宋','宋诗','song-poetry','','[]','慷慨悲歌續五噫，等閒觀物倚筇枝。',64,'全唐诗/poet.song.236000.json','["慷慨悲歌續五噫，等閒觀物倚筇枝。", "士龍瓦屋西頭住，吏部霜螯左手持。", "湖海悠悠空拓落，風埃冉冉竟衰遲。", "登樓作賦羞王粲，寂寞歸與理釣絲。"]'),
('f3f81e7e-2925-4b8b-b92b-4f94e873f9a5','通津田舍','俞德鄰','宋','宋诗','song-poetry','','[]','汀葭江菼兩依依，鷗鷺相親寂不飛。',64,'全唐诗/poet.song.236000.json','["汀葭江菼兩依依，鷗鷺相親寂不飛。", "僧入翠微雲伴去，牛耕白水犢隨歸。", "古今賢聖多蕭索，王伯干戈有是非。", "老病憂時心力弱，可能此地得漁磯。"]'),
('c08061d0-5540-411c-9f71-caf3c9a60454','游鶴林寺','俞德鄰','宋','宋诗','song-poetry','','[]','步屧叩禪扉，春山碧四圍。',48,'全唐诗/poet.song.236000.json','["步屧叩禪扉，春山碧四圍。", "天高黄鶴遠，仙去杜鵑非。", "拂石雲生袖，捫松霧濕衣。", "幾生通佛性，一昔遂忘歸。"]'),
('f04d5931-eff0-4eed-b927-e22893f58266','客懷','俞德鄰','宋','宋诗','song-poetry','','[]','客懷元自惡，歸思浩無垠。',48,'全唐诗/poet.song.236000.json','["客懷元自惡，歸思浩無垠。", "愁織窗前草，情凄岸曲蘋。", "十年紛戰伐，四海暗風塵。", "故舊無消息，西風淚滿巾。"]'),
('73f4ee10-f305-4a08-a653-4b25fde172ca','夜坐','俞德鄰','宋','宋诗','song-poetry','','[]','蒲團疊膝誦南華，蓮勺燈明細吐花。',64,'全唐诗/poet.song.236000.json','["蒲團疊膝誦南華，蓮勺燈明細吐花。", "客有可人期不至，鄰無美酒夜難賒。", "濕星釀雨愁飛鴈，枯木號風怨宿鴉。", "自笑不眠還不倦，城頭嗚咽又鳴笳。"]'),
('ab0a6422-bf4c-43b0-8dba-4a001b53e275','次韻陳登父送春有感','俞德鄰','宋','宋诗','song-poetry','','[]','同谷歌殘返舊蹊，園廬寂寞半蒿藜。',64,'全唐诗/poet.song.236000.json','["同谷歌殘返舊蹊，園廬寂寞半蒿藜。", "憂時頓覺愁如海，對客何能醉似泥。", "春去春來人漸老，城南城北望猶迷。", "鼓鼙一概旌旗滿，何日車書混僰鞮。"]'),
('6e6f065b-9a2e-4660-8918-d3520efe53de','臂疾示兒','俞德鄰','宋','宋诗','song-poetry','','[]','臂疾浸淫骨半枯，蒲團毯被學跏趺。',64,'全唐诗/poet.song.236000.json','["臂疾浸淫骨半枯，蒲團毯被學跏趺。", "宋清藥券償未了，司業酒錢來便無。", "湖海飄零銷壯志，風霜荏苒上吟鬚。", "征遼挾矢知無分，老向新豐倩汝扶。"]'),
('7c5fdeeb-b996-48f8-8459-31de5ab2cf71','閒居遣興','俞德鄰','宋','宋诗','song-poetry','','[]','數間破屋玉川家，紗帽籠頭自煮茶。',64,'全唐诗/poet.song.236000.json','["數間破屋玉川家，紗帽籠頭自煮茶。", "萬卷圖書三尺劍，半窗風雨一池蛙。", "詩情寂寞腹無稿，老態浸尋眼有花。", "鼎鼎百年成底事，醉鄉端的是生涯。"]'),
('f327cbe5-84b3-41e0-a8b8-becf526ed596','次陳登父中秋遊古竹院韻','俞德鄰','宋','宋诗','song-poetry','','[]','閒過竹院聽華嚴，結願清香發舊奩。',64,'全唐诗/poet.song.236000.json','["閒過竹院聽華嚴，結願清香發舊奩。", "灝氣半空浮桂魄，凉風三徑拂松髯。", "酒闌野興歸長笛，吟罷秋聲落短簷。", "終日昏昏真醉夢，幾時游屐更苔黏。"]'),
('e51bf0e2-12b1-42da-9489-9f39a3b6048c','秋殘','俞德鄰','宋','宋诗','song-poetry','','[]','樂天老矣放樊蠻，鷗羨忘機鶴羨閒。',64,'全唐诗/poet.song.236000.json','["樂天老矣放樊蠻，鷗羨忘機鶴羨閒。", "緩步當車休下澤，澆愁得酒即中山。", "些騷豈敢奴僕命，伊呂元非伯仲間。", "兀兀支頤秋又晚，亂雲斜日澹煙鬟。"]'),
('9f3da7d1-a09f-45ad-a1e4-4c41a4d6adbd','養拙','俞德鄰','宋','宋诗','song-poetry','','[]','養拙柴扉百慮疎，天光雲影亂秋渠。',64,'全唐诗/poet.song.236000.json','["養拙柴扉百慮疎，天光雲影亂秋渠。", "一身摇動未妨酒，兩眼眵昏猶嗜書。", "陶令但知歸有菊，馮諼忍歎食無魚。", "閒中滋味君休厭，門外紛紛幾覆車。"]'),
('2363e5c5-0a6d-462d-8912-f89afb4230db','無題二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','杯酒河橋餞去篷，誰知此別竟西東。',64,'全唐诗/poet.song.236000.json','["杯酒河橋餞去篷，誰知此別竟西東。", "隙駒冉冉歲華改，樓燕飛飛春事空。", "珮冷江臯凄落月，笳吹朔漠動悲風。", "芳魂寂寞揚州路，后土瓊姬恨畧同。"]'),
('036ed2e8-41b6-4803-a4da-8be1ba5bd154','無題二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','花柳亭臺半劫灰，故人淪落共徘徊。',64,'全唐诗/poet.song.236000.json','["花柳亭臺半劫灰，故人淪落共徘徊。", "湖光山色西施舸，水影月香和靖梅。", "鴻蹋雪泥猶記跡，鶴歸華表總成哀。", "一尊濁酒和愁酌，淚灑東風醉玉頹。"]'),
('34748c63-9284-4c0b-893c-4448772ffb9b','正月十日理髮三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','多病多愁鬢已星，更憐詩骨瘦崚嶒。',64,'全唐诗/poet.song.236000.json','["多病多愁鬢已星，更憐詩骨瘦崚嶒。", "百錢挑杖但求醉，五斗折腰良不能。", "徒步幸無官長駡，浩歌聊襲散人稱。", "世情閲盡忘今古，一合乾坤幾廢興。"]'),
('d4fb57c9-130e-4f10-9ac0-c930ac921847','正月十日理髮三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','寂歷勞生歎轉蓬，百年强半走西東。',64,'全唐诗/poet.song.236000.json','["寂歷勞生歎轉蓬，百年强半走西東。", "從師謾學屠龍技，報國元無汗馬功。", "二頃有秋生計足，三杯近卯客愁空。", "兒童相見從相笑，兩鬢絲絲一老翁。"]'),
('cf61c77f-ee0a-4275-a09e-0f342be3dd40','正月十日理髮三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','晨梳白髮照青銅，歎息光陰過眼空。',64,'全唐诗/poet.song.236000.json','["晨梳白髮照青銅，歎息光陰過眼空。", "一市少年羞袴下，三朝新婦閉車中。", "酒逢知己猶堪醉，文不驚人莫送窮。", "天下士憂天下事，肯將飛伏較雌雄。"]'),
('c64ad4f4-7b91-4088-8166-baa1e56ae649','送王舍人之燕山','俞德鄰','宋','宋诗','song-poetry','','[]','柳媚花明二月天，金羈絡馬路三千。',64,'全唐诗/poet.song.236000.json','["柳媚花明二月天，金羈絡馬路三千。", "鱣鯨得意縱溟壑，蛙蚓無知閙坎泉。", "今古不磨惟正理，是非何必待他年。", "離騷已信多忠憤，珍重毋忘鴇羽篇。"]'),
('2e28e5ef-0fd1-449a-9678-1804f6c4a0a9','游宣慰載酒泛溪即席有作','俞德鄰','宋','宋诗','song-poetry','','[]','五載綈袍憶故人，春風吹鶴過湖濱。',64,'全唐诗/poet.song.236000.json','["五載綈袍憶故人，春風吹鶴過湖濱。", "樓臺冷浸兩溪水，天地清無一點塵。", "棹底空觥今杜牧，井中投轄舊陳遵。", "萬方一概吾安往，儻許誅茅竟卜鄰。"]'),
('e2ef6cf0-7164-4f53-80a4-6811b0ee9575','陪游宣慰游霅歸賦','俞德鄰','宋','宋诗','song-poetry','','[]','隃望平山碧四圍，鵓鴣啼處見柴扉。',64,'全唐诗/poet.song.236000.json','["隃望平山碧四圍，鵓鴣啼處見柴扉。", "白蘋風起雨初歇，綠葉成陰春又歸。", "野外樵夫紛避道，溪邊鷗鳥獨忘機。", "深杯百罰人扶醉，一枕西軒月滿衣。"]'),
('a700864d-2f5a-4237-ac0f-ae028b32c34c','次韻簡林紹先諸友三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','宦路風波渺望洋，幾人赤馬旦蒙霜。',64,'全唐诗/poet.song.236000.json','["宦路風波渺望洋，幾人赤馬旦蒙霜。", "便便懶是誇經笥，嗑嗑從渠笑酒囊。", "花柳春風朝步屧，菰蒲春水夜鳴榔。", "人間別有桃源路，肯爲浮榮替戾岡。"]'),
('b19a259f-0c5a-4b93-a361-73a23f8c0033','次韻簡林紹先諸友三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','納納乾坤萬彙滋，同聲同氣自相宜。',64,'全唐诗/poet.song.236000.json','["納納乾坤萬彙滋，同聲同氣自相宜。", "江山今古幾興廢，湖海交朋屢別離。", "落月照梁疑太白，西風揮扇障元規。", "老來萬事如泥濁，一笑論文祇自知。"]'),
('c4012a3a-ea95-47f1-b0cf-6b2e2df9ae5b','次韻簡林紹先諸友三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','載酒湖山憶盛年，可憐風物竟凄然。',64,'全唐诗/poet.song.236000.json','["載酒湖山憶盛年，可憐風物竟凄然。", "杜陵野老哭春日，空谷佳人倚暮天。", "禾黍離離迷故國，旌旗杳杳徧南偏。", "虎皮何日包弓矢，老爲羲皇受一廛。"]'),
('2e7edfcd-9fc6-46e8-bc42-7582682d1424','客窗夜雨','俞德鄰','宋','宋诗','song-poetry','','[]','世路驅馳力不任，老來世路轉嶇嶔。',64,'全唐诗/poet.song.236000.json','["世路驅馳力不任，老來世路轉嶇嶔。", "小窗一夜芭蕉雨，倦客十年桑梓心。", "黄紙紅旗違壯志，青尊綠醑笑孤斟。", "故山何日真歸隠，磵水松風直萬金。"]'),
('d2e18eaf-cfb3-45cc-8615-3769dea7fe84','息寮王教授輓詞二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','黄鶴山前蛻骨仙，飽餐玉蕊潄珠泉。',64,'全唐诗/poet.song.236000.json','["黄鶴山前蛻骨仙，飽餐玉蕊潄珠泉。", "酒酣拓戟老工部，官冷無氈貧鄭虔。", "四海風埃方坱莽，一生岐路幾迍邅。", "公今得向揚州死，况復懸車過八年。"]'),
('b4f1e8f5-cbdd-461e-a86e-1aeb8a44d4ca','息寮王教授輓詞二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','昔年牀下拜龐公，數樹梅花一畝宮。',64,'全唐诗/poet.song.236000.json','["昔年牀下拜龐公，數樹梅花一畝宮。", "寂寞吟情頭盡鶴，摧頹病骨氣如虹。", "祇今有子能傳業，誰念無錢解送終。", "千古幽扃鄰牧惰，遥憐環珮月明中。"]'),
('c3d067aa-89ba-419a-8f43-a0890c32004a','梅雨','俞德鄰','宋','宋诗','song-poetry','','[]','宇宙冥冥四月時，小齋吟眺苦低垂。',64,'全唐诗/poet.song.236000.json','["宇宙冥冥四月時，小齋吟眺苦低垂。", "江城地僻莓苔老，山徑雲深草木滋。", "密霧蒙蒙籠翠幄，輕煙冉冉散青絲。", "楚宮幽珮勞魂夢，西望巫陽祇自悲。"]'),
('7fdf2189-904b-43af-8db7-57fbaf6bd6f7','老病','俞德鄰','宋','宋诗','song-poetry','','[]','老病幽棲覺懶吟，眼觀時態獨關心。',64,'全唐诗/poet.song.236000.json','["老病幽棲覺懶吟，眼觀時態獨關心。", "古今不冺春秋筆，天地難欺暮夜金。", "幸有別腸堪貯酒，未愁短髮不勝簪。", "柴門一閉從春盡，桃李飛花葉又陰。"]'),
('56535081-a0cd-4fcf-9bd8-9f37c8b9ec33','遣懷','俞德鄰','宋','宋诗','song-poetry','','[]','擾擾乾坤幾戰塵，南山北闕意逡巡。',64,'全唐诗/poet.song.236000.json','["擾擾乾坤幾戰塵，南山北闕意逡巡。", "貧思隠語呼庚癸，病怯流年避巳辰。", "三顧恐無開濟術，百年須了去來因。", "鹿門有約吾將隠，倚杖看雲老此身。"]'),
('c882bed8-3b55-4471-9b9d-2eda388ee889','送劉伯宣尹松江府五首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','來往燕鴻異，逍遥鵬鷃同。',48,'全唐诗/poet.song.236000.json','["來往燕鴻異，逍遥鵬鷃同。", "古交千載上，餘論六經中。", "瓜渚茅檐月，蕪城柳岸風。", "寸心談未了，櫂士莫怱怱。"]'),
('15ce63aa-25e6-4d15-85a1-180dca277b40','送劉伯宣尹松江府五首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','宦途昏抹漆，達士久悲絲。',48,'全唐诗/poet.song.236000.json','["宦途昏抹漆，達士久悲絲。", "汲直世多忌，父清人不知。", "隆汙俱合道，行止要隨時。", "富貴真槐蟻，千年看鼎彝。"]'),
('da3baafa-6fe2-4365-ac00-0be88e86f928','送劉伯宣尹松江府五首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','兵燹三年久，瘡痍百姓同。',48,'全唐诗/poet.song.236000.json','["兵燹三年久，瘡痍百姓同。", "政須隨日化，心要與天通。", "刻木期難對，屯膏施易窮。", "松江三萬頃，盂水愛任公。"]'),
('94e5846c-fe8a-43a0-b9eb-f25a75e42b60','送劉伯宣尹松江府五首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','事叢緣網密，意廣忌才疎。',48,'全唐诗/poet.song.236000.json','["事叢緣網密，意廣忌才疎。", "浩浩皇風遠，遲遲化日舒。", "俗移三紀後，德洽百年餘。", "擿伏非仁政，生民本一初。"]'),
('9a6b0d6a-979e-40be-9ce3-2783c22895cc','送劉伯宣尹松江府五首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','烹鮮知政理，履豨識民心。',48,'全唐诗/poet.song.236000.json','["烹鮮知政理，履豨識民心。", "土壤分南北，詩書亙古今。", "遐方猶戰伐，癃老正呻吟。", "三尺焦桐在，煩公發至音。"]'),
('3592fe28-81c2-4296-a7a8-67683ec47499','次韻崔郎中遊西湖','俞德鄰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','萬頃湖光一葦杭，畫橋橫接舊堤長。',64,'全唐诗/poet.song.236000.json','["萬頃湖光一葦杭，畫橋橫接舊堤長。", "松環九里煙雲濕，梅壓孤山水月香。", "梵宇琳宮增突兀，銅駝金谷自凄凉。", "悲吟一夜頭添雪，慚愧崔鴻在洛陽。"]'),
('532c49a5-6c88-4903-9d61-ff273f1ae1f6','范仲山以磵谷居自號爲賦二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','山林朝市兩相忘，寂寂幽居興味長。',64,'全唐诗/poet.song.236000.json','["山林朝市兩相忘，寂寂幽居興味長。", "雨過竹侵書帙浄，風輕花落硯池香。", "三杯卯酒醉未醉，一枕午窗凉更凉。", "人境結廬元不俗，淵明何必定柴桑。"]'),
('ce4425d1-c60b-4b1b-9a80-aeddec9d4198','范仲山以磵谷居自號爲賦二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','丘壑中間著幼輿，何如此地卜幽居。',64,'全唐诗/poet.song.236000.json','["丘壑中間著幼輿，何如此地卜幽居。", "棋聲夜靜客飲酒，花影晝閒兒讀書。", "塵世覆蕉多得鹿，癡人緣木更求魚。", "先生夢覺渾無事，一笑浮雲指太虛。"]'),
('3073dd8f-854a-4459-be1f-771beff1bc6b','山房遣興','俞德鄰','宋','宋诗','song-poetry','','[]','三徑嵐煙護碧苔，地無高下總栽梅。',64,'全唐诗/poet.song.236000.json','["三徑嵐煙護碧苔，地無高下總栽梅。", "花隨流水繞除去，雲共好山排闥來。", "月冷蛙聲諠鼓吹，風清蜃氣聳樓臺。", "過逢况有侯芭在，白首玄經未足咍。"]'),
('a7e094b6-a236-4c45-8552-c5e0ef671e8c','遊靈巖','俞德鄰','宋','宋诗','song-poetry','','[]','躡石捫蘿一徑通，凭闌極目思無窮。',64,'全唐诗/poet.song.236000.json','["躡石捫蘿一徑通，凭闌極目思無窮。", "川明竹樹蕭疎外，人語煙雲杳靄中。", "風月五湖西子舸，樓臺千古梵王宮。", "艱難隠遁尋幽憩，晤語無人憶贊公。"]'),
('7f98a81e-6109-48ae-bc84-86a2a9e3a781','次韻趙提舉二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','白首玄經病子雲，感時懷舊獨霑巾。',64,'全唐诗/poet.song.236000.json','["白首玄經病子雲，感時懷舊獨霑巾。", "十年戰伐多新鬼，四海逢迎少故人。", "上苑鶑花非昔日，曲江蒲柳爲誰春。", "湧金香酒甜如蜜，滿眼沽來莫厭頻。"]'),
('ec5a4bb7-ccf7-41a7-b965-0343981c2fc7','次韻趙提舉二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','寂歷謀生後計然，已將窮達付蒼天。',64,'全唐诗/poet.song.236000.json','["寂歷謀生後計然，已將窮達付蒼天。", "狙公枉自計朝暮，徐邈但知中聖賢。", "歲月催人如過隙，功名隨世任先鞭。", "紛紛燕雀驚鷹隼，誰識圖真在左綿。"]'),
('65f2f252-cbcc-4d3d-938e-548e33e21f18','山林樂四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','山林何所樂，忽忽遂忘歸。',48,'全唐诗/poet.song.236000.json','["山林何所樂，忽忽遂忘歸。", "江闊天低水，山深霧濕衣。", "青蟲當戶織，白鳥背人飛。", "野性因留滯，非干與世違。"]'),
('bda3ba01-3b2d-4fc4-9b34-e51cc105d2ed','山林樂四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','山林何所樂，佳興四時同。',48,'全唐诗/poet.song.236000.json','["山林何所樂，佳興四時同。", "琴罷庭留月，酒殘松度風。", "鶴歸蒼漢外，猿叫碧蘿中。", "却笑磻溪叟，區區理釣筒。"]'),
('f18aac43-6b79-4277-8136-9aa03360b540','山林樂四首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','山林何所樂，所樂在琴書。',48,'全唐诗/poet.song.236000.json','["山林何所樂，所樂在琴書。", "醉買中山酒，遊乘下澤車。", "結交忘鹿豕，分席混樵漁。", "何必桃源路，方爲隠者居。"]'),
('a4ae74f9-9a83-4cca-8acf-c345baf1515a','山林樂四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','山林何所樂，幽處兩三家。',48,'全唐诗/poet.song.236000.json','["山林何所樂，幽處兩三家。", "曲徑新移竹，疎籬舊著花。", "嵐煙千嶂合，野水一橋斜。", "誰道無音樂，漁陽有摻撾。"]'),
('72b216e4-2dd2-4e99-8601-5d776f6472c5','淮楚絕無行樂地萬柳池邊有開元小寺稍潔因載酒約淮上翁荀桂叔林紹先諸友同遊','俞德鄰','宋','宋诗','song-poetry','','[]','柳外澄波繫小艖，玉皇宮畔梵王家。',64,'全唐诗/poet.song.236000.json','["柳外澄波繫小艖，玉皇宮畔梵王家。", "蟻浮臘味杯行酒，鶴避晴煙竈煮茶。", "客裏招邀慙草率，座中霑洽笑蘭闍。", "杖藜歸路西風晚，一抹寒林萬點鴉。"]'),
('a37c7d0c-0ea1-4700-b266-acc836e4d32a','次韻夏楚材登山陽故城有感','俞德鄰','宋','宋诗','song-poetry','','[]','金粟松摧故國荒，春秋未作歎詩亡。',64,'全唐诗/poet.song.236000.json','["金粟松摧故國荒，春秋未作歎詩亡。", "十年漂泊家千里，百代興衰夢一場。", "蠙浦風清波鴨綠，漁梁春暖酒鵝黄。", "相逢且盡尊前醉，莫遣愁多白髮長。"]'),
('ebaa7afc-60b6-4f4f-9643-99f328f6da6f','初度留山陽','俞德鄰','宋','宋诗','song-poetry','','[]','茫茫南國徧旌旗，九日明朝有所思。',64,'全唐诗/poet.song.236000.json','["茫茫南國徧旌旗，九日明朝有所思。", "元亮暮年書甲子，靈均初度憶庚寅。", "魚龍寂寞秋江闊，豺虎從衡客路危。", "歸去白雲堪共卧，萬山深處結茅茨。"]'),
('432e3221-37aa-4d9a-8787-a45967857a00','答淮上翁二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','風雨淒淒戰客衣，長淮東去鴈南飛。',64,'全唐诗/poet.song.236000.json','["風雨淒淒戰客衣，長淮東去鴈南飛。", "碧山學士老復老，芳草王孫歸不歸。", "尊酒細論悲昨夢，囊書空負笑前非。", "木奴千輩侯千戶，早晚應須賦式微。"]'),
('f5e686e1-40b4-4a71-ae0d-5257c7b5ddee','答淮上翁二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','京江語別十三春，宇宙茫茫幾戰塵。',64,'全唐诗/poet.song.236000.json','["京江語別十三春，宇宙茫茫幾戰塵。", "客路秋風欺白髮，陰房夜雨濕青燐。", "杖藜嘆世悲誰子，懸印朝天少故人。", "回首鹿門思舊隠，荒墳宿草更沾巾。"]'),
('ab6525f1-542d-496d-a3bf-296f73b4c4e0','懷林紹先三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','長淮滾濁瀾，春半尚嚴寒。',48,'全唐诗/poet.song.236000.json','["長淮滾濁瀾，春半尚嚴寒。", "久客愁無寐，懷人醉不歡。", "讀書狂李白，忘事老師丹。", "何日歸林下，悠然飯一簞。"]'),
('2fc08896-870b-4c01-b5a2-6d32c3a8366b','懷林紹先三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','歲歲苦擔簦，飄然雲水僧。',48,'全唐诗/poet.song.236000.json','["歲歲苦擔簦，飄然雲水僧。", "星霜變玄鳥，天地有青蠅。", "留滯慵僮僕，懷歸畏友朋。", "求田端有暇，誰復問陳登。"]'),
('de1a6785-5fa7-4dcf-b4a8-52c7c07bf0ca','懷林紹先三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','羈懷不自憀，明日又花朝。',48,'全唐诗/poet.song.236000.json','["羈懷不自憀，明日又花朝。", "我畏杖藜遠，君難折簡招。", "愁長憐髮短，室邇嘆人遥。", "剪盡西窗燭，憑誰慰寂寥。"]'),
('77b556b5-999c-4e8f-b4fc-8cc432f37893','寓山陽天慶館作','俞德鄰','宋','宋诗','song-poetry','','[]','紫氣浮關悵客情，琳宮羸卧絕逢迎。',64,'全唐诗/poet.song.236000.json','["紫氣浮關悵客情，琳宮羸卧絕逢迎。", "長廊夜靜蛩吟苦，古殿秋深鶴唳清。", "勾漏丹砂何處問，藍橋雲液爲誰傾。", "捲簾殘月斜窺牖，街鼓鼕鼕又五更。"]'),
('05127796-b0d6-439f-82b6-00250c5a5403','次韻陳教授見寄二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','藜牀聽雨卧，雨霽抱琴行。',48,'全唐诗/poet.song.236000.json','["藜牀聽雨卧，雨霽抱琴行。", "古徑荒苔合，秋渠墜葉平。", "流年悲鴈影，往事咽蛩聲。", "誰識玄都觀，劉郎舊有名。"]'),
('08b08b43-c511-4bbb-ab56-0dd375210976','次韻陳教授見寄二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','江城吾舊隠，今歲喜秋穰。',48,'全唐诗/poet.song.236000.json','["江城吾舊隠，今歲喜秋穰。", "一頃南山豆，千畦負郭薑。", "看雲扃戶晚，對月引杯長。", "他日憑魚鴈，猶堪話楚狂。"]'),
('f2d20887-e0c9-479e-adb5-3cdd7f3c6751','送程道大歸新安兼簡憲使盧處道學士四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','倦客思歸整旆鞍，班荆祖道駐江干。',64,'全唐诗/poet.song.236000.json','["倦客思歸整旆鞍，班荆祖道駐江干。", "浮雲流水別離易，明月清風會晤難。", "携妓東山須載酒，上書北闕莫求官。", "諸公衮衮君休羨，得馬還將失馬看。"]'),
('f9693894-5829-4d91-9021-ae94a6c70061','送程道大歸新安兼簡憲使盧處道學士四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','十年故國黍離離，一日翩然賦式微。',64,'全唐诗/poet.song.236000.json','["十年故國黍離離，一日翩然賦式微。", "儒服政憐山鳥怪，機心何獨海鷗飛。", "山中朝露閒觀槿，嶺曲春風自采薇。", "蒼狗白衣從變化，是今非昔昔誰非。"]'),
('2f6007c6-65dc-4305-bbdf-09f0a3a74a29','送程道大歸新安兼簡憲使盧處道學士四首  其三','俞德鄰','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','我生慚愧賈胡留，暮鼓晨鐘復報秋。',64,'全唐诗/poet.song.236000.json','["我生慚愧賈胡留，暮鼓晨鐘復報秋。", "萬里橋南存舊宅，十年客舍尚并州。", "青山是處堪埋骨，白髮新來漸滿頭。", "此日送君何限意，長江萬折有東流。"]'),
('4ea83252-462c-4e55-9837-d1eef4cd351a','送程道大歸新安兼簡憲使盧處道學士四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','戔戔束帛賁丘阿，有幾英雄入網羅。',64,'全唐诗/poet.song.236000.json','["戔戔束帛賁丘阿，有幾英雄入網羅。", "少室山人徵不起，貞元朝士已無多。", "聲光赫奕埋輪使，音調凄清扣角歌。", "傾蓋相驩應恨晚，喬松千尺有絲蘿。"]'),
('19eadf17-6ed7-40c8-8168-0a3e04a86e43','次韻程道益見贈二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','此生慚愧馬牛襟，返鎖柴門歲月深。',64,'全唐诗/poet.song.236000.json','["此生慚愧馬牛襟，返鎖柴門歲月深。", "避地管寧甘白帽，登臺郭隗自黄金。", "風霜漸老騷人鬢，天地元知國士心。", "却喜程侯晚相遇，長魚碧酒共清吟。"]'),
('1375ee60-bfbd-4f24-8fb2-9eed450bd8a4','次韻程道益見贈二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','十載時艱淚染襟，餘生幾擬託幽深。',64,'全唐诗/poet.song.236000.json','["十載時艱淚染襟，餘生幾擬託幽深。", "匹夫無罪空懷璧，校尉有官從摸金。", "老去風塵猶瞇眼，春來藥裹更關心。", "草玄作賦吾何敢，梁父吟成祇自吟。"]'),
('bb87c255-a8c1-4c5b-a075-12d4dd98a15a','病中三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','病來十日閉茅廬，孤負吟詩與著書。',64,'全唐诗/poet.song.236000.json','["病來十日閉茅廬，孤負吟詩與著書。", "牀下不知牛是蟻，濠間誰識子非魚。", "羸形分絕麒麟畫，老境堪同鹿豕居。", "坎止流行隨所寓，分明天地一籧篨。"]'),
('69c3654f-e570-4b41-a0b0-790a2b0a2e76','病中三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','腐儒麤糲愧無功，一月兼旬卧病中。',64,'全唐诗/poet.song.236000.json','["腐儒麤糲愧無功，一月兼旬卧病中。", "賦就但應增肺渴，檄成元不愈頭風。", "移心有法難忘藥，折臂無緣定作公。", "世事漸艱吾已老，翛然夢不到槐宮。"]'),
('14f980ac-03e7-4225-af25-2042a887c6ec','病中三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','婢尋本草犬迎醫，二豎驅除去復隨。',64,'全唐诗/poet.song.236000.json','["婢尋本草犬迎醫，二豎驅除去復隨。", "衰老維摩常示病，瘦生杜甫不關詩。", "門堪羅雀那容駟，釜不烹魚但作糜。", "見說九重徵武士，却須攘臂學支離。"]'),
('e4a3a82a-cdec-418c-91a8-78e436ba82ca','故舶使知泉州趙公挽詞五首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','閩粵驅馳後，乾坤震蕩中。',48,'全唐诗/poet.song.236000.json','["閩粵驅馳後，乾坤震蕩中。", "名雖高斗北，身竟老遼東。", "仕止因時異，悲懽與世同。", "洛濱多侍從，立懦獨清風。"]'),
('64f55576-4469-4a08-99e8-d3cada76dc48','故舶使知泉州趙公挽詞五首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','慷慨辭雙節，逍遥寄一筇。',48,'全唐诗/poet.song.236000.json','["慷慨辭雙節，逍遥寄一筇。", "揚雄雖若鳳，老子自猶龍。", "霽月窗前草，悲風隴上松。", "遺民應巷哭，何但輟秦舂。"]'),
('c57f3ba5-1b01-4abc-bcc0-d93869df1ffe','故舶使知泉州趙公挽詞五首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','壯歲風雲會，衰齡岸谷遷。',48,'全唐诗/poet.song.236000.json','["壯歲風雲會，衰齡岸谷遷。", "芾棠南國裏，細柳曲江邊。", "天地紛戈甲，園林寂管絃。", "康成共丁卯，肯避巳辰年。"]'),
('2196bab5-bc60-497a-9992-01df8ffef017','故舶使知泉州趙公挽詞五首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','杜陵侔稷契，諸葛陋袁曹。',48,'全唐诗/poet.song.236000.json','["杜陵侔稷契，諸葛陋袁曹。", "道在七分易，文過九辯騷。", "丘原終古閉，嵩嶽極天高。", "况復階庭樹，于今有鳳毛。"]'),
('65b3a9a8-1702-46a8-aad0-40e5f96e2e8f','故舶使知泉州趙公挽詞五首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','世梗投林密，人稀寄驛遲。',48,'全唐诗/poet.song.236000.json','["世梗投林密，人稀寄驛遲。", "一朝傳易簀，千古竟騎箕。", "斲鼻空悲郢，援琴謾憶期。", "薤歌嗟已晚，生死負恩私。"]'),
('9d47c718-98d3-4bf7-8356-8b00b9724fcc','秋壑堂','俞德鄰','宋','宋诗','song-poetry','','[]','衮繡三朝樂盛時，湖山廊廟兩棲遲。',64,'全唐诗/poet.song.236000.json','["衮繡三朝樂盛時，湖山廊廟兩棲遲。", "一聲鼙鼓乾坤沸，萬里煙塵草木悲。", "隔葉黄鸝空睍睆，定巢紫燕尚差池。", "春風不管人間事，猶繞雕闌颺綠漪。"]'),
('22692cdc-7447-4fd7-a334-ff730e9d9702','懷聶道錄二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','形影參商已六春，春風吹夢益霑巾。',64,'全唐诗/poet.song.236000.json','["形影參商已六春，春風吹夢益霑巾。", "江頭楊柳送行客，窗外梅花疑故人。", "世事茫茫山嶽隔，年光冉冉燕鴻新。", "一尊何日重携手，鶴外乾坤迥不塵。"]'),
('019f5550-7cc0-43a2-a731-96a2324f0f56','懷聶道錄二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','夜鶴朝猿伴苦吟，碧窗靜鎖綠雲陰。',64,'全唐诗/poet.song.236000.json','["夜鶴朝猿伴苦吟，碧窗靜鎖綠雲陰。", "青精可飯藥資乏，黄獨無苗山雪深。", "豈有故人分祿米，但聞隠士寄焦琴。", "相思一夜生春草，明月滿街天籟沈。"]'),
('9357bf22-c3e7-4e2e-9005-7f0bfe25279d','病愈出游','俞德鄰','宋','宋诗','song-poetry','','[]','桐帽椶鞋破曉煙，落花飛絮暮春天。',64,'全唐诗/poet.song.236000.json','["桐帽椶鞋破曉煙，落花飛絮暮春天。", "風簷轉日噪乾鵲，雲樹隔溪啼杜鵑。", "客引茅亭沽舊酒，僧邀竹院話枯禪。", "病餘一事還堪笑，脚力輕鬆倍去年。"]'),
('0af385f6-2d47-47d6-8697-7045a42dc81a','舟行欲訪三茅踐許宗師鶴會之約','俞德鄰','宋','宋诗','song-poetry','','[]','磵飲巖棲願已違，小舟拂曉泛漣漪。',64,'全唐诗/poet.song.236000.json','["磵飲巖棲願已違，小舟拂曉泛漣漪。", "蒲叢露冷泣姑惡，木末雲深叫子規。", "山近三茅便杖屐，酒沽五里带糟醨。", "乘風俓擬尋幽躅，莫負當年汗漫期。"]'),
('ee5d6087-b17b-436e-a005-c8cbc51fc52f','夜卧旅邸夢入三茅山一道士病一道士鼾睡因作詩紀其概云','俞德鄰','宋','宋诗','song-poetry','','[]','夢入三茅叩玉扉，樓臺金碧浄朝暉。',64,'全唐诗/poet.song.236000.json','["夢入三茅叩玉扉，樓臺金碧浄朝暉。", "巖花澗草高低見，田鶴沙禽下上飛。", "道士倚牆方熟睡，至人杜德不言機。", "人間天上元非遠，非想非非更覺非。"]'),
('c48083b8-b006-48ab-a9e7-be2e0cc98964','人日','俞德鄰','宋','宋诗','song-poetry','','[]','人日吟窗滌硯塵，探官擘繭笑鄉鄰。',64,'全唐诗/poet.song.236000.json','["人日吟窗滌硯塵，探官擘繭笑鄉鄰。", "山人雅愛終南徑，詩客空懷渭北春。", "譽毀蓋棺猶未了，勳名看鏡不須頻。", "從今好是支離卧，有客問余方負薪。"]'),
('577e86a1-6eb5-4b4c-b549-27b46d129913','郭朝奉挽詞二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','性儉家常足，心閒體自胖。',48,'全唐诗/poet.song.236000.json','["性儉家常足，心閒體自胖。", "令名緣有子，良貴不須官。", "遺像衣冠古，高堂几席寒。", "他年說耆舊，回首重辛酸。"]'),
('8bd69878-07cd-4724-b714-b0e2f5c34bf3','郭朝奉挽詞二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','世態十年別，交情奕代論。',48,'全唐诗/poet.song.236000.json','["世態十年別，交情奕代論。", "及門先倒屣，引酌定空尊。", "杖屨春風語，松楸夜月魂。", "些成嗟已晚，江闊聽啼猿。"]'),
('286cfd28-b765-4cd8-8550-eb1111a8a804','悼俞仁則','俞德鄰','宋','宋诗','song-poetry','','[]','藕花汀畔柳絲垂，杯酒殷勤話別離。',64,'全唐诗/poet.song.236000.json','["藕花汀畔柳絲垂，杯酒殷勤話別離。", "風雨對牀空有約，池塘夢草竟無詩。", "荒墳日落誰人弔，古屋苔深獨我悲。", "畢竟功名大槐國，排雲書在即豐碑。"]'),
('0c657ccc-9e1b-41a5-bb84-ac62e365084b','吳門逢友人','俞德鄰','宋','宋诗','song-poetry','','[]','澤國江山冷戰雲，扁舟春晚忽逢君。',64,'全唐诗/poet.song.236000.json','["澤國江山冷戰雲，扁舟春晚忽逢君。", "荒城鼓角含商氣，舊曲樓臺暗楚氛。", "海燕認巢迷故主，苔蝸篆壁變新文。", "更憐庾信江南賦，音調凄清不忍聞。"]'),
('723f4f85-e6a7-4c41-95b8-aa77dcf61317','送張師道','俞德鄰','宋','宋诗','song-poetry','','[]','七閩幕府藉詞臣，一笑平反草木春。',64,'全唐诗/poet.song.236000.json','["七閩幕府藉詞臣，一笑平反草木春。", "制下九重新渙汗，胸蟠千古舊經綸。", "生平耻不爲伊傅，夜半何煩問鬼神。", "無限焦枯待霖雨，好將斯道覺斯民。"]'),
('c2b81f21-6539-47d0-8ffa-b7869fa0e8f4','送道士孫雪房','俞德鄰','宋','宋诗','song-poetry','','[]','霧豹文章野鶴姿，黄冠晦跡淛江涯。',64,'全唐诗/poet.song.236000.json','["霧豹文章野鶴姿，黄冠晦跡淛江涯。", "携家擬就鹿門隠，奏賦何期狗監知。", "觸熱問塗行有日，排雲論事豈無時。", "太平上策須傾倒，更憶崆峒麥熟詩。"]'),
('ecb367e2-ca7e-435f-ba7b-6d3bc50e40dc','送董左丞二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','帝睠東南用正人，角巾歸第請何頻。',64,'全唐诗/poet.song.236000.json','["帝睠東南用正人，角巾歸第請何頻。", "相公久矣倦台鼎，故國依然倚世臣。", "霖雨合歸天上作，忠言須造榻前陳。", "丈夫出處非徒爾，四海安危寄一身。"]'),
('b7c05bfc-bd8d-4009-a131-71b206bed8c5','送董左丞二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','煌煌勳業繪凌煙，共說韋平有世賢。',64,'全唐诗/poet.song.236000.json','["煌煌勳業繪凌煙，共說韋平有世賢。", "黄閤紫樞名將相，凉臺燠館半神仙。", "百年富貴真槐國，一日清閒勝葛天。", "祇恐九重方側席，東山未許遽高眠。"]'),
('d2de112a-2762-4e1f-912f-f8f42d30703a','閒居遣懷','俞德鄰','宋','宋诗','song-poetry','','[]','密樹幽花似遠村，循除流水自渾渾。',64,'全唐诗/poet.song.236000.json','["密樹幽花似遠村，循除流水自渾渾。", "無僧肯送盧仝米，有客時過陸抗門。", "月暈河天魚散子，泥融雨徑竹生孫。", "十年四海干戈滿，似此遺民幾戶存。"]'),
('ffeca1ef-c091-4898-aa46-65e36a620c94','爲湯提刑賦南園玉繡毬花二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','繡衣持斧舊詩翁，天與奇葩襯綺櫳。',64,'全唐诗/poet.song.236000.json','["繡衣持斧舊詩翁，天與奇葩襯綺櫳。", "翠㔩葉攢珠的皪，碧搔頭映玉瓏璁。", "氤氳香霧迷叢蝶，淡沲晴颸颺轉蓬。", "安得素娥斟綠醑，緩歌一闋月明中。"]'),
('fd7d5464-b192-4a42-988d-86fc27584afd','爲湯提刑賦南園玉繡毬花二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','愁煙泫露泣明妃，萬蝶魂迷倦不飛。',64,'全唐诗/poet.song.236000.json','["愁煙泫露泣明妃，萬蝶魂迷倦不飛。", "帳簇流蘇裀翡翠，階翻蹴踘落珠璣。", "瓊葩分韻香疑減，柳絮成團似却非。", "風雨朝昏他日約，忍令容易失芳菲。"]'),
('a1118eed-f671-4ce9-abd1-81b4a37fe7e1','次韻陳靜佳詠梅','俞德鄰','宋','宋诗','song-poetry','','[]','玉骨冰肌不受塵，紛紛紅紫謾爭春。',64,'全唐诗/poet.song.236000.json','["玉骨冰肌不受塵，紛紛紅紫謾爭春。", "最宜巖壑風霜夜，相對心腸鐵石人。", "寂寞上林迷霧苑，嵯峨巫岫隔煙津。", "翛然自得閒中趣，肯與姚黄作素臣。"]'),
('5465823c-fe46-4eef-b7d5-696f019e270b','古寺','俞德鄰','宋','宋诗','song-poetry','','[]','古寺倚崢嶸，春風信馬行。',48,'全唐诗/poet.song.236000.json','["古寺倚崢嶸，春風信馬行。", "猿吟千樹暗，僧定一燈明。", "野水循除出，庭莎夾徑生。", "云何多俗韻，一宿又江城。"]'),
('5d2a19b3-dbe8-4c26-9c93-2fc8cde27509','故樞密使陸公挽詞三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','杞國天將壓，蒼梧雲正愁。',48,'全唐诗/poet.song.236000.json','["杞國天將壓，蒼梧雲正愁。", "龍胡垂可挽，魚腹葬何憂。", "萬死丹心在，千齡王氣收。", "縣知精衛忿，今古不能休。"]'),
('9644f76d-1292-47be-9343-3ca97b2faf0b','故樞密使陸公挽詞三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','七朝迷瘴霧，一昔倒狂瀾。',48,'全唐诗/poet.song.236000.json','["七朝迷瘴霧，一昔倒狂瀾。", "天意竟難料，皇圖不再安。", "寧甘蹈東海，不忍縶南冠。", "自古誰無死，從容就義難。"]'),
('091f0429-2571-43fb-9d38-fdbdc050f3ca','故樞密使陸公挽詞三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','羣雄紛愛死，一士獨捐生。',48,'全唐诗/poet.song.236000.json','["羣雄紛愛死，一士獨捐生。", "曆數絕誰續，綱常晦復明。", "人皆念王蠋，天豈禍程嬰。", "淚眼休枯盡，他年看史評。"]'),
('625942c0-7f89-4888-9651-421296507f9f','次韻答酈學正見贈三首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','雞鳴羣動已憧憧，習靜工夫自笑慵。',64,'全唐诗/poet.song.236000.json','["雞鳴羣動已憧憧，習靜工夫自笑慵。", "風月一襟霜兩鬢，圖書萬卷酒千鍾。", "維摩示病元非病，李廣難封不願封。", "世道隆污隨所適，我知老子本猶龍。"]'),
('b991f455-1dd0-415e-86cb-a29c1852e79f','次韻答酈學正見贈三首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','蕭森竹柏小蒲菴，身世嵇康七不堪。',64,'全唐诗/poet.song.236000.json','["蕭森竹柏小蒲菴，身世嵇康七不堪。", "眼底故人俱寂寞，鏡中衰髮自䰐鬖。", "過車慷慨陳清酹，舊館殷勤脫左驂。", "老我與君同此意，紛紛輕薄不須談。"]'),
('e553a34f-454f-4076-9cf5-0cb463124b8e','次韻答酈學正見贈三首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','粥飯隨緣類出家，小瓶汲月自煎茶。',64,'全唐诗/poet.song.236000.json','["粥飯隨緣類出家，小瓶汲月自煎茶。", "浮榮等是蕉中鹿，薄俗堪憐井底蛙。", "南畝半栽元亮秫，東陵多種邵平瓜。", "青鞋布襪相隨去，九陌紅塵任沒車。"]'),
('89ad5b35-5cc9-4ea4-801a-e98c4f300104','次韻陳教授見寄二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','擬效時人恥效尤，時人嫉我亦如讎。',64,'全唐诗/poet.song.236000.json','["擬效時人恥效尤，時人嫉我亦如讎。", "携金嬾市燕臺駿，賣劍聊尋渤海牛。", "白髮盈簪羞我老，黄花滿徑爲誰秋。", "尊前有酒休辭醉，癡絕由來愛虎頭。"]'),
('bf5c0fcb-d6cd-449e-ae8f-d86456b879e1','次韻陳教授見寄二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','朝暮何人肯拔尤，周民何友亦何讎。',64,'全唐诗/poet.song.236000.json','["朝暮何人肯拔尤，周民何友亦何讎。", "還家久類蘇耽鶴，溷世聊歌甯戚牛。", "筆在不妨書甲子，詩亡誰爲作春秋。", "百年修短終歸盡，倚杖看山任白頭。"]'),
('28e26db6-8c2b-4143-a8bb-d2bd14f17f10','夏五園亭對雨漫成六首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','野鶴乘軒愧不才，柴門鍵密晝慵開。',64,'全唐诗/poet.song.236000.json','["野鶴乘軒愧不才，柴門鍵密晝慵開。", "荒亭鎖霧紅葵老，古木號風白雨來。", "酒免官沽時一醉，詩非私貸日相催。", "人間萬事皆兒戲，千載昆明幾劫灰。"]'),
('96cb3ec5-4a5e-47e9-b5e1-84742b05109a','夏五園亭對雨漫成六首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','從來工瑟莫吹竽，赤米黄虀儘自娛。',64,'全唐诗/poet.song.236000.json','["從來工瑟莫吹竽，赤米黄虀儘自娛。", "種柳藏鴉憐哺母，葺巢護燕待將雛。", "荆榛少剪但除道，瓜芋多栽莫問區。", "金馬玉堂元有分，青銅慚愧白髭鬚。"]'),
('277081a2-0524-4b61-9779-d87f5be26f3a','夏五園亭對雨漫成六首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','鏡中勳業不須論，拭髮何由得馬肝。',64,'全唐诗/poet.song.236000.json','["鏡中勳業不須論，拭髮何由得馬肝。", "日暮論文思李白，年衰忘事類師丹。", "幾多歸燕愁無主，是處鳴蛙總爲官。", "多謝天公相勞苦，梅風吹雨長琅玕。"]'),
('7888a5bd-39c5-44e1-8228-df5a778be308','夏五園亭對雨漫成六首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','五噫休作不平鳴，世事悠悠弈一枰。',64,'全唐诗/poet.song.236000.json','["五噫休作不平鳴，世事悠悠弈一枰。", "歌有紅兒休用比，酒無白墮亦須傾。", "青山倘是埋骨好，素髮何嫌照眼明。", "鼎鼎百年三萬日，曉煙收盡暮雲橫。"]'),
('52550fe9-46b9-49ce-9209-e79b14ac71e8','夏五園亭對雨漫成六首  其五','俞德鄰','宋','宋诗','song-poetry','','[]','雨霽雲收正午天，槐陰翳翳北窗眠。',64,'全唐诗/poet.song.236000.json','["雨霽雲收正午天，槐陰翳翳北窗眠。", "百年未了暫爲客，一日得閒真是仙。", "美酒但尋知己飲，好詩休用俗人傳。", "山林鐘鼎知誰是，輸與鴟夷理釣船。"]'),
('77fff334-8e5b-435d-8388-f64dcc6aec05','夏五園亭對雨漫成六首  其六','俞德鄰','宋','宋诗','song-poetry','','[]','有酒能澆磊磈胸，人生何處不從容。',64,'全唐诗/poet.song.236000.json','["有酒能澆磊磈胸，人生何處不從容。", "橫飛遼海成孤鶴，老死南陽亦卧龍。", "習靜一丘聊自足，逢時萬戶莫先封。", "梧楸門巷將迎少，澗曲分畦學老農。"]'),
('bf721528-b554-4769-a4f5-3a5bf97608e5','秋泊吳門寄友','俞德鄰','宋','宋诗','song-poetry','','[]','尊酒旗亭說舊遊，重來茂苑又深秋。',64,'全唐诗/poet.song.236000.json','["尊酒旗亭說舊遊，重來茂苑又深秋。", "煙霞靜鎖詩人屋，風雨常欺倦客樓。", "獨鴈叫羣天漠漠，蹇馿畏滑路悠悠。", "相思清夜黄花老，一琖寒燈萬斛愁。"]'),
('cbc5bd97-2836-4a70-9bdd-dba803273583','次韻薛曉翁教授','俞德鄰','宋','宋诗','song-poetry','','[]','鯤鵬意氣鶴精神，髣髴風流賀季真。',64,'全唐诗/poet.song.236000.json','["鯤鵬意氣鶴精神，髣髴風流賀季真。", "三顧豈無天下計，百年空老夢中身。", "兵塵滿眼誰知己，儒術謀生每誤人。", "長嘯歸來尋舊隠，石田茅屋未全貧。"]'),
('6c4f72c7-b6bd-467e-aeb2-9bf7b5675261','閒境','俞德鄰','宋','宋诗','song-poetry','','[]','門外紅塵競往還，小軒容膝自怡顔。',64,'全唐诗/poet.song.236000.json','["門外紅塵競往還，小軒容膝自怡顔。", "三杯對影夜邀月，一笏拄頤朝看山。", "芳草落花春不老，鳴鳩乳燕樂相關。", "人間尋徧無閒境，閒境由來祇此間。"]'),
('2edc856a-d874-4fa2-883a-e65881188287','小園漫興四首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','小園雨過草離離，寂寞葵榴又一時。',64,'全唐诗/poet.song.236000.json','["小園雨過草離離，寂寞葵榴又一時。", "載酒客來閒問字，催租人去更吟詩。", "一杯淡粥學僧供，三尺高牀避鬼吹。", "百歲光陰行六十，世間何許鳳凰池。"]'),
('97c67481-40b5-42b2-93bd-fa17f14964f3','小園漫興四首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','杖藜竹外獨徘徊，歎息人間幾劫灰。',64,'全唐诗/poet.song.236000.json','["杖藜竹外獨徘徊，歎息人間幾劫灰。", "燕頷素無難食肉，蟹螯才有便持杯。", "世人枉是皆欲殺，明主何嘗肯棄才。", "多謝諸公共推輓，公車時亦到蒿萊。"]'),
('b48078f0-b9db-4fb4-a866-8e978daf15a2','小園漫興四首  其三','俞德鄰','宋','宋诗','song-poetry','','[]','公車縱肯詔遺民，宣髮蕭蕭已滿巾。',64,'全唐诗/poet.song.236000.json','["公車縱肯詔遺民，宣髮蕭蕭已滿巾。", "美景昔時多樂事，豐年今日有饑人。", "翻雲覆雨憐輕薄，洗眼開懷任屈伸。", "野鶴瘦軀馴鹿性，此時寧復繪麒麟。"]'),
('14ddda7b-4588-4a9b-ba51-5f2e35eb8abc','小園漫興四首  其四','俞德鄰','宋','宋诗','song-poetry','','[]','華髮思鄉去苦遲，人民城郭總成非。',64,'全唐诗/poet.song.236000.json','["華髮思鄉去苦遲，人民城郭總成非。", "九原可作吾誰與，三徑就荒胡不歸。", "詩思寂寥無腹稿，病軀顦顇減腰圍。", "有時夢與鍾期遇，閒拂枯桐按玉徽。"]'),
('81c43dbb-ed0c-4354-8a26-67b9593522ad','懷蕭道夫','俞德鄰','宋','宋诗','song-poetry','','[]','北轍南轅一昔分，何時尊酒細論文。',64,'全唐诗/poet.song.236000.json','["北轍南轅一昔分，何時尊酒細論文。", "談經舉世用燕說，橫筆何人靜楚氛。", "朋輩風流推李杜，弟兄詞藻愧機雲。", "麟洲有客長迴首，歸誦琅章飫所聞。"]'),
('24f03090-e884-43a3-b538-31a264030b96','泊閻橋有懷','俞德鄰','宋','宋诗','song-poetry','','[]','青鏡霜刀杳莫尋，陳留巷陌故陰陰。',64,'全唐诗/poet.song.236000.json','["青鏡霜刀杳莫尋，陳留巷陌故陰陰。", "鴻飛猶記東西跡，燕去難留下上音。", "多病樂天悲老近，三生杜牧恨春深。", "浮雲柳絮元無準，慚愧人間兒女心。"]'),
('813d1400-0415-490b-8b46-4c1feb32398a','戲簡友人二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','百年何處築菟裘，又向周南歎滯留。',64,'全唐诗/poet.song.236000.json','["百年何處築菟裘，又向周南歎滯留。", "砧韻但能凄客枕，鴈聲渾不到歌樓。", "江湖展轉魚千里，今古驅馳貉一丘。", "回首金焦渺何許，瀟瀟風雨使人愁。"]'),
('1b4f2e85-fce9-4c7e-9603-eabc6c7f1dd5','戲簡友人二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','茅齋蓬鬢靜編蒲，誰使擔簦問客途。',64,'全唐诗/poet.song.236000.json','["茅齋蓬鬢靜編蒲，誰使擔簦問客途。", "萬里晴雲離塞鴈，一天明月繞枝烏。", "羈愁浩渺夜將半，詩思凄凉歲欲徂。", "却羨故人沉醉處，紅樓紅粉擁紅鑪。"]'),
('1a7f02f7-2993-498b-a2b9-84eacf17fee3','次郭元德二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','馬周淹逆旅，夢寐憶常何。',48,'全唐诗/poet.song.236000.json','["馬周淹逆旅，夢寐憶常何。", "琴古知音少，囊空得句多。", "凄凉憐我老，慷慨爲誰歌。", "三尺匣中劍，時時自濯磨。"]'),
('126d3f4e-6312-4c95-a6b5-5349483164ad','次郭元德二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','昔賢多不偶，今我欲如何。',48,'全唐诗/poet.song.236000.json','["昔賢多不偶，今我欲如何。", "浮世歡娛少，衰年感慨多。", "吾伊繙蠹簡，欵乃聽漁歌。", "自笑平生志，低回竟不磨。"]'),
('0d9f4f8e-8b95-496c-87a3-1d0284c5ee2f','次韻郭元德旅懷','俞德鄰','宋','宋诗','song-poetry','','[]','挾冊知何用，援琴且自寬。',48,'全唐诗/poet.song.236000.json','["挾冊知何用，援琴且自寬。", "世途今更險，客枕夜偏寒。", "俯仰隨時易，隆汙合道難。", "功名大槐夢，青鏡莫頻看。"]'),
('4a38fc8a-b1bc-4959-b377-563c528d8292','偶題','俞德鄰','宋','宋诗','song-poetry','','[]','身世厭漂零，衣冠愧典刑。',48,'全唐诗/poet.song.236000.json','["身世厭漂零，衣冠愧典刑。", "乾坤開闔戶，日月短長亭。", "水闊連天白，山高擁岸青。", "揚雄中有宅，垂老太玄經。"]'),
('f8c93c4b-5d8d-480d-b48f-161717f723ad','村居即事二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','地僻村深過客稀，數家生聚突煙微。',64,'全唐诗/poet.song.236000.json','["地僻村深過客稀，數家生聚突煙微。", "魚蝦入網忙呼酒，鵝鴨棲池靜掩扉。", "喚婦索綯苫屋角，課兒斫竹補籬圍。", "溝東積水通前浦，也有蒲帆带雨歸。"]'),
('712498f3-ad06-46c6-b569-966f52ac8d3a','村居即事二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','漠漠平疇接遠沙，一浜寒水浸梅花。',64,'全唐诗/poet.song.236000.json','["漠漠平疇接遠沙，一浜寒水浸梅花。", "兒挑苦芺供鵝食，妻擷葫荽薦客茶。", "榾柮火殘寒尚力，茅柴酒熟夜能賒。", "歲時伏臘歌呼處，三世兒孫共一家。"]'),
('4de87bb7-0f66-4377-8929-fd41b90509ff','贈良常山人','俞德鄰','宋','宋诗','song-poetry','','[]','青歲迂疎厭市廛，誅茅結屋北山巔。',64,'全唐诗/poet.song.236000.json','["青歲迂疎厭市廛，誅茅結屋北山巔。", "泉冷陰洞猿分飲，草軟陽坡鹿伴眠。", "三徑煙雲渾是畫，四時風月不論錢。", "忽逢野老談庚甲，笑指喬松不記年。"]'),
('2a41f598-7b9e-4230-8971-34f14a66abfa','富安田舍二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','風饕雪虐駕扁舟，又作田家數日留。',64,'全唐诗/poet.song.236000.json','["風饕雪虐駕扁舟，又作田家數日留。", "鴈逐稻粱飛遠浦，犬驚杖屐吠荒丘。", "三杯薄酒延僧話，一琖寒燈伴客愁。", "白水漫漫妨麥事，催錢縣吏亦宜休。"]'),
('809eb323-13a8-4542-adb8-e791a8baa856','富安田舍二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','漠漠寒雲接斷蕪，平疇積水入長湖。',64,'全唐诗/poet.song.236000.json','["漠漠寒雲接斷蕪，平疇積水入長湖。", "犢眠籬下霜埋草，鴈宿汀邊月滿蘆。", "戟吻苦茶連葉煮，膠牙酸酒带糟餔。", "數朝已覺人情熟，識字耕田著我無。"]'),
('9858cd2f-5ba1-420a-911d-e739d2fef7ae','田家喜雪','俞德鄰','宋','宋诗','song-poetry','','[]','漫空飛雪歲云徂，獨坐閒吟粟滿膚。',64,'全唐诗/poet.song.236000.json','["漫空飛雪歲云徂，獨坐閒吟粟滿膚。", "廓落江山千態迥，渾淪天地一塵無。", "寒聲夜吼松筠裂，和氣朝回薺麥蘇。", "說與田家判一醉，明年寧復慮官租。"]'),
('1245108c-6289-4dd8-9f7d-d473039cf866','除夕二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','十旬爲客思凄然，返樛言歸又覈田。',64,'全唐诗/poet.song.236000.json','["十旬爲客思凄然，返樛言歸又覈田。", "榾柮煨鑪銷永夜，屠蘇浸井迫新年。", "人生半是忙中過，農事偏于隠者便。", "將老菟裘何處卜，九龍泉畔錫山邊。"]'),
('f3caaef4-b8ad-4396-9f7c-c96f0f8b545c','除夕二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','買田陽羨笑東坡，三黜窮荒兩鬢皤。',64,'全唐诗/poet.song.236000.json','["買田陽羨笑東坡，三黜窮荒兩鬢皤。", "瘴霧蠻煙添老色，寒燈夜雨强悲歌。", "百年富貴歡悰少，一日清閒樂事多。", "說與故人休大噱，省曹閽者面如何。"]'),
('94f6c31e-fea9-4eca-bb87-f84689551241','次韻郭元德閒居二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','萬事夢中夢，百年身後身。',48,'全唐诗/poet.song.236000.json','["萬事夢中夢，百年身後身。", "黄塵空沒馬，白髮不饒人。", "鱸美蓴波浄，螯肥菊露新。", "相思須命駕，莫厭子輿貧。"]'),
('3e7b6b74-01e4-4d18-b262-a67826a329f8','次韻郭元德閒居二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','弋篡冥鴻遠，城荒去鶴還。',48,'全唐诗/poet.song.236000.json','["弋篡冥鴻遠，城荒去鶴還。", "萬緣俱是幻，百計不如閒。", "人在羲黄上，時當晉宋間。", "委心乘物化，何地不蓬山。"]'),
('f3926528-254f-4254-8fe6-81aaa779ebd0','后平叔母夫人挽辭二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','十載干戈四海同，幾人徐庶幾陳宮。',64,'全唐诗/poet.song.236000.json','["十載干戈四海同，幾人徐庶幾陳宮。", "阿奴侍母但膝下，潘令棄官歸洛中。", "生死總歸蝴蝶夢，哀榮何啻馬牛風。", "送車千乘誰能致，我亦潸然淚灑空。"]'),
('2aa418d8-0486-40ce-af39-a0f4673e322f','后平叔母夫人挽辭二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','昔年烽火隔江津，指痛呻吟夜徹晨。',64,'全唐诗/poet.song.236000.json','["昔年烽火隔江津，指痛呻吟夜徹晨。", "旁置萬家空有冢，祿營三釜已無親。", "鸞回紫誥承恩舊，牛卧青岡卜兆新。", "送死養生無一憾，老懷緣此重沾巾。"]'),
('b230f891-07e5-4e36-a3d1-d1f41db3dc83','餞楊少監','俞德鄰','宋','宋诗','song-poetry','','[]','白髮蒼顔自在仙，流行坎止任天然。',64,'全唐诗/poet.song.236000.json','["白髮蒼顔自在仙，流行坎止任天然。", "江山得意俓携酒，家世爲官不愛錢。", "天與清閒娛晚景，人看富貴出長年。", "傳聞尺一來閶闔，匹馬春風快着鞭。"]'),
('a262fac9-8c49-4728-84c4-1815e8b8df9f','楊剛中分教京口有司以冗員罷去作詩爲別就次韻以餞其行二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','沖霄志氣合雄飛，誰遣談經坐絳幃。',64,'全唐诗/poet.song.236000.json','["沖霄志氣合雄飛，誰遣談經坐絳幃。", "夜雨簷花聊痛飲，秋風蓴菜竟思歸。", "一官豈爲吾曹冗，五斗政嫌兒輩譏。", "去去草玄從尚白，丈夫元不羨輕肥。"]'),
('5fcf54c9-f159-4069-884b-d2d9578db8bd','楊剛中分教京口有司以冗員罷去作詩爲別就次韻以餞其行二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','公車指日召嚴徐，友道從渠自耳餘。',64,'全唐诗/poet.song.236000.json','["公車指日召嚴徐，友道從渠自耳餘。", "浮世功名蕉覆鹿，冷官滋味釜生魚。", "百年荏苒醒還醉，一氣循環慘復舒。", "歸去湖山多樂事，故人休枉絕交書。"]'),
('9784804a-b395-4e30-b785-5b9a9a18ecc8','贈程秀才','俞德鄰','宋','宋诗','song-poetry','','[]','莎徑莓牆枳棘籬，藜牀六尺卧書帷。',64,'全唐诗/poet.song.236000.json','["莎徑莓牆枳棘籬，藜牀六尺卧書帷。", "門前剝啄誰驚夢，馬上推敲客有詩。", "北牖清風聊共語，夜梁落月重相思。", "賓鴻此去過京峴，應遣新吟慰舊知。"]'),
('64106789-95ed-45ad-a0e6-23ee45e377b6','姑蘇有贈','俞德鄰','宋','宋诗','song-poetry','','[]','畫樓珠翠列娉婷，遼鶴重來失故城。',64,'全唐诗/poet.song.236000.json','["畫樓珠翠列娉婷，遼鶴重來失故城。", "商女不知寧有恨，徐娘雖老尚多情。", "一簾花雨談幽夢，雙槳蓴波急去程。", "却倚閶門重回首，笳聲嗚咽暮雲橫。"]'),
('785eac8a-dc13-4f5e-a1df-086fe6d40dd9','天竺山','俞德鄰','宋','宋诗','song-poetry','','[]','鷲嶺舊尋詩，重來十載期。',48,'全唐诗/poet.song.236000.json','["鷲嶺舊尋詩，重來十載期。", "蛩吟僧定榻，猿挂鶴棲枝。", "山月穿窗入，溪雲傍竹移。", "一聲清磬發，應悔出家遲。"]'),
('65c04d4e-38e3-4fb8-b314-d117ce47429c','遊金山寺次壁間韻','俞德鄰','宋','宋诗','song-poetry','','[]','水國微茫境物閒，洪濤九派護禪關。',64,'全唐诗/poet.song.236000.json','["水國微茫境物閒，洪濤九派護禪關。", "帆檣下上淮連浙，樓殿高低寺裹山。", "潮駕金鰲來海上，天留玉府在人間。", "凭闌落日蘆風起，時有魚龍聽法還。"]'),
('2bde8be2-448c-4a38-914a-0a0e2e9e1931','醉中偶書','俞德鄰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','落花流水兩無依，夢入桃源覺已非。',64,'全唐诗/poet.song.236000.json','["落花流水兩無依，夢入桃源覺已非。", "尊酒闌珊山月落，片帆摇曳浦風微。", "雲橫北固朱樓遠，煙暝西湖畫舸歸。", "別易會難今古恨，鱗鴻來往莫相違。"]'),
('c03d1d63-f9b6-4357-9247-68c04b5681b8','甘露寺火後登多景樓故基有作','俞德鄰','宋','宋诗','song-poetry','','[]','西風散屧步崔嵬，霽色浮空望眼開。',64,'全唐诗/poet.song.236000.json','["西風散屧步崔嵬，霽色浮空望眼開。", "江勢亂奔滄海去，天形低約衆山回。", "一卷狠石埋焦土，百尺危樓付劫灰。", "惟有沙鷗知我意，相親相近不驚猜。"]'),
('fd2ccf65-1052-4acd-a596-3f06c772f34e','金陵道','俞德鄰','宋','宋诗','song-poetry','','[]','樓頭凝望處，落日帝王州。',24,'全唐诗/poet.song.236000.json','["樓頭凝望處，落日帝王州。", "下有朝宗水，滔滔日夜流。"]'),
('35ca1e55-181e-4756-ba35-26cba25bf400','曉行沙上','俞德鄰','宋','宋诗','song-poetry','','[]','宿雨浥輕塵，沙平草樹春。',24,'全唐诗/poet.song.236000.json','["宿雨浥輕塵，沙平草樹春。", "遠山千萬疊，空翠欲霑人。"]'),
('ec7762a3-da00-422c-82a6-de538d5c5731','客中雨','俞德鄰','宋','宋诗','song-poetry','','[]','風雨正瀟瀟，孤燈伴寂寥。',24,'全唐诗/poet.song.236000.json','["風雨正瀟瀟，孤燈伴寂寥。", "關心多少事，一一付芭蕉。"]'),
('fe833637-54f1-45b0-b338-3ad927a244ea','尋春','俞德鄰','宋','宋诗','song-poetry','','[]','日日尋春到水涯，今朝籬落見梅花。',32,'全唐诗/poet.song.236000.json','["日日尋春到水涯，今朝籬落見梅花。", "折梅欲問春消息，春在橋南賣酒家。"]'),
('810e18c9-0ecf-4f70-adbc-682099e4b312','春日山行','俞德鄰','宋','宋诗','song-poetry','','[]','山北山南日幾回，半山山舍更傳杯。',32,'全唐诗/poet.song.236000.json','["山北山南日幾回，半山山舍更傳杯。", "一聲羌笛山雲裂，二月山花有落梅。"]'),
('0fb68b69-0a2c-41aa-a92f-f440d7badd0e','晚醉','俞德鄰','宋','宋诗','song-poetry','','[]','兀兀餘酣潄晚汀，古犧香霧入疎櫺。',32,'全唐诗/poet.song.236000.json','["兀兀餘酣潄晚汀，古犧香霧入疎櫺。", "捲簾歸坐月弦上，隔岸遠山青更青。"]'),
('1d85d37a-1a69-43f9-8031-d392def3b7c7','何山白水田','俞德鄰','宋','宋诗','song-poetry','','[]','離離遠樹接山低，白水田頭杜宇啼。',32,'全唐诗/poet.song.236000.json','["離離遠樹接山低，白水田頭杜宇啼。", "昨夜前村新雨過，桔槹閒在石橋西。"]'),
('4938314f-a998-400d-9c24-d9a0356db2f7','題米友仁遠景','俞德鄰','宋','宋诗','song-poetry','','[]','蒙蒙樹隠山，渺渺波橫海。',24,'全唐诗/poet.song.236000.json','["蒙蒙樹隠山，渺渺波橫海。", "其中一葉舟，豈有陶朱在。"]'),
