('f85c9025-7226-4563-9219-2ff1df90c846','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其五','俞德鄰','宋','宋诗','song-poetry','','[]','水秀山明仙佛國，天開地闢帝王家。',32,'全唐诗/poet.song.236000.json','["水秀山明仙佛國，天開地闢帝王家。", "欲窮勝賞人非昔，獨立西風夕照斜。"]'),
('149304cc-0102-45e6-b993-c75f83440a3c','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其六','俞德鄰','宋','宋诗','song-poetry','','[]','衮繡三朝邁等倫，曾將雙美繪麒麟。',32,'全唐诗/poet.song.236000.json','["衮繡三朝邁等倫，曾將雙美繪麒麟。", "當年早共赤松去，未必清漳見逐臣。"]'),
('931f6b69-530d-4369-9350-cded80b408f9','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其七','俞德鄰','宋','宋诗','song-poetry','','[]','黄門飛鞚賜厨珍，翠舞珠歌度十春。',32,'全唐诗/poet.song.236000.json','["黄門飛鞚賜厨珍，翠舞珠歌度十春。", "今日敗垣荒草合，近前那復相君嗔。"]'),
('f2d28d55-5190-459a-a9f8-69a53490a784','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其八','俞德鄰','宋','宋诗','song-poetry','','[]','堤邊楊柳拂晴波，堤上遊人衒綺羅。',32,'全唐诗/poet.song.236000.json','["堤邊楊柳拂晴波，堤上遊人衒綺羅。", "山色湖光渾似舊，采蓮人唱采茶歌。"]'),
('8ac2af67-3667-45b7-8323-d6d20abef677','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其九','俞德鄰','宋','宋诗','song-poetry','','[]','慈雲嶺下拜郊臺，表裏湖山繡畫開。',32,'全唐诗/poet.song.236000.json','["慈雲嶺下拜郊臺，表裏湖山繡畫開。", "十載西風動禾黍，行人休憶翠華來。"]'),
('6d3d20a2-2781-4d10-80b2-f49fc3bb65b5','癸未遊杭作口號十首因事懷舊雜以俚語不復詮擇  其一○','俞德鄰','宋','宋诗','song-poetry','','[]','西馬塍邊紅杏雨，金牛寺外白楊風。',32,'全唐诗/poet.song.236000.json','["西馬塍邊紅杏雨，金牛寺外白楊風。", "杭人憂樂多如此，儻有聖賢吾欲中。"]'),
('883fa27b-46ec-405d-9444-167967b4638f','敬題丞相趙忠靖公墨梅爲張宣參作','俞德鄰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','稜稜瘦鐵點瑶花，筆底陽和轉歲華。',32,'全唐诗/poet.song.236000.json','["稜稜瘦鐵點瑶花，筆底陽和轉歲華。", "却笑西湖窮處士，暗香疎影屬誰家。"]'),
('1c399bde-c141-4895-9757-81915fecae33','次韻張受益六言兼戲方使君二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','狎鷺亭臨野水，夢蝶牀置禪齋。',28,'全唐诗/poet.song.236000.json','["狎鷺亭臨野水，夢蝶牀置禪齋。", "矲矮金壺有酒，葛天栗陸無懷。"]'),
('a87c5b66-d233-4747-8574-71c1c24a68f1','次韻張受益六言兼戲方使君二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','燕玉公堪暖老，澤室我嫌犯齋。',28,'全唐诗/poet.song.236000.json','["燕玉公堪暖老，澤室我嫌犯齋。", "世事不均如此，臨風渺渺余懷。"]'),
('359a452f-db7d-4699-932a-e6aa4c045943','題古木寒泉手卷','俞德鄰','宋','宋诗','song-poetry','','[]','觱沸一谿泉，巃嵸千古木。',24,'全唐诗/poet.song.236000.json','["觱沸一谿泉，巃嵸千古木。", "中有避世人，陰厓結茅屋。"]'),
('1c8dbcd3-6b11-4e90-92b9-a02fe820a185','題葉勸農對山樓次韻二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','三平二滿過即休，十事九律誰與謀。',32,'全唐诗/poet.song.236000.json','["三平二滿過即休，十事九律誰與謀。", "歸來政自有佳趣，樓對青山山對樓。"]'),
('57c9b2b7-c6bc-4f31-b6e9-7d05a57ca2ee','題葉勸農對山樓次韻二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','避名莫學韓伯休，生子何必孫仲謀。',32,'全唐诗/poet.song.236000.json','["避名莫學韓伯休，生子何必孫仲謀。", "遥岑寸碧可人意，風月一天閒倚樓。"]'),
('93e7dbea-9ca7-438d-b28f-cf9296455839','贈武當山孫道士二首  其一','俞德鄰','宋','宋诗','song-poetry','','[]','雲龍風虎正經綸，長嘯歸山作道人。',32,'全唐诗/poet.song.236000.json','["雲龍風虎正經綸，長嘯歸山作道人。", "千古武當丘壑在，紛紛高位幾全身。"]'),
('8fbccf81-3742-4bc3-9b6e-6d8a0a75e7d6','贈武當山孫道士二首  其二','俞德鄰','宋','宋诗','song-poetry','','[]','漢祚雖開四百基，韓彭諸將竟何之。',32,'全唐诗/poet.song.236000.json','["漢祚雖開四百基，韓彭諸將竟何之。", "誰如四皓商山去，明月一天餐紫芝。"]'),
('8ba5a80b-d37c-42ba-9a46-3e7cbdfab1c1','桐廬縣作','俞德鄰','宋','宋诗','song-poetry','','[]','荒城秋雨後，寒谷曉晴初。',24,'全唐诗/poet.song.236000.json','["荒城秋雨後，寒谷曉晴初。", "沙路縈紆處，柴扉蕩析餘。"]'),
('a240ba71-f199-4d42-b0d2-a0a875aadaea','泊東館','俞德鄰','宋','宋诗','song-poetry','','[]','一望嚴陵十里餘，亂山銜日鴈相呼。',32,'全唐诗/poet.song.236000.json','["一望嚴陵十里餘，亂山銜日鴈相呼。", "故人零落今餘幾，獨有黄公舊酒罏。"]'),
('93e9c565-e9ab-4c89-a4ec-183a86b44628','郊居','俞德鄰','宋','宋诗','song-poetry','','[]','野徑晴霏斂，江郊夏日凉。',24,'全唐诗/poet.song.236000.json','["野徑晴霏斂，江郊夏日凉。", "夢中知是蝶，還復是蒙莊。"]'),
('4d106024-5e7e-4901-9255-196ec1e46b62','訪三茅舟至金沙雨阻因游龍山書院','俞德鄰','宋','宋诗','song-poetry','','[]','遊霧登天計苦遲，崑崙聊欲訪支離。',32,'全唐诗/poet.song.236000.json','["遊霧登天計苦遲，崑崙聊欲訪支離。", "幅巾破曉龍山去，且免三茅費勒移。"]'),
('ddd71f93-2721-411e-87bd-439d4ff4aecc','村舍','俞德鄰','宋','宋诗','song-poetry','','[]','㶁㶁流泉漱石寒，蒙蒙草樹接江干。',32,'全唐诗/poet.song.236000.json','["㶁㶁流泉漱石寒，蒙蒙草樹接江干。", "雲歸遠岫月初上，雨打落花春又殘。"]'),
('0557f93d-197b-4238-94f3-137903ce9c53','次韻山人見寄','俞德鄰','宋','宋诗','song-poetry','','[]','營得菟裘佚暮年，雲山萬疊足風煙。',32,'全唐诗/poet.song.236000.json','["營得菟裘佚暮年，雲山萬疊足風煙。", "絕憐擾擾馳名者，落日西津喚渡船。"]'),
('3f5ae120-d638-4e30-af69-8d2986a5066e','閒居','俞德鄰','宋','宋诗','song-poetry','','[]','客少經過因地僻，門無障礙覺天寬。',32,'全唐诗/poet.song.236000.json','["客少經過因地僻，門無障礙覺天寬。", "餘生已斷封侯願，渭北蕭蕭竹萬竿。"]'),
('d3cd06c5-2168-4e22-a2b3-f134ceea9e5f','泊湖頭','俞德鄰','宋','宋诗','song-poetry','','[]','潦翻川蓊匌，烟靄樹模糊。',24,'全唐诗/poet.song.236000.json','["潦翻川蓊匌，烟靄樹模糊。", "小艇時呼客，龍游酒試沽。"]'),
('26148c9e-e973-4896-868f-2aae9cfcedc2','初晴','劉辰翁','宋','宋诗','song-poetry','','[]','初日入高樓，歸雲雜江樹。',108,'全唐诗/poet.song.236000.json','["初日入高樓，歸雲雜江樹。", "鱼遊新雨晴，鳥語晨光吐。", "天容朗復清，烟色轉輕素。", "牆草麗車前，巷溝映泥路。", "窗明袪宿潤，礎泫滑微步。", "會朝有宿客，過午無來屨。", "沿砌上蠙衣，虛庭竿犢袴。", "人生足無事，世故非所慮。", "彼語吾不聞，清風有時度。"]'),
('ea78d21a-a7fd-4adc-9fc6-09f65625a9f7','山中雨行  其一','劉辰翁','宋','宋诗','song-poetry','','[]','雨行如漏篷，側身半車中。',48,'全唐诗/poet.song.236000.json','["雨行如漏篷，側身半車中。", "風翻荷葉白，難可爲芙蓉。", "向來三重茅，仰屋嘆穿空。", "已經亂離苦，志念常從容。"]'),
('22f9ddfe-fd95-46ae-b82d-a397a41e799e','山中雨行  其二','劉辰翁','宋','宋诗','song-poetry','','[]','入城過新雨，路靜市人稀。',48,'全唐诗/poet.song.236000.json','["入城過新雨，路靜市人稀。", "吾家林塘間，水鴨狂欲飛。", "門闌稚子笑，隔樹見翁歸。", "何人無此樂，頹暮樂知希。"]'),
('b469749d-cbfb-4ed3-8fe0-7151cd69af88','沙苑箭','劉辰翁','宋','宋诗','song-poetry','','[]','道人不在無人茶，空房惟有菖蒲花。',96,'全唐诗/poet.song.236000.json','["道人不在無人茶，空房惟有菖蒲花。", "偶留壁上一枝箭，熟視恍惚令人嗟。", "箭頭年月去如電，吹向空中再相見。", "亦知近事不偶然，汝亦當時負吾箭。", "神仙一劍在吾手，萬事空驚一搔首。", "馬嵬重過雨淋鈴，異日臨邛是君否。"]'),
('cf592b7e-33be-41d0-8572-f9c7f3e1d55e','月下','劉辰翁','宋','宋诗','song-poetry','','[]','月色爲酒吾爲壺，仰天吸盡欲更沽。',112,'全唐诗/poet.song.236000.json','["月色爲酒吾爲壺，仰天吸盡欲更沽。", "世界如入流離珠，東南大半江海湖。", "微風白浪如摇鬚，子從我也有意無。", "跳身作勢與泪俱，嘗試入此觀何如。", "惜哉畏死非吾徒，嘔出還爾桑田枯。", "仙人嗔我涴六銖，醉中無力能分疏。", "汝自失脚如逃逋，彈指咄咄汝負吾。"]'),
('7e7e0509-7880-4843-ac49-2affc2a9c839','題墨竹長卷與汪遂良','劉辰翁','宋','宋诗','song-poetry','','[]','摩訶池上龍千年，化爲匹練橫曳煙。',32,'全唐诗/poet.song.236000.json','["摩訶池上龍千年，化爲匹練橫曳煙。", "拔石數莖衝蒼天，我見其面何必全。"]'),
('718e4e82-219d-4082-acae-71242b52ee75','送李鶴田遊古杭','劉辰翁','宋','宋诗','song-poetry','','[]','天下南北車書通，行人點點過汴宮。',320,'全唐诗/poet.song.236000.json','["天下南北車書通，行人點點過汴宮。", "空餘艮嶽一拳土，黯慘如雪吹不融。", "平乘樓上王夷甫，一灑中州淚如雨。", "西風羽扇不障塵，更自蓮子隨根去。", "政事堂上三相公，往往退食如夔龍。", "少年慟哭不見用，一語不合面發紅。", "八年流落無處所，合眼當朝遽如許。", "忠魂不到海門潮，別殿芙蓉廢爲圃。", "茫茫古路日平西，不信金銅不淚垂。", "浮沈親故懶相問，白髮惟有春風知。", "李侯髀肉堪流涕，同谷哀吟越州第。", "買絲刺繡刺未成，公子翩翩雁書至。", "飄飄起望白雲間，裘雪牛車度赤山。", "亂餘七十能幾見，我且欲往窮當還。", "平生高李經行處，寂寞斷橋漂落絮。", "不知到日似枯魚，淚入黄河別魴鱮。", "當空殿閣密雲團，曾和薰絃接羽翰。", "至今尚留花石否，杜鵑再賦長恨端。", "蘇州正念東鄰女，傷心更遇楊開府。", "憔悴語言敢分明，買酒行澆茂陵土。"]'),
('eae7c7ff-f360-4da3-a66a-ea7a30cc0b78','寄別孫潜齋','劉辰翁','宋','宋诗','song-poetry','','[]','嘗笑唐衢生，一慟可以死，焉能流涕被面日日別知己。',303,'全唐诗/poet.song.236000.json','["嘗笑唐衢生，一慟可以死，焉能流涕被面日日別知己。", "又嘗笑朝鮮無淚可霑巾，悲歌兩語爲我異婦人。", "平生鍾情重離別，一聽陽關腸一絕。", "銅駝陌上會逢君，誰料相忘如永訣。", "憶昔携手青青春，水邊一笑禊吏塵。", "醉能狂歌醒能賦，滿座惟有孫堯文。", "酒闌歌斷如轉燭，寒食纍纍新鬼哭。", "丞相書桐異烏巢，曾園仙市芳郊綠。", "海棠三徑無根株，敗瓦頹垣亦已鋤。", "舊遊多感有至此，獨爲吾黨懷區區。", "我欲與君重一到，化爲長瓶酹荒草。", "早知世事去如風，只合黄公壚下倒。", "當時一醉鍤埋我，不見興亡應更好。", "且復止此休云云，我有陳子高能文。", "令其讀罷日就君，就君歸日誦所聞。", "吾貧吾老不足念，君鬚君髮何年變。", "幼安九十愁更愁，空羨一生長樂傳。", "嗚呼斯人斯世不相見，綠樹鶑啼淚如霰。"]'),
('19252103-b272-4c78-9cc9-99bce6bfc578','夜雨','劉辰翁','宋','宋诗','song-poetry','','[]','夜半起雷車，天門報曉衙。',48,'全唐诗/poet.song.236000.json','["夜半起雷車，天門報曉衙。", "何消如此雨，又有未開花。", "繡被人中酒，茅簷客夢家。", "一晴天地闊，稽首見重華。"]'),
('5d42a072-7968-4859-8609-f3a979169249','留京','劉辰翁','宋','宋诗','song-poetry','','[]','遠夢孤難到，憑高烟景微。',48,'全唐诗/poet.song.236000.json','["遠夢孤難到，憑高烟景微。", "重留山僕怨，數別里人稀。", "病用寒衣盡，書無定日歸。", "十年行役事，俯首輒歔欷。"]'),
('1a151eeb-05ea-4f11-bd17-97a97089562d','輓劉明國','劉辰翁','宋','宋诗','song-poetry','','[]','浮邱成一夢，如此哭斯人。',48,'全唐诗/poet.song.236000.json','["浮邱成一夢，如此哭斯人。", "宇宙真如醉，風霆若有神。", "涅槃空萬劫，懸解總微塵。", "有子承千載，堂堂麟筆新。"]'),
('d8181c3a-f0d9-42cd-a6dc-0d4e3c349f32','輓朱文公','劉辰翁','宋','宋诗','song-poetry','','[]','皇天開太極，庚戌聖人生。',48,'全唐诗/poet.song.236000.json','["皇天開太極，庚戌聖人生。", "六籍文將絕，千年道復明。", "淵源羅仲素，師友李延平。", "遶舍閩溪急，潺湲洛水聲。"]'),
('07970b59-32c3-4dbb-b975-cd9aa9b0b23a','輓蔡西山','劉辰翁','宋','宋诗','song-poetry','','[]','四海朱夫子，徵君獨典型。',48,'全唐诗/poet.song.236000.json','["四海朱夫子，徵君獨典型。", "青雲伯夷傳，白首太玄經。", "有客憐孤憤，無人問獨醒。", "瑶琴空寶匣，絃誦不堪聽。"]'),
('1ae95c57-4b0c-4546-b7b4-4e43e31aa164','錢秀才要社日呈漢宰詩書以予之錢以長句爲謝饒秀才又用社日韻作詩見投因用韻並答二君','劉辰翁','宋','宋诗','song-poetry','','[]','知津積雨坡云爾，故並涪翁快閣晴。',64,'全唐诗/poet.song.236000.json','["知津積雨坡云爾，故並涪翁快閣晴。", "投贈更欣佳士識，眵昏寧待好山明。", "浩然放逐緣多病，東野窮愁坐不平。", "萬歲千秋有何得，一杯斷勿換浮名。"]'),
('3058396e-9d5a-4f92-893f-bae4a58e7ff2','餘興','劉辰翁','宋','宋诗','song-poetry','','[]','江國遲歸二十年，十年兩繫峽江船。',64,'全唐诗/poet.song.236000.json','["江國遲歸二十年，十年兩繫峽江船。", "身如梅子半晴雨，路入柳花相後先。", "堠短堠長春繫馬，江南江北夜聞鵑。", "人生老大空無用，寄語羣兒早着鞭。"]'),
('c6b4abb7-60f6-4908-8653-be72031d3989','咏西湖偉觀樓','劉辰翁','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','舉目看來皆畫屏，只因闌檻接蒼冥。',64,'全唐诗/poet.song.236000.json','["舉目看來皆畫屏，只因闌檻接蒼冥。", "江湖二水一般白，吳越兩山相對青。", "雲北雲南何處沒，潮生潮落幾時停。", "西偏不被斜陽碍，直見家山與洞庭。"]'),
('ac24a885-2cc9-4fce-9d88-5d54ce13cdc6','重陽','劉辰翁','宋','宋诗','song-poetry','','[]','風流九日勝前期，誰把茱萸壓桂枝。',64,'全唐诗/poet.song.236000.json','["風流九日勝前期，誰把茱萸壓桂枝。", "天地盡從騷國老，風煙何似蔣陵時。", "故人四海知誰健，白髮黄花總奈吹。", "滿座衣冠陳迹遠，明年復憶去年詩。"]'),
('bb52e7f8-5c1e-47ce-a6db-2823c77f1277','周耐軒見訪','劉辰翁','宋','宋诗','song-poetry','','[]','麥徑紆斜縮寄蝸，傳呼驚倒望前牙。',64,'全唐诗/poet.song.236000.json','["麥徑紆斜縮寄蝸，傳呼驚倒望前牙。", "能忘特進羣公表，來訪尋常百姓家。", "草市波喧騰竹馬，柴門路隘簇鞍花。", "屏窺不信雌同甲，爲倍高明兩鬢華。"]'),
('d6962aa6-a6fa-45c2-bea2-d8cde402bd49','壽段知事','劉辰翁','宋','宋诗','song-poetry','','[]','曉立斕斒拜二親，擁門賀客半詩人。',64,'全唐诗/poet.song.236000.json','["曉立斕斒拜二親，擁門賀客半詩人。", "月三十斛菊花水，秋八千年椿樹春。", "每有傳聞須說項，明當召入定留恂。", "南來北去多陳迹，惟有聲名日日新。"]'),
('b3678f14-1330-4e3d-acec-792dc8db49bb','壽城山六十五','劉辰翁','宋','宋诗','song-poetry','','[]','留得八千唐刺史，看成百億宰官身。',64,'全唐诗/poet.song.236000.json','["留得八千唐刺史，看成百億宰官身。", "不爭一月大小閏，猶是兩朝耆俊人。", "今歲兩翻初度日，明年三十六宮春。", "近來化得鄉君子，爲報麻姑不更塵。"]'),
('98fc27ca-1558-44cd-a450-f7637c81f998','壽周耐軒府尹','劉辰翁','宋','宋诗','song-poetry','','[]','去日江南梅未花，歸來芳草漲天涯。',64,'全唐诗/poet.song.236000.json','["去日江南梅未花，歸來芳草漲天涯。", "馳驅斥堠八千里，夢寐青原十萬家。", "白叟倚門清燕寢，黄童騎馬學胡笳。", "八陵盡是燕京路，想爲孤楸訊暮鴉。"]'),
('5ecafa80-d02f-47b6-82ce-9cd3600cfbce','壽王按察','劉辰翁','宋','宋诗','song-poetry','','[]','試手東南第一杯，江南知己是寒梅。',64,'全唐诗/poet.song.236000.json','["試手東南第一杯，江南知己是寒梅。", "山中四老衣冠起，野外諸生俎豆開。", "天運又從今日始，江空如見古翁來。", "清平笑語皆文物，早起書雲認魯臺。"]'),
('36362b30-1054-4888-86f9-dce798c49e58','戲題','劉辰翁','宋','宋诗','song-poetry','','[]','無人知坦腹，水影半簾苔。',24,'全唐诗/poet.song.236000.json','["無人知坦腹，水影半簾苔。", "驚謂青蟲墮，垂絲忽上來。"]'),
('44ed0eee-3487-47f8-a141-480b7ff26e31','春歸','劉辰翁','宋','宋诗','song-poetry','','[]','留春一日不可，種樹十年未成。',28,'全唐诗/poet.song.236000.json','["留春一日不可，種樹十年未成。", "芳草斷腸花落，綠窗携手鶑聲。"]'),
('aed8ad8b-7fa3-4f5f-8dee-1f611c7f9690','梅','劉辰翁','宋','宋诗','song-poetry','','[]','花前速到速到，月下一盃一盃。',28,'全唐诗/poet.song.236000.json','["花前速到速到，月下一盃一盃。", "好語被人道盡，簪花步月歸來。"]'),
('93135e18-7f8b-4a5d-b1c0-73455d8ff7be','許練師携手求題','劉辰翁','宋','宋诗','song-poetry','','[]','養就金童姹女精，松風蘿月寄閒情。',32,'全唐诗/poet.song.236000.json','["養就金童姹女精，松風蘿月寄閒情。", "廣寒桂樹商飈起，咫尺浮黎白玉京。"]'),
('f2703092-ab53-4113-83ca-888d1a74c83a','春晴  其一','劉辰翁','宋','宋诗','song-poetry','','[]','江柳長天草色齊，新晴何物不芳菲。',32,'全唐诗/poet.song.236000.json','["江柳長天草色齊，新晴何物不芳菲。", "無因化作千蝴蝶，西蜀東吳款款歸。"]'),
('766e8b86-857a-42de-8354-ccb2fefc577d','春晴  其二','劉辰翁','宋','宋诗','song-poetry','','[]','新燕池塘綠雨肥，初晴未暖日光微。',32,'全唐诗/poet.song.236000.json','["新燕池塘綠雨肥，初晴未暖日光微。", "角巾猶带花梢濕，纔倚闌干見絮飛。"]'),
('36ddcffa-2eba-492c-bb33-a2978158d123','壽王太守  其一','劉辰翁','宋','宋诗','song-poetry','','[]','鱗鱗鴛瓦試新霜，斗帳寒輕夜漏長。',32,'全唐诗/poet.song.236000.json','["鱗鱗鴛瓦試新霜，斗帳寒輕夜漏長。", "天上玉麟來瑞世，夢餘奎壁燦星光。"]'),
('ad6194d4-58d1-4648-9d62-050ac3fc1f14','壽王太守  其二','劉辰翁','宋','宋诗','song-poetry','','[]','韻華瑞籥應黄鐘，六葉階蓂舞舜風。',32,'全唐诗/poet.song.236000.json','["韻華瑞籥應黄鐘，六葉階蓂舞舜風。", "袖有西山童子藥，清霜夜映玉顔紅。"]'),
('33de4b5a-b49d-4437-a4b8-04bf2d7d36b7','壽王太守  其三','劉辰翁','宋','宋诗','song-poetry','','[]','龍飛天子禹湯明，收拾英才共太平。',32,'全唐诗/poet.song.236000.json','["龍飛天子禹湯明，收拾英才共太平。", "寄語吳興賢太守，亟將霖雨濟蒼生。"]'),
('c6ce49f1-d077-43a6-abc3-b820c4924296','壽王太守  其四','劉辰翁','宋','宋诗','song-poetry','','[]','八千秋與八千春，此語繇來未識真。',32,'全唐诗/poet.song.236000.json','["八千秋與八千春，此語繇來未識真。", "曾共麻姑擗麟脯，笑看滄海幾揚塵。"]'),
('38a61067-ede2-46e9-af1d-a029701d52b1','壽王太守  其五','劉辰翁','宋','宋诗','song-poetry','','[]','月中桂斫夜琅琅，搗就瓊花絕粒方。',32,'全唐诗/poet.song.236000.json','["月中桂斫夜琅琅，搗就瓊花絕粒方。", "繇是蟾宮折雲路，願持雲粉薦霞觴。"]'),
('73d1a8d7-6a90-4aaa-8fa1-91595127b823','春景 花蕊上蜂鬚','劉辰翁','宋','宋诗','song-poetry','','[]','擾擾課生涯，蜂脾若似家。',72,'全唐诗/poet.song.236000.json','["擾擾課生涯，蜂脾若似家。", "看來鬚上蕊，餐盡眼前花。", "百卉如脩貢，千門總釀葩。", "露香沾掩冉，風絮入槎牙。", "飲硯偷玄去，沿簪着鬢斜。", "粉痕驚墜處，遠趁上番衙。"]'),
('148c2fb4-7af0-4bd1-87ac-10664ec24183','春景 柳塘春水漫','劉辰翁','宋','宋诗','song-poetry','','[]','柳外澹烟光，芊綿去路長。',72,'全唐诗/poet.song.236000.json','["柳外澹烟光，芊綿去路長。", "風花隨世界，春水漫池塘。", "手種青青許，堤回曲曲香。", "綠猶深舊雨，流不動斜陽。", "濠上知魚樂，橋邊看燕忙。", "欄干風起晚，人影皺羅裳。"]'),
('12bb45fe-03d5-4e60-b9a0-9eff26827b52','春景 春來常早起','劉辰翁','宋','宋诗','song-poetry','','[]','世事懽娛夢，芳心老未灰。',72,'全唐诗/poet.song.236000.json','["世事懽娛夢，芳心老未灰。", "每常須起早，豈獨爲春來。", "自與韶光約，長應倒載回。", "久無朝馬動，漫道曉鴉催。", "秧事侵晨理，花期昨夜開。", "誤令圯上者，見謂有心哉。"]'),
('c7011f3c-dcb7-45bf-a02a-6a4b1a6b9b00','春景 杖藜入春泥','劉辰翁','宋','宋诗','song-poetry','','[]','步出浣花溪，兒童識杖藜。',72,'全唐诗/poet.song.236000.json','["步出浣花溪，兒童識杖藜。", "逝將隨晚景，獨自入春泥。", "九節閑堪愛，百錢相與携。", "行從竹雞裏，徑到子規西。", "屐弊猶須蠟，壺傾可得提。", "暮歸驚倒載，笑倒白銅鞮。"]'),
('00cce955-e124-41b0-bea5-e91453f5659b','春景 春草步步綠','劉辰翁','宋','宋诗','song-poetry','','[]','何苦懷芳草，無情綠又新。',72,'全唐诗/poet.song.236000.json','["何苦懷芳草，無情綠又新。", "年年生古道，步步是青春。", "愁碧連分袂，飛紅墮舞茵。", "一筇當秀野，萬里亦隨人。", "莽蒼成蕪楚，烟緜又入秦。", "長安紅紫陌，羅襪已生塵。"]'),
('b3c1edc8-82f4-4537-be16-5a41fd2185f5','春景 絕域改春華 其一','劉辰翁','宋','宋诗','song-poetry','','[]','絕域何堪久，悠悠日又斜。',72,'全唐诗/poet.song.236000.json','["絕域何堪久，悠悠日又斜。", "未能辭客况，更自改春華。", "故國三千里，荒春八九家。", "一聲幽谷鳥，滿眼故園花。", "漸煖回歸雁，餘寒倚暮鴉。", "陌頭看過客，歌吹擁氈車。"]'),
('90db8f34-8df5-4c26-abc2-a9cf757fc3a8','春景 絕域改春華 其二','劉辰翁','宋','宋诗','song-poetry','','[]','絕域魂堪斷，風烟不可遮。',72,'全唐诗/poet.song.236000.json','["絕域魂堪斷，風烟不可遮。", "至今疑夢事，舉目改春華。", "此處吾爲客，何言國與家。", "尚存他日淚，又看一年花。", "谷口遷鶑語，都城御柳斜。", "茫茫皆漢土，無地種秦瓜。"]'),
('5550e24e-de8a-4b38-ae4c-dce4d9b4dd73','春景 寒食月明雨','劉辰翁','宋','宋诗','song-poetry','','[]','寒食娛清夜，飛紅已滿城。',72,'全唐诗/poet.song.236000.json','["寒食娛清夜，飛紅已滿城。", "日懸春又暮，月是雨中明。", "漢苑傳新燭，鄜州憶故京。", "柳梢眉黯黮，花上淚縱橫。", "人立斜河澹，晨占上冢晴。", "綿田烟泣露，天老豈無情。"]'),
('e2743ab9-ebf6-4f44-84ec-f49e3c4363a1','春景 落花香滿泥 其一','劉辰翁','宋','宋诗','song-poetry','','[]','春去如流水，落花忙又忙。',72,'全唐诗/poet.song.236000.json','["春去如流水，落花忙又忙。", "晴泥空滿眼，陳迹尚餘香。", "無計留枝上，愁人香路旁。", "雨餘金谷土，風動馬嵬囊。", "拾翠遺鴻爪，飛紅入燕梁。", "遥憐妝墮馬，寸步斷人腸。"]'),
('80838fbc-31d8-40d9-831c-fe444a384870','春景 落花香滿泥 其二','劉辰翁','宋','宋诗','song-poetry','','[]','花落秦虞兮，紛紛東復西。',72,'全唐诗/poet.song.236000.json','["花落秦虞兮，紛紛東復西。", "舉頭無霽日，滿地是香泥。", "紅雨愁如海，絮風飄上堤。", "和成文杏壘，軟襯錦韉蹄。", "妙舞驚飛燕，醉歸扶竹雞。", "誰家採桑女，陌上自相携。"]'),
('8f575825-0ad1-4d66-a320-24b3ff64e055','春景 空院落花深','劉辰翁','宋','宋诗','song-poetry','','[]','綠沈空院雨，依約舊誰家。',72,'全唐诗/poet.song.236000.json','["綠沈空院雨，依約舊誰家。", "已廢惟芳草，尤深是落花。", "陰陰迷燕壘，籍籍失蜂衙。", "數點埋香玉，千枝委雪沙。", "樓殘金谷障，路合玉鈎斜。", "喚醒弓彎舞，天風即海涯。"]'),
('e6eaa558-3c9d-4dfe-8a74-8eeb4434f6c1','春景 林花掃更落','劉辰翁','宋','宋诗','song-poetry','','[]','花外愁如海，持觴爲掃林。',72,'全唐诗/poet.song.236000.json','["花外愁如海，持觴爲掃林。", "猶深猶可惜，更落更難禁。", "片片春將盡，三三徑莫尋。", "青苔纔列席，紅雨又沾襟。", "不是乘風去，應如立雪深。", "柳綿欺我老，旋拂遍能侵。"]'),
('26b18e84-d0f7-4f57-b078-87e057d7ef31','春景 棋聲花院閉','劉辰翁','宋','宋诗','song-poetry','','[]','棋聲何處起，滿院寂無譁。',72,'全唐诗/poet.song.236000.json','["棋聲何處起，滿院寂無譁。", "門閉雞鳴午，庭空蝶繞花。", "靜中時落子，高處欲驚鴉。", "枸杞籬根吠，棠梨屋角斜。", "客迷柯下路，人在橘中家。", "此樂商山似，休爭着數差。"]'),
('d1f15a92-a243-4388-a46c-5c308e852276','春景 禪房花木深','劉辰翁','宋','宋诗','song-poetry','','[]','此處少人跡，禪房深客心。',72,'全唐诗/poet.song.236000.json','["此處少人跡，禪房深客心。", "殿廊常寂寂，花木自深深。", "面壁看紅影，蒲團對綠陰。", "定回蜂欲逗，香在蝶難尋。", "棋電驚青子，茶烟出半林。", "客來參話久，隔屋聽鳴禽。"]'),
('28855b58-602d-41f4-9dc6-ac43228fa327','春景 新火起新烟','劉辰翁','宋','宋诗','song-poetry','','[]','風雨暗綿田，春愁百五天。',72,'全唐诗/poet.song.236000.json','["風雨暗綿田，春愁百五天。", "故人成故俗，新火起新烟。", "自用青楓後，何如墨突前。", "人間寒食改，天上蠟薪傳。", "當戶三星出，齊州九點連。", "人心思漢德，猶望死灰然。"]'),
('860c6335-426a-4cfd-babc-748c74c03947','春景 漢宮傳蠟燭','劉辰翁','宋','宋诗','song-poetry','','[]','寒食誰家燭，紅香蠟更鮮。',72,'全唐诗/poet.song.236000.json','["寒食誰家燭，紅香蠟更鮮。", "晶熒侯邸盛，日暮漢宮傳。", "永巷花同閉，長門柳又眠。", "人間金谷火，天上蜜脾煙。", "食客三千履，皇恩四百年。", "回思諸葛井，流涕陣圖邊。"]'),
('5dbcf2f3-5432-4503-abde-3762e56a79d4','春景 寒食四鄰清','劉辰翁','宋','宋诗','song-poetry','','[]','寒食掩柴荆，春郊無意行。',72,'全唐诗/poet.song.236000.json','["寒食掩柴荆，春郊無意行。", "極知三日近，并覺四鄰清。", "綠暗鴉銜紙，晴明笛賣餳。", "朱陳前社遠，王謝斷烟橫。", "鶴表憐城冢，鯖盤冷客卿。", "昭丘茅屋破，千載見人情。"]'),
('7218af0c-857c-4e1d-8428-a90275726f0b','春景 寒食少天色','劉辰翁','宋','宋诗','song-poetry','','[]','風雨待晴難，人間熟食盤。',72,'全唐诗/poet.song.236000.json','["風雨待晴難，人間熟食盤。", "從來天色少，偏向暮春寒。", "宮女斜偏冷，家人火自鑽。", "烟光籠綵索，雲影壓欄干。", "村落花如紙，風流絮作團。", "不能韋杜曲，見月憶長安。"]'),
('a866bcf0-2854-4577-a740-0c20a6496dc6','春景 馬上逢寒食','劉辰翁','宋','宋诗','song-poetry','','[]','寒食古來同，鄉關隔萬重。',72,'全唐诗/poet.song.236000.json','["寒食古來同，鄉關隔萬重。", "天涯俱是恨，馬上又相逢。", "雨雪臯蘭道，弓刀苜蓿峰。", "滿城看插柳，分路入澆松。", "繡嶺開門日，鄜州陷賊蹤。", "年年聞改火，雙淚下龍鍾。"]'),
('b5de66cd-b7a5-4a02-a04d-fd540f54ef63','春景 墦間','劉辰翁','宋','宋诗','song-poetry','','[]','寒食應無見，携樽炙更燔。',72,'全唐诗/poet.song.236000.json','["寒食應無見，携樽炙更燔。", "墦間迷舊陌，陌上乞吾墦。", "麟卧新華表，鴉啼古墓門。", "施施東郭客，處處樂游原。", "冷眼看鵝炙，傳家自瓦盆。", "若敖無麥飯，過者更銷魂。"]'),
('8d4d0798-06d1-4687-9883-defc9e96ebc3','春景 介山','劉辰翁','宋','宋诗','song-poetry','','[]','念舊情何及，逃虛理不還。',72,'全唐诗/poet.song.236000.json','["念舊情何及，逃虛理不還。", "不因求介子，安識是何山。", "公子何恩怨，覊臣自險艱。", "巔崖蒼莽外，烟雨有亡間。", "就使身豺虎，寧當火蒯菅。", "年年寒食雨，天亦爲潺湲。"]'),
('908ea114-3236-4404-bd69-31b238632777','春景 疏簾看弈棋','劉辰翁','宋','宋诗','song-poetry','','[]','道院無迎客，疏簾緲緲垂。',72,'全唐诗/poet.song.236000.json','["道院無迎客，疏簾緲緲垂。", "未須驚倒屣，共看弈殘棋。", "日透花陰午，風摇竹影漪。", "嘔心誰白黑，袖手見安危。", "別墅塵難到，南風管已窺。", "仙凡終似隔，彷彿記來時。"]'),
('d9c74f00-fd86-44f5-9130-54171486b534','春景 碧山晴又濕','劉辰翁','宋','宋诗','song-poetry','','[]','山色洗逾碧，昏明水墨成。',72,'全唐诗/poet.song.236000.json','["山色洗逾碧，昏明水墨成。", "相看如許濕，政似不曾晴。", "翠拂雙蛾起，青如老眼橫。", "嶺雲才斂態，峽雨復多情。", "瀑濺香爐紫，烟銷石鏡明。", "乾坤翻覆頃，蘿月吐深更。"]'),
('ffb4c6fc-e8d3-413c-938e-2c61aca27622','春景 公作送春詩','劉辰翁','宋','宋诗','song-poetry','','[]','春與公何厚，公嘗惜盛時。',72,'全唐诗/poet.song.236000.json','["春與公何厚，公嘗惜盛時。", "忍於臨別日，不作送行詩。", "自覺同遲暮，何堪賦別離。", "衰蘭行客道，芳草斷腸詞。", "明日成愁蝶，殘陽又子規。", "少年誰不省，問我獨何悲。"]'),
('2685a182-f614-4f70-9f5a-0a1631e1720f','春景 假日從時飲','劉辰翁','宋','宋诗','song-poetry','','[]','假日故應稀，逢春喜可知。',72,'全唐诗/poet.song.236000.json','["假日故應稀，逢春喜可知。", "有懷長似海，不飲亦從時。", "孺子新年喜，公家弛告嬉。", "悠悠聊復爾，每每一中之。", "對客無辭罰，看花少待遲。", "何因似山簡，暮暮習家池。"]'),
('d8374a76-478f-4550-950b-246a63a8d100','春景 潤物細無聲','劉辰翁','宋','宋诗','song-poetry','','[]','何用雨聲麤，分明潤物酥。',72,'全唐诗/poet.song.236000.json','["何用雨聲麤，分明潤物酥。", "豈惟聽不得，政自細如無。", "九陌塵難起，千林澤徧敷。", "怪如霑草露，滴不到蓬壺。", "但覺花沈醉，誰知柳索扶。", "老龍空辟歷，辛苦救焚枯。"]'),
('507c4963-3a4e-4f76-8e5d-4212dedbee53','春景 春來祇欠花','劉辰翁','宋','宋诗','song-poetry','','[]','道是春來也，春猶似未來。',72,'全唐诗/poet.song.236000.json','["道是春來也，春猶似未來。", "亦知爲日久，祇是欠花開。", "殘雪依然在，東風幾許回。", "空令一杯酒，更憶去年梅。", "萬里寒如信，千林巧莫催。", "詩成天一笑，紅綠半爭魁。"]'),
('afe5fc47-e861-4463-a137-48c50343e3f0','春景 芳草換野色','劉辰翁','宋','宋诗','song-poetry','','[]','何處尋春色，園林已斷腸。',72,'全唐诗/poet.song.236000.json','["何處尋春色，園林已斷腸。", "居然憐野草，惟此換年芳。", "殘燒回春久，香泥去路長。", "能令南浦碧，未覺五陵芳。", "拾翠迷寒食，飛紅卧夕陽。", "遥知青冢恨，南北兩茫茫。"]'),
('cc83def9-4929-4b55-906e-67df5ca740d1','春景 一雨百泉漲','劉辰翁','宋','宋诗','song-poetry','','[]','故是春晴好，冬乾已隔年。',72,'全唐诗/poet.song.236000.json','["故是春晴好，冬乾已隔年。", "一番經過雨，百道漲新泉。", "破屋移偏濕，荒陂斷復連。", "浮山通寺驛，眢井出潮田。", "地脈天能續，簷聲石亦穿。", "仇池九十九，蠟屐去無緣。"]'),
('1714a1e9-bb3f-4e72-b647-43a5c67f01e4','春景 鳥散餘花落','劉辰翁','宋','宋诗','song-poetry','','[]','風雨欺人後，枝頭已自疏。',72,'全唐诗/poet.song.236000.json','["風雨欺人後，枝頭已自疏。", "鳥啼因散去，花落是驚餘。", "衝雨知何許，流聲已瞥如。", "不應紅顫雨，猶似暗沾裾。", "青子疑彈雀，紅桃借網魚。", "開元宮更遠，王母寄誰書。"]'),
('48e1598c-b91a-4c3d-8993-ec4aa18feec2','春景 碧草生舊跡','劉辰翁','宋','宋诗','song-poetry','','[]','花下同遊迹，令人念舊驚。',72,'全唐诗/poet.song.236000.json','["花下同遊迹，令人念舊驚。", "如何春草碧，盡向客愁生。", "南浦隨人色，芳洲拾翠情。", "凌波塵渺渺，滿地綠菁菁。", "冢上何堪沒，人間總未平。", "池塘新夢破，時復下階行。"]'),
('8f0745be-1173-46b7-a24f-86ce709edaf8','春景 鶑囀謝娘慵','劉辰翁','宋','宋诗','song-poetry','','[]','春似謝娘濃，晴酣困未鬆。',72,'全唐诗/poet.song.236000.json','["春似謝娘濃，晴酣困未鬆。", "鶑從何處囀，人比向來慵。", "啼得嬌成曲，聽餘恨滿胸。", "閑看風柳絮，更問繡花茸。", "隔屋渠三折，倚屏山萬重。", "棋聲驚過鳥，敵手不曾逢。"]'),
('bd32b78b-46f1-43b1-a7c3-45dfa3a12a16','春景 詩人命屬花','劉辰翁','宋','宋诗','song-poetry','','[]','紅落臙脂井，香埋絳縷紗。',72,'全唐诗/poet.song.236000.json','["紅落臙脂井，香埋絳縷紗。", "詩人工掞藻，吾命屬渠花。", "心嘔猶堪思，山頹尚念賒。", "吟殘錦官里，醉倒玉皇家。", "愈願償春酒，郊迷擇壻車。", "江頭顛欲死，已辦鬢生華。"]'),
('a0893973-b784-4439-9abd-2f87ce1f97f5','春景 村村自花柳 其一','劉辰翁','宋','宋诗','song-poetry','','[]','御宿長楊館，南山沁水園。',72,'全唐诗/poet.song.236000.json','["御宿長楊館，南山沁水園。", "風塵猶日日，花柳自村村。", "王謝人家遠，朱陳里姓存。", "飄零香澗水，摇颺綠柴門。", "杜曲風和雨，秦人子又孫。", "細腰桃露臉，脈脈竟無言。"]'),
('84140d5f-8e7a-405c-9a49-3f525e85de02','春景 村村自花柳 其二','劉辰翁','宋','宋诗','song-poetry','','[]','亂後新烟少，村村自物華。',72,'全唐诗/poet.song.236000.json','["亂後新烟少，村村自物華。", "周遭溪上柳，爛熳路傍花。", "獨獨人沽酒，行行客賣瓜。", "絮迷三戶曲，香滿四娘家。", "清汴龍舟遠，玄都燕麥斜。", "琵琶鞍路悄，應念浣溪紗。"]'),
('72629ac4-6fbd-4335-a1a4-0ce8e9a0516c','春景 去帆春色隨','劉辰翁','宋','宋诗','song-poetry','','[]','春色終然別，開帆豈有期。',72,'全唐诗/poet.song.236000.json','["春色終然別，開帆豈有期。", "飄飄從此去，往往與之隨。", "漸可孤蓬小，能令絕岸移。", "殢人愁碧遠，到海落紅癡。", "風自無回理，潮猶有上時。", "離魂難可得，飛絮滿天涯。"]'),
('c58d9e68-1f4a-4ef3-8481-eb2333af2222','春景 寒盡怕春銷','劉辰翁','宋','宋诗','song-poetry','','[]','飛絮新烟外，東風託信遥。',72,'全唐诗/poet.song.236000.json','["飛絮新烟外，東風託信遥。", "春猶有寒否，寒盡怕春銷。", "畫閣圍紅獸，行鞭裹黑貂。", "便無三月雨，也不再花朝。", "倚翠還輕扇，飛紅共落潮。", "少年宜秉燭，莫負可憐宵。"]'),
('39029eff-c01f-4269-8827-3fb49be46a7b','春景 山歸萬古春','劉辰翁','宋','宋诗','song-poetry','','[]','萬古山如此，青青歲歲新。',72,'全唐诗/poet.song.236000.json','["萬古山如此，青青歲歲新。", "自憐看到老，未有不歸春。", "雲樹曾經別，鶑花不棄貧。", "自迎東太乙，重作葛天民。", "一燒迷千仞，三開見幾秦。", "八公花下飲，仍是少年人。"]'),
('68a0aabe-dae7-4473-a114-31620da8a0ca','春景 池塘生春草','劉辰翁','宋','宋诗','song-poetry','','[]','滿眼成新趣，池塘午夢驚。',72,'全唐诗/poet.song.236000.json','["滿眼成新趣，池塘午夢驚。", "青春何日到，芳草滿前生。", "縠縠東風起，波波兩剪橫。", "翠鈿如可拾，仙藥不知名。", "轉步玉鈎合，幾時珠履行。", "平陂青似海，無處認昆明。"]'),
('fe0c4547-ffb3-4db5-9a47-caba02bd92ee','春景 春風花草香','劉辰翁','宋','宋诗','song-poetry','','[]','高下花成谷，烟綿草際空。',72,'全唐诗/poet.song.236000.json','["高下花成谷，烟綿草際空。", "以香爲世界，布馥是春風。", "駘蕩蛛絲外，顛狂蝶夢中。", "汀洲仙藥市，天地錦薰籠。", "澧浦遺余綠，昌州絕世紅。", "餘芳猶可藉，應恨耿匆匆。"]'),
('72db2451-d08f-4976-bee5-9c1dd3c844e9','春景 閑院綠陰生','劉辰翁','宋','宋诗','song-poetry','','[]','花院苔空積，遊絲若有情。',72,'全唐诗/poet.song.236000.json','["花院苔空積，遊絲若有情。", "斷無珠履迹，閑見綠陰生。", "縹緲朱簾悄，丁東玉漏鳴。", "隔窗梅子落，繞屋笋竿成。", "幾日落紅雨，數聲深處鶑。", "午雞人睡起，繞水看魚行。"]'),
('448404ca-74e8-4c3a-9642-1edb334b3dd6','春景 閶闔開黄道','劉辰翁','宋','宋诗','song-poetry','','[]','閶闔祥光起，班行好語催。',72,'全唐诗/poet.song.236000.json','["閶闔祥光起，班行好語催。", "青郊隨候應，黄道似初開。", "夢繞天門去，風從震地回。", "東西行白日，南北驗清臺。", "曉殿分龍角，春城轉斗魁。", "中天符四七，人物萬方來。"]'),
('4c032ae3-be9b-472a-a151-a894124eb0e4','春景 衣冠拜紫宸','劉辰翁','宋','宋诗','song-poetry','','[]','萬古衣冠舊，三朝曆數新。',72,'全唐诗/poet.song.236000.json','["萬古衣冠舊，三朝曆數新。", "青皇來遠道，紫袖拜嚴宸。", "花日明簪冕，槐雲舞佩紳。", "昭容當檻曉，宰相賀班春。", "索令分同列，傳呼掖老臣。", "漢儀當日事，江漢四朝人。"]'),
('3d790dba-8364-4dc5-a403-1dc3d974fce8','春景 新年賀太平 其一','劉辰翁','宋','宋诗','song-poetry','','[]','亂向殘年定，東風息戰塵。',72,'全唐诗/poet.song.236000.json','["亂向殘年定，東風息戰塵。", "太平如可待，相見賀從新。", "自笑屠蘇我，誰吹畫角秦。", "幾人天寶舊，重賞後元春。", "賣釧猶堪醉，簪花不恨貧。", "淵明今甲子，猶是晉時人。"]'),
('15499232-4d56-4262-a904-51b4d32f1b60','春景 新年賀太平 其二','劉辰翁','宋','宋诗','song-poetry','','[]','相過賀新元，干戈且息肩。',72,'全唐诗/poet.song.236000.json','["相過賀新元，干戈且息肩。", "不圖垂老日，還見太平年。", "灰向昆明盡，春從待漏傳。", "衣冠禾黍地，簫鼓杏花天。", "燈市嬉遺老，旗亭卧醉仙。", "山林聞好語，天下米三錢。"]'),
('b8a72d78-0f87-4d71-8d3f-ad7b855b2609','春景 明月逐人來','劉辰翁','宋','宋诗','song-poetry','','[]','人影光相亂，月明燈市開。',72,'全唐诗/poet.song.236000.json','["人影光相亂，月明燈市開。", "依依隨馬去，故故逐人來。", "勝賞春三五，流光酒一杯。", "爲君分綺席，同我上瑶臺。", "扶路傾相就，分襟逝却回。", "玉山人醉矣，健到莫驚猜。"]'),
('e3f374d5-816b-49c8-bfb7-54e65bc9976d','春景 風起春燈亂','劉辰翁','宋','宋诗','song-poetry','','[]','故是春風起，香塵暖未曾。',72,'全唐诗/poet.song.236000.json','["故是春風起，香塵暖未曾。", "暮寒驚翠袖，春影亂華燈。", "泠浸朱門月，吹成碧海冰。", "沙河三五夜，火樹幾千層。", "金炬開蓮島，銀花颭玉繩。", "一聲清蹕遠，冷落內前棚。"]'),
('4f245f49-d116-4e97-8280-5ca07c9c8038','春景 溪壑回春姿','劉辰翁','宋','宋诗','song-poetry','','[]','雲擁千溪斷，霜溪萬壑衰。',72,'全唐诗/poet.song.236000.json','["雲擁千溪斷，霜溪萬壑衰。", "自從回煖景，依舊是春姿。", "晴日雲千疊，東風雨一池。", "還他新歲好，似我少年時。", "錦水桃千障，巫山柳十眉。", "時同天一笑，不敢恨衰遲。"]'),
('aecdc976-5ced-4654-8e49-e43d2b3b34c3','春景 暗水流花徑','劉辰翁','宋','宋诗','song-poetry','','[]','日出習池遊，晴簷水不收。',72,'全唐诗/poet.song.236000.json','["日出習池遊，晴簷水不收。", "幾回經草暗，一逕带花流。", "汩汩何從至，青青自欲浮。", "但疑紅雨漲，不似御溝愁。", "靜聽鳴金谷，行迷失玉鈎。", "凌波羅襪潤，大是斷橋頭。"]'),
('d637e663-6a03-45b9-bd9b-2d1849e80155','春景 小水細通池 其一','劉辰翁','宋','宋诗','song-poetry','','[]','過雨山泉潤，悠悠小水同。',72,'全唐诗/poet.song.236000.json','["過雨山泉潤，悠悠小水同。", "未嫌來脈細，更與曲池通。", "花徑頻違濕，苔溝暗入叢。", "却看萍破碧，未覺葉流紅。", "澗壑千枝曲，乾坤一鏡中。", "所嗟瓜地遠，不得灌連筒。"]'),
('fca547f2-5c6b-4ad0-918f-f7326c58969c','春景 小水細通池 其二','劉辰翁','宋','宋诗','song-poetry','','[]','小小回堤水，花陰寸步隨。',72,'全唐诗/poet.song.236000.json','["小小回堤水，花陰寸步隨。", "細難爲灌圃，長是曲通池。", "乳竇仍從出，雲根觸處滋。", "又添晴滴瀝，欲漲碧漣漪。", "新綠常如雨，流紅未見詩。", "昆明鯨背淺，盡日絮溝遲。"]'),
('428006cd-3a67-49c0-b049-e176fc70fb9b','春景 仰蜂粘落絮','劉辰翁','宋','宋诗','song-poetry','','[]','採採香無據，遊蜂與絮兼。',72,'全唐诗/poet.song.236000.json','["採採香無據，遊蜂與絮兼。", "輕吹無影落，仰抱有時粘。", "欹蕊棲難穩，垂跗採未然。", "花鬚紛更辨，柳雪誤相沾。", "未礙餐能飽，貪看嚥欲甜。", "吟安時失笑，往往似吾髯。"]'),
('90ab7537-ab69-4dcb-9837-7df8951ebb39','春景 綠陰生晝寂','劉辰翁','宋','宋诗','song-poetry','','[]','深院停春雨，庭空鳥不鳴。',72,'全唐诗/poet.song.236000.json','["深院停春雨，庭空鳥不鳴。", "自然清晝寂，盡是綠陰生。", "滿眼成青幄，無人惜絳英。", "輕風低鼎篆，遲日上簾旌。", "遠水明鸂鶒，平欄繞杜蘅。", "小窗臨晉帖，悞落剪刀聲。"]'),
('308d95e0-f161-4b6f-8834-1aa02f434271','春景 燕子家家入','劉辰翁','宋','宋诗','song-poetry','','[]','燕子來何晚，城春換物華。',72,'全唐诗/poet.song.236000.json','["燕子來何晚，城春換物華。", "逢人能語語，隨意入家家。", "故宇何堪戀，朱簾可得遮。", "王門深巷悄，謝墅夕陽斜。", "是處隨芳草，無情似柳花。", "興亡真閲遍，盡是主人差。"]'),
('d51edc44-ce25-4563-bf37-42312271e651','春景 春燕巢林','劉辰翁','宋','宋诗','song-poetry','','[]','燕子故依人，重來跡已陳。',72,'全唐诗/poet.song.236000.json','["燕子故依人，重來跡已陳。", "主樓空舞地，林木自巢春。", "無復郊迎乙，惟應語訴辛。", "乾坤一枝土，風雨畫梁身。", "荒草歌塵遠，頹松社屋新。", "尋常空巷裏，憶着舊家貧。"]'),
('c612169f-0bbd-48e9-b4ef-ae5c69d2d266','春景 浙江花木深','劉辰翁','宋','宋诗','song-poetry','','[]','遊子江南老，美人浙水陰。',72,'全唐诗/poet.song.236000.json','["遊子江南老，美人浙水陰。", "風光何冉冉，花木自深深。", "蘋渚藏妃怨，蘭臯寄屈吟。", "飄香迷去路，種子約青林。", "遠浦歸帆興，芳洲來暮心。", "天寒人倚竹，目斷去鴻沈。"]'),
('09011702-e17b-40ba-aab4-1fbb198b4721','春景 孤舟亂春華 其一','劉辰翁','宋','宋诗','song-poetry','','[]','天地孤舟客，東風是處家。',72,'全唐诗/poet.song.236000.json','["天地孤舟客，東風是處家。", "偶然乘興遠，不擬亂春華。", "牢落無茶具，飄零自釣槎。", "誤將青篛笠，撐入碧桃花。", "路斷雲相覓，溪深柳又斜。", "忽聞雞犬近，隨處有桑麻。"]'),
('8a8d58fe-75df-47ff-a521-6df5a06ae45e','春景 孤舟亂春華 其二','劉辰翁','宋','宋诗','song-poetry','','[]','罨畫來兼往，孤舟自若耶。',72,'全唐诗/poet.song.236000.json','["罨畫來兼往，孤舟自若耶。", "悠悠信谿路，籍籍亂春華。", "今古三高客，乾坤一葉家。", "泛桃衝雨過，穿柳带烟斜。", "下水隨飛燕，移梢爲惜花。", "日斜歸興急，恐或見胡麻。"]'),
('1c863c56-2138-4d43-9cfd-596e00aa7b34','春景 孤舟亂春華 其三','劉辰翁','宋','宋诗','song-poetry','','[]','晴日孤舟好，溪流带岸斜。',72,'全唐诗/poet.song.236000.json','["晴日孤舟好，溪流带岸斜。", "浮游忘世慮，爛熳亂春華。", "朝共漁穿港，暮隨鷗宿沙。", "却知桃有路，惟見柳無涯。", "蓑舞村村酒，罾歌處處花。", "羣仙驚再見，留宿武陵家。"]'),
('d688782d-5923-448b-85c8-ee99f61b6ffc','春景 孤舟亂春華 其四','劉辰翁','宋','宋诗','song-poetry','','[]','有客孤舟裏，風平日又嘉。',72,'全唐诗/poet.song.236000.json','["有客孤舟裏，風平日又嘉。", "未須憐歲晚，從此亂春華。", "自扣舷三版，相將水一涯。", "前村隨柳色，昨夜宿桃花。", "鷗浴波翻錦，漁歌影入霞。", "江頭稠杏暗，子美四娘家。"]'),
('1eddf43d-8763-4d3f-b6d8-855faf418916','春景 遊絲白日靜','劉辰翁','宋','宋诗','song-poetry','','[]','靜似長門裏，初晴未暑時。',72,'全唐诗/poet.song.236000.json','["靜似長門裏，初晴未暑時。", "悠悠銷白日，冉冉上遊絲。", "白髮因風起，青蟲映戶垂。", "牆陰雙蝶遠，花影一簾遲。", "新壘乾泥絮，晴衙散蜜脾。", "鳥驚梅子落，深院客爭棋。"]'),
('3982cfd5-c10f-4cf5-920e-5baf657a1feb','春景 柳葉暗金溝','劉辰翁','宋','宋诗','song-poetry','','[]','輦路垂垂柳，昆明寂寂流。',72,'全唐诗/poet.song.236000.json','["輦路垂垂柳，昆明寂寂流。", "近天高翠葉，映日暗金溝。", "眠起當前殿，萎蕤拂御舟。", "鎖成三閣暮，流出六宮愁。", "桐影題難立，楊花宕不收。", "至今寒食雨，墮淚曲江頭。"]'),
('aa317683-9c1a-4a49-938d-7c8e3dc7dfbe','春景 花飛減却春','劉辰翁','宋','宋诗','song-poetry','','[]','老子情如海，花無醉後新。',72,'全唐诗/poet.song.236000.json','["老子情如海，花無醉後新。", "飛來如許雪，減却不多春。", "輕薄隨流水，顛狂落近鄰。", "猶寒猶未晚，半雨半成塵。", "拾翠危無路，殘紅老得人。", "清晨添酒量，日日是芳辰。"]'),
('10fb230e-568d-4217-8c96-43ee9418f0f5','春景 城春草木深','劉辰翁','宋','宋诗','song-poetry','','[]','春又不知暮，城荒獨至今。',72,'全唐诗/poet.song.236000.json','["春又不知暮，城荒獨至今。", "樓臺花下遠，草木雨中深。", "寒食無烟綠，頹垣有月侵。", "荒苔隨意古，落子又成陰。", "鄰笛殘兵淚，胡琴故國心。", "廢興天不語，鐘鼓遍園林。"]'),
('e3ee062c-c185-458f-b178-83b73e40bb55','春景 春色在鄰家','劉辰翁','宋','宋诗','song-poetry','','[]','春色闌珊去，朱門懶夢華。',72,'全唐诗/poet.song.236000.json','["春色闌珊去，朱門懶夢華。", "悠悠看蝶翅，往往在鄰家。", "暖日明金谷，光風媚浣沙。", "似聞携手笑，疑有隔牆花。", "望眼穿銀漢，香塵透綠紗。", "是誰窺宋玉，憔悴一枝斜。"]'),
('34b03e06-6d47-40b8-90a5-0ab3fbfbc9b7','春景 吹面受和風','劉辰翁','宋','宋诗','song-poetry','','[]','寒曾欺我倒，今日是和風。',72,'全唐诗/poet.song.236000.json','["寒曾欺我倒，今日是和風。", "吹面濃春酒，開懷受化工。", "未知來暖律，政似識癯翁。", "大袖猶堪滿，衰顔欲更紅。", "鬢如新柳動，鼻與暗香通。", "天上知何信，千花一笑中。"]'),
('694d36c2-b6f4-4eb7-86ee-7c5fb5a13a65','春景 火樹銀花合','劉辰翁','宋','宋诗','song-poetry','','[]','星炬亂林鴉，火城標赤霞。',72,'全唐诗/poet.song.236000.json','["星炬亂林鴉，火城標赤霞。", "端門開璧月，散樹合銀花。", "光燄摇千尺，扶疏轉九華。", "昭回三閣近，鑿落萬枝斜。", "玉李迷天象，金蓮出內家。", "龍光如海蜃，猶有誤連車。"]'),
('8486f644-c0b1-4681-9203-8ce39ed11785','夏景 薰風自南來','劉辰翁','宋','宋诗','song-poetry','','[]','當年唐殿閣，何似道人庵。',72,'全唐诗/poet.song.236000.json','["當年唐殿閣，何似道人庵。", "閑日長如此，薰風來自南。", "清香吹不斷，大暑故如惔。", "靜見花陰午，凉添竹徑三。", "客遮前席坐，人卧北窗酣。", "別墅棋邊急，閑將赤壁談。"]'),
('03fd9763-a350-4af4-91ba-b88897232caf','夏景 夏雨生衆綠 其一','劉辰翁','宋','宋诗','song-poetry','','[]','入夏可曾晴，陰陰衆綠成。',72,'全唐诗/poet.song.236000.json','["入夏可曾晴，陰陰衆綠成。", "但驚春盡去，誰信雨中生。", "一月須梅潤，千林但葉聲。", "荷邊蒲猗儺，桑外笋崢嶸。", "芳草非無恨，新條各向榮。", "秧田禾似浪，滿眼幾時平。"]'),
('c69494c2-eef8-4e15-8582-51e4fe32ad2b','夏景 夏雨生衆綠 其二','劉辰翁','宋','宋诗','song-poetry','','[]','無人嫌夏雨，衆木共欣榮。',72,'全唐诗/poet.song.236000.json','["無人嫌夏雨，衆木共欣榮。", "已辦黄梅熟，還將綠葉生。", "送春無物色，盡日是簷聲。", "處處桑麻長，陰陰桃李成。", "風翻蒲水白，烟共草天平。", "山色沈冥久，朝來兩黛橫。"]'),
('ced48d2a-9d77-4b48-93d4-db316c2b5e97','夏景 雨過苔花潤','劉辰翁','宋','宋诗','song-poetry','','[]','雨過殘春遠，晴天半入梅。',72,'全唐诗/poet.song.236000.json','["雨過殘春遠，晴天半入梅。", "草根餘落照，花潤只深苔。", "山共朱簾捲，庭無蠟屐來。", "翠錢流地滿，珠靨照人開。", "寂寂承殘霤，青青繞廢臺。", "唾茸宮壁在，殘月照餘哀。"]'),
('fbd0b1df-8472-47aa-801d-16c5024b05c0','夏景 既雨晴亦佳','劉辰翁','宋','宋诗','song-poetry','','[]','既雨失陰霾，天憐萬竈蛙。',72,'全唐诗/poet.song.236000.json','["既雨失陰霾，天憐萬竈蛙。", "是雖猶暑潤，亦自覺晴佳。", "早見瓢翻海，今無漏透階。", "但能開晚景，麤足慰人懷。", "山翠光浮玉，塗泥軟襯鞋。", "一簾花露影，醉眼爲渠揩。"]'),
('3c986bb8-6a0c-428e-9081-ffb4216e4f71','夏景 樹濕風凉進','劉辰翁','宋','宋诗','song-poetry','','[]','樹晚晴猶濕，好風如故長。',72,'全唐诗/poet.song.236000.json','["樹晚晴猶濕，好風如故長。", "翛然林下意，進似雨時凉。", "坐覺茅容徙，來看呂政忙。", "飄蕭初似暑，淅瀝轉成霜。", "倚袖嵐添翠，題秋葉欲黄。", "不知兼露下，河漢芰荷香。"]'),
('559a1b65-ea57-46a5-813c-119eb24a99c3','夏景 松凉夏健人 其一','劉辰翁','宋','宋诗','song-poetry','','[]','松影夏天雲，凉開一院新。',72,'全唐诗/poet.song.236000.json','["松影夏天雲，凉開一院新。", "若無如此暑，可以健於人。", "風外潮聲起，林間客欠伸。", "自憐三伏日，重得百年身。", "鶴唳如輕舉，兒扶更怒嗔。", "下山逢急雨，爲洗覆車塵。"]'),
('bd9e2432-2131-4a30-bf02-3eb4c0d67ada','夏景 松凉夏健人 其二','劉辰翁','宋','宋诗','song-poetry','','[]','天地若爲容，凉陰何處逢。',72,'全唐诗/poet.song.236000.json','["天地若爲容，凉陰何處逢。", "困人惟夏日，健我是雲松。", "雨立三千丈，風生一萬重。", "如餐華峰藕，不藉葛陂龍。", "脫帽蒼虬笑，披衣病鶴鬆。", "月明天似水，歸路踏芙蓉。"]'),
('d8f4b162-35a6-4b92-bb76-1cfd19139f6e','夏景 露頂灑松風','劉辰翁','宋','宋诗','song-poetry','','[]','野處闕過逢，投巾仰露空。',72,'全唐诗/poet.song.236000.json','["野處闕過逢，投巾仰露空。", "蕭蕭松下老，灑灑頂門風。", "暑不容章甫，天猶念禿翁。", "昂霄潮洶洶，落雪鬢蓬蓬。", "搔首平生事，忘形半醉中。", "蓬萊歸去路，潦倒笑臣同。"]'),
('d5c70747-48f2-4934-b86b-104d1f1a118b','夏景 清風松下來','劉辰翁','宋','宋诗','song-poetry','','[]','狹世清風少，清風不受催。',72,'全唐诗/poet.song.236000.json','["狹世清風少，清風不受催。", "惟應松下有，肯向坐間來。", "襟袖元如水，山林自少埃。", "遂驚弘景宅，不是楚王臺。", "柳巷無人掃，柴門盡日開。", "是誰前喝道，空遣鶴飛回。"]'),
('527ad96f-d86f-46e3-a750-f9f9445e030b','夏景 林風凉不絕','劉辰翁','宋','宋诗','song-poetry','','[]','不可居無竹，清風動滿林。',72,'全唐诗/poet.song.236000.json','["不可居無竹，清風動滿林。", "長無如夏日，凉不絕予襟。", "安得秋如許，能令午正陰。", "兩間何舋舋，三徑自深深。", "簟玉翻如水，簷冰語至今。", "故人千萬里，明月兩知心。"]'),
('e713cc77-b19f-4b5c-8ca9-6be9196d8e0f','夏景 喬木生夏凉','劉辰翁','宋','宋诗','song-poetry','','[]','何可無喬木，多年雨露成。',72,'全唐诗/poet.song.236000.json','["何可無喬木，多年雨露成。", "是間凉意別，長夏綠陰生。", "日度雲旗影，風含澗水聲。", "能令霜六月，不待月三更。", "翠幄宜琴枕，枯棋就石枰。", "五楸朝又暮，故國可勝情。"]'),
('52cda013-77d9-4f76-b324-017d5a89d590','夏景 清室夏含霜','劉辰翁','宋','宋诗','song-poetry','','[]','一室蘭香滿，陰陰夏木成。',72,'全唐诗/poet.song.236000.json','["一室蘭香滿，陰陰夏木成。", "炎光雖自酷，霜意自含清。", "珮玉傳風馬，鈎簾下水精。", "燕臺無六月，楚戶忽三更。", "冷袖藏冰藕，凉蟾滿露莖。", "江湖無雁信，詩鬢自先驚。"]'),
('544247e9-00a2-4cce-823e-4a96984ee64f','夏景 凉引簟先秋','劉辰翁','宋','宋诗','song-poetry','','[]','八尺橫斜簟，寒光凝不流。',72,'全唐诗/poet.song.236000.json','["八尺橫斜簟，寒光凝不流。", "引教凉到我，坐覺意先秋。", "溽暑收梅雨，清風度竹樓。", "湘紋殊似水，班扇未應愁。", "冷逼金莖潤，溫便玉臂柔。", "頗哀城市悄，斗米換衾裯。"]'),
('c59fa34b-3efa-4f88-a87b-45f36831c323','夏景 盛夏火爲日','劉辰翁','宋','宋诗','song-poetry','','[]','日在天無二，明明夏盛時。',72,'全唐诗/poet.song.236000.json','["日在天無二，明明夏盛時。", "到今雖可愛，非火孰能爲。", "謾把薰絃語，難禁坐甑炊。", "未應一杯水，能沃九華枝。", "王屋飛猶在，崑岡事可知。", "未須頻夢竈，倏忽看崦嵫。"]'),
('276659e1-0bb0-4b96-a528-bcd589ff79f6','夏景 蓮房墜粉紅','劉辰翁','宋','宋诗','song-poetry','','[]','蓮欲成房去，三三兩兩空。',72,'全唐诗/poet.song.236000.json','["蓮欲成房去，三三兩兩空。", "摘來中有子，墜處粉尤紅。", "已鏤冰爲藕，誰將翠作蓬。", "半妝摇越棹，一水膩秦宮。", "濯濯含秋露，亭亭立曉風。", "么荷因見憶，憔悴感青銅。"]'),
('b2b61778-82ba-459c-ae62-bd9670bdd273','夏景 竹影金瑣碎','劉辰翁','宋','宋诗','song-poetry','','[]','竹可淋漓畫，難將竹影臨。',72,'全唐诗/poet.song.236000.json','["竹可淋漓畫，難將竹影臨。", "寂寥誰布地，瑣碎總如金。", "密處開爲徑，疏時舞又陰。", "汗青銷作字，翡翠屑成林。", "弄月平分破，臨風鑿落斟。", "鏘然聲入耳，忽認是徽琴。"]'),
('2829ed50-7a11-4f36-afbc-dfc82696d5d7','夏景 炎赫衣流汗','劉辰翁','宋','宋诗','song-poetry','','[]','暑綌衣能幾，長流汗似痁。',72,'全唐诗/poet.song.236000.json','["暑綌衣能幾，長流汗似痁。", "惶惶何慄慄，赫赫復炎炎。", "安得三庚度，猶如十日兼。", "坐驚慚背浹，不是淚襟霑。", "湯餠何堪試，煎茶可更添。", "可人嬌熨玉，頻起立風簷。"]'),
('c831adb2-010c-42d6-ba84-19adb39cf956','夏景 夢回蓮葉雨','劉辰翁','宋','宋诗','song-poetry','','[]','萬葉勝花開，蓮香雨送來。',72,'全唐诗/poet.song.236000.json','["萬葉勝花開，蓮香雨送來。", "欲知凉可愛，政是夢初回。", "未擬華胥轉，誰將繡戶推。", "棹歌摇別浦，裙影濕陽臺。", "天上霓裳斷，人間羯鼓催。", "酒醒莖露渴，狂引碧筒杯。"]'),
('978b7c17-dc9e-4f04-a76e-4934e00f8f71','夏景 衣冷欲裝綿 其一','劉辰翁','宋','宋诗','song-poetry','','[]','老厭人間熱，單衣就冷泉。',72,'全唐诗/poet.song.236000.json','["老厭人間熱，單衣就冷泉。", "不知清到骨，故欲轉裝綿。", "蘿月滿襟雪，松風半臂仙。", "頓疏桃竹瑩，擬就柳花眠。", "倚倦思燕玉，全生願蜀氈。", "溫湯無去路，搔首聽潺湲。"]'),
('2801a4d4-1911-4d64-a054-fd791810cc29','夏景 衣冷欲裝綿 其二','劉辰翁','宋','宋诗','song-poetry','','[]','石洞元無暑，泉聲灑面凉。',72,'全唐诗/poet.song.236000.json','["石洞元無暑，泉聲灑面凉。", "衣疑中夜冷，綿欲此時裝。", "灑灑驚荷雨，披披變葛霜。", "擬將洴澼絖，換却薄羅裳。", "中道憐班女，溫言憶楚王。", "驪山在何許，我更念溫湯。"]'),
('6cfe6e82-e3cd-4556-97d7-df4afd1371f0','夏景 褦襶子','劉辰翁','宋','宋诗','song-poetry','','[]','俗子高門走，那知物意嫌。',72,'全唐诗/poet.song.236000.json','["俗子高門走，那知物意嫌。", "婆娑中避暑，褦襶早趨炎。", "楚楚朝衣格，峨峨古帽簷。", "夤緣三伏謁，瞻仰上官嚴。", "尚說毛寒慄，寧辭背汗沾。", "寄言鄉里者，貸我北窗眠。"]'),
('23106164-8ec6-47fc-9226-b4baf2187bc9','夏景 清泉潔塵襟','劉辰翁','宋','宋诗','song-poetry','','[]','是事不堪聞，清泉獨可親。',72,'全唐诗/poet.song.236000.json','["是事不堪聞，清泉獨可親。", "翛然携鬢影，聊以潔塵襟。", "簾瀉千年雨，藍拖百尺紳。", "能令肝肺雪，更遣芰荷新。", "京洛昏沈夢，江湖淡蕩身。", "一瓢明月燕，併洗脫鞾嗔。"]'),
('66b24ba1-d73b-42f5-82cd-36bc69fbce5d','夏景 涉江採芙蓉','劉辰翁','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','夢破芙蓉雨，蛾眉瑣綠窗。',72,'全唐诗/poet.song.236000.json','["夢破芙蓉雨，蛾眉瑣綠窗。", "悠悠思遠道，采采涉長江。", "北渚浮湘水，西興渡越邦。", "波穿紅錦亂，影轉畫橈雙。", "花路迷相問，菱歌遠失腔。", "扣舷驚水鳥，晼晚笑吳憃。"]'),
('5aa007b9-dd82-4bc0-833c-ffafaf66eddd','夏景 公子調冰水','劉辰翁','宋','宋诗','song-poetry','','[]','盛世佳公子，明光避暑曾。',72,'全唐诗/poet.song.236000.json','["盛世佳公子，明光避暑曾。", "調冰初入水，和水亦成冰。", "鳴佩朝儀鳳，揚鞲夕臂鷹。", "汲來金碗脫，攪碎玉崚嶒。", "一吸風林壑，重傾雪肺膺。", "瓊姬持袖舉，疑飲露盤昇。"]'),
('29d824be-5adf-4a90-95fb-2a70b7c3634d','夏景 炎宵惡明燭','劉辰翁','宋','宋诗','song-poetry','','[]','畏日纔宵匿，誰教燭又添。',72,'全唐诗/poet.song.236000.json','["畏日纔宵匿，誰教燭又添。", "明雖無可惡，看得故成炎。", "漏永風如禁，膏殘飲未厭。", "萬枝何用許，一點有人嫌。", "蛾命那知惜，蟲花懶復占。", "吳牛應自笑，何事畏銀蟾。"]'),
('0fe7eabb-58b9-498b-8d0b-e51040de20fb','夏景 行雲遞崇高','劉辰翁','宋','宋诗','song-poetry','','[]','自不容無雨，行雲盡日勞。',72,'全唐诗/poet.song.236000.json','["自不容無雨，行雲盡日勞。", "來來方汗漫，遞遞看崇高。", "一氣埋飛鳥，層陰壓戴鰲。", "前驅淝水陣，後至浙江濤。", "羊角天帆席，龍身海桔槔。", "鴻蒙驚久別，握手重相遭。"]'),
('fffc17a5-c1f8-4dca-87a0-48a79fb8a56d','夏景 訟風伯','劉辰翁','宋','宋诗','song-poetry','','[]','豈敢訟穹穹，何堪敗願豐。',72,'全唐诗/poet.song.236000.json','["豈敢訟穹穹，何堪敗願豐。", "雲乎難致雨，伯也實司風。", "長是垂將合，吹之使不同。", "不思商怨後，但霸楚稱雄。", "已脫知臣罪，不誅無歲功。", "皇恩懲使悔，終念小心仝。"]'),
('e4f0198b-d715-4468-9c7c-7da039bd4460','夏景 亭深到芰香','劉辰翁','宋','宋诗','song-poetry','','[]','十里荒寒地，亭空暑不侵。',72,'全唐诗/poet.song.236000.json','["十里荒寒地，亭空暑不侵。", "能令塵土外，更到芰荷深。", "水閣臨風迥，蓮舟隔浦尋。", "紅妝風四面，翠倚月中心。", "此處閑搔首，何人泣露襟。", "拍浮宜有酒，亂挽碧筒斟。"]'),
('be8abb56-40b9-4dd2-bb07-9aeffa7fa3bb','夏景 蟬聲集古寺','劉辰翁','宋','宋诗','song-poetry','','[]','此寺創何年，人間幾變遷。',72,'全唐诗/poet.song.236000.json','["此寺創何年，人間幾變遷。", "山空千萬古，聲集兩三蟬。", "振木繰餘繭，憑風咽斷絃。", "助成騷國晚，驚破少林禪。", "喧寂聞塵外，炎凉落照邊。", "客來悲世事，蟲語暮鐘連。"]'),
('67e78fc8-f1b2-4dfa-8ea9-abdb665be17d','夏景 綠荷雨跳珠','劉辰翁','宋','宋诗','song-poetry','','[]','荷外雨瀟瀟，舟如泊斷橋。',72,'全唐诗/poet.song.236000.json','["荷外雨瀟瀟，舟如泊斷橋。", "忽驚紅粉亂，又見綠珠跳。", "萬葉明蒼水，輕風問步摇。", "疏疏霑羽蓋，點點濺鮫綃。", "玉露明金掌，紅妝濕翠翹。", "珮痕留不得，立地使魂銷。"]'),
('26d1621f-737c-4d50-9eed-47d4a221475d','夏景 扇枕','劉辰翁','宋','宋诗','song-poetry','','[]','千古一黄香，庭萱晝日長。',72,'全唐诗/poet.song.236000.json','["千古一黄香，庭萱晝日長。", "枕閑非受熱，扇舉欲先凉。", "畏暑侵支髮，摇風願滿堂。", "恨無寒水玉，琢在碧紗牀。", "泉澗心如棘，瑶池鬢已霜。", "如何荀奉倩，只在玉人傍。"]'),
('6ea6a976-79e3-4466-841a-bed267b0db26','夏景 雲雨覺虛無','劉辰翁','宋','宋诗','song-poetry','','[]','天欲今朝雨，雲如滿八區。',72,'全唐诗/poet.song.236000.json','["天欲今朝雨，雲如滿八區。", "居然同願望，如此竟虛無。", "鵬運風猶黑，龍光電又驅。", "遂成神女夢，誤擬阿香呼。", "酷吏踰前憯，餘民絕望蘇。", "皇心終不測，變化屬須臾。"]'),
('c647a396-66d5-4788-be69-992d5698df64','夏景 高風動秋聲','劉辰翁','宋','宋诗','song-poetry','','[]','萬竅忽爭號，南風動地豪。',72,'全唐诗/poet.song.236000.json','["萬竅忽爭號，南風動地豪。", "此聲何處起，到地似秋高。", "草木波頹靡，乾坤暑戰鏖。", "有人推戶外，無葉下庭皋。", "寒扇憐孤影，征鞍感二毛。", "豪鷹雙角聳，無計剪蓬蒿。"]'),
('bf55cdf0-1af7-4a06-9805-c4e860d04c25','夏景 清風左右至','劉辰翁','宋','宋诗','song-poetry','','[]','風於萬里外，飛動故人情。',72,'全唐诗/poet.song.236000.json','["風於萬里外，飛動故人情。", "如許殷勤至，居然左右清。", "吹潮成雪色，入竹已秋聲。", "珮玉丁丁起，臺襟翼翼生。", "玉川從此去，列子御之行。", "邂逅浮丘老，相携上五城。"]'),
('ba6cf087-6f30-4fbc-b7f5-59ffebae84c5','秋景 乞巧文','劉辰翁','宋','宋诗','song-poetry','','[]','能拙吾無比，高靈昔有聞。',72,'全唐诗/poet.song.236000.json','["能拙吾無比，高靈昔有聞。", "不知天下巧，乞以世間文。", "果列空庭露，香浮入漢雲。", "天孫何冉冉，柳子蓋云云。", "有說能要我，無才可贈君。", "絳衣持節後，窮達竟何分。"]'),
('0bd14e27-5ce2-4baa-9ac2-373231a0ed36','秋景 曬書','劉辰翁','宋','宋诗','song-poetry','','[]','芸香天上宴，不到野人居。',72,'全唐诗/poet.song.236000.json','["芸香天上宴，不到野人居。", "見說星期夕，閑將腹曬書。", "笑人操犢鼻，容我辟蟫魚。", "小勿欺椰子，中從著石渠。", "從他便是懶，乞汝巧相如。", "此日何堪負，餘暄獻納疏。"]'),
('8fd89da4-526e-46e7-baf1-d05ec2645f1d','秋景 牛女年年渡','劉辰翁','宋','宋诗','song-poetry','','[]','牛女是誰傳，靈橋不待船。',72,'全唐诗/poet.song.236000.json','["牛女是誰傳，靈橋不待船。", "昔年曾此渡，每渡似初年。", "此夕須停織，何人更服牽。", "星期無了日，河水尚依然。", "歲晚長疏隔，人間早棄捐。", "瑶池人獨處，搔首待君還。"]'),
('cd87f35c-22df-4a98-95c8-7c81ec22ba04','秋景 機絲虛夜月','劉辰翁','宋','宋诗','song-poetry','','[]','不見機邊女，當時獨月知。',72,'全唐诗/poet.song.236000.json','["不見機邊女，當時獨月知。", "坐令如此夜，虛却理殘絲。", "繰得扶桑繭，張成錦字詞。", "弦光空到曉，花影不侵帷。", "尺寸知何用，須臾即別離。", "小窗思婦懶，不是恤周嫠。"]'),
('038a06ef-c088-462f-86e7-1c3eaf79150d','秋景 秋空日凌凌','劉辰翁','宋','宋诗','song-poetry','','[]','最是秋空恝，秋田訴不譍。',72,'全唐诗/poet.song.236000.json','["最是秋空恝，秋田訴不譍。", "夜占常悄悄，日復覺凌凌。", "何似春工惻，無端地氣騰。", "雙眉頻望極，八翼愈難昇。", "其雨今若此，如雲亦未曾。", "小心風不上，涕泗日沾膺。"]'),
('fe28140c-7f87-434e-9171-6177833f2704','秋景 吹笛月明中','劉辰翁','宋','宋诗','song-poetry','','[]','何處吹長笛，千年恨未終。',72,'全唐诗/poet.song.236000.json','["何處吹長笛，千年恨未終。", "關山人去後，秋夜月明中。", "曠野參差久，寒江滉漾通。", "曲終郿縣塢，怨徹廣寒宮。", "海外陰晴異，天涯慷慨同。", "江南回首處，歌罷水流東。"]'),
('068ec840-3717-4e3a-86f7-55cfe737ed0a','秋景 清輝玉臂寒','劉辰翁','宋','宋诗','song-poetry','','[]','待得清輝滿，中秋兩地看。',72,'全唐诗/poet.song.236000.json','["待得清輝滿，中秋兩地看。", "丹心空自苦，玉臂故應寒。", "銀漢成冰水，金波滿露盤。", "西風羅袖薄，落月杵聲殘。", "身世誰知苦，裳衣客最單。", "關山同杜老，垂淚憶長安。"]'),
('b6fda5b8-f4c2-43ff-8b14-a0c66f009752','秋景 月滿秋夜長','劉辰翁','宋','宋诗','song-poetry','','[]','塵世如天海，團團共月光。',72,'全唐诗/poet.song.236000.json','["塵世如天海，團團共月光。", "一輪秋正滿，百刻夜偏長。", "端正惟三五，空明更十方。", "萃臺猶卓午，梧井欲飛霜。", "箭漏迷青海，闌干轉上陽。", "雪痕留得在，何用促扶桑。"]'),
('a9447fcf-329f-49d8-b43c-607b5a190fb1','秋景 月色醉遠客 其一','劉辰翁','宋','宋诗','song-poetry','','[]','明月有佳色，客中迷遠遊。',72,'全唐诗/poet.song.236000.json','["明月有佳色，客中迷遠遊。", "自應眠不得，更似醉時留。", "玉屑凉堪吸，金波香欲浮。", "頓忘鄉國恨，如在酒家樓。", "鸞鏡驚相對，霓裳卒未休。", "天風扶我起，不用典貂裘。"]'),
('6de97a5d-34a8-4494-8943-a38a8e9ca11e','秋景 月色醉遠客 其二','劉辰翁','宋','宋诗','song-poetry','','[]','遠客坐長夜，纏綿月色留。',72,'全唐诗/poet.song.236000.json','["遠客坐長夜，纏綿月色留。", "明知不是醉，爲爾更無愁。", "玉雪三千界，金波十二樓。", "謫仙迷采石，小杜在揚州。", "雁背如流水，蛾眉也白頭。", "一聲長嘯起，滿眼故山秋。"]'),
('04fdecc1-e5e5-4640-aca4-164d415e5f4d','秋景 卿月升仙掌','劉辰翁','宋','宋诗','song-poetry','','[]','卿在郎星上，瑶臺第一層。',72,'全唐诗/poet.song.236000.json','["卿在郎星上，瑶臺第一層。", "已如金掌迥，又得月華升。", "近與公相似，清如貴未曾。", "銅仙千尺表，玉指一輪冰。", "天下名公子，秋風老茂陵。", "衰蘭千里道，垂淚記觚稜。"]'),
('2d911175-a095-437e-bf5a-164ce1b2dda0','秋景 把釣待秋風','劉辰翁','宋','宋诗','song-poetry','','[]','長夏如年日，蕭然把釣終。',72,'全唐诗/poet.song.236000.json','["長夏如年日，蕭然把釣終。", "欲知臨水意，政自待秋風。", "豈是羊裘者，相從漁社中。", "何心思覓鱠，極目望來鴻。", "天下無知己，溪邊自老翁。", "六鰲閑入手，不是學任公。"]'),
('a5b80867-62b9-465b-8400-3ff355796e96','秋景 秋風白雲飛','劉辰翁','宋','宋诗','song-poetry','','[]','風起秋塵外，山空海又圍。',72,'全唐诗/poet.song.236000.json','["風起秋塵外，山空海又圍。", "疏疏黄葉外，渺渺白雲飛。", "掃地驅殘暑，林烟带落暉。", "空明仙仗過，夭矯玉龍歸。", "中野悲遊子，蒼梧迎帝妃。", "回首汾水上，不覺淚沾衣。"]'),
('0aba7894-e427-4f2a-b122-38a5c43d9aa1','秋景 秋風思鱸蓴','劉辰翁','宋','宋诗','song-poetry','','[]','秋風已如此，游子復何爲。',72,'全唐诗/poet.song.236000.json','["秋風已如此，游子復何爲。", "蕉鹿空形役，蓴鱸繞夢思。", "凉天新雁過，旅思白鷗知。", "雪色松江鱠，銀光笠澤絲。", "人生歸去好，鄉味寄來遲。", "尚覺薑難致，令人憶左慈。"]'),
('31365771-8c9d-4051-b7bb-dccd1d996a34','秋景 閉門感秋風','劉辰翁','宋','宋诗','song-poetry','','[]','世路故當窮，興亡一轉蓬。',72,'全唐诗/poet.song.236000.json','["世路故當窮，興亡一轉蓬。", "閉門羞俗子，仰屋感秋風。", "舊日施行馬，如今掩候蟲。", "瞭然一葉下，從此萬山空。", "歲月玄蟬槁，乾坤白雁通。", "荒凉今又在，吹笛月明中。"]'),
('bcccfec9-399c-4895-880d-e5f9c6f705b1','秋景 秋高風怒號','劉辰翁','宋','宋诗','song-poetry','','[]','萬里秋風下，還驚掃地高。',72,'全唐诗/poet.song.236000.json','["萬里秋風下，還驚掃地高。", "不因茅屋怒，全向樹梢號。", "寥廓歸雲盡，荒寒晚吹豪。", "黑摧淝水陣，白卷浙江濤。", "過耳鳴鶻羽，連山掣戴鰲。", "空林無落葉，拾得海鳬毛。"]'),
('6f3c80b3-5fcb-481b-9e26-2b4f343869fd','秋景 夜雨更秋風','劉辰翁','宋','宋诗','song-poetry','','[]','世事惟孤枕，吾生尚轉蓬。',72,'全唐诗/poet.song.236000.json','["世事惟孤枕，吾生尚轉蓬。", "共誰堪夜雨，何意更秋風。", "已是霖鈴苦，何當刻漏終。", "又聞翻溟滓，不是滴梧桐。", "衰壑鳴蛩外，寒燈落葉中。", "忽明天似水，萬里附冥鴻。"]'),
('6b6cdf5b-bd0b-4af6-89ed-bf588960fda8','秋景 秋風生桂枝','劉辰翁','宋','宋诗','song-poetry','','[]','又勝春風處，秋芳宇宙清。',72,'全唐诗/poet.song.236000.json','["又勝春風處，秋芳宇宙清。", "由來天路遠，幾許桂枝生。", "古道寒雲色，空山落葉聲。", "忽看金粟綴，如在蕊宮行。", "香入銅盤飲，根愁玉斧驚。", "小山人倚袖，延佇不勝情。"]'),
('9b10650b-9d78-448f-8657-b83bd782e989','秋景 疏雨滴梧桐','劉辰翁','宋','宋诗','song-poetry','','[]','疏雨兼長夜，巴山信未通。',72,'全唐诗/poet.song.236000.json','["疏雨兼長夜，巴山信未通。", "寥寥深院落，滴滴在梧桐。", "淚與簷相續，聽如漏未終。", "寒飄金井上，愁入碧階空。", "楚水孤蓬暝，吳宮落葉紅。", "霖鈴南內曉，今古此聲中。"]'),
('cd51d8a9-ed6f-47ca-bc46-aaa559121567','秋景 風雨近重陽','劉辰翁','宋','宋诗','song-poetry','','[]','白髮驚秋晚，青雲認故鄉。',72,'全唐诗/poet.song.236000.json','["白髮驚秋晚，青雲認故鄉。", "乾坤愁老眼，風雨近重陽。", "吹得沾衣濕，寒添落帽狂。", "未知明日是，還憶去年將。", "北闕風流遠，東籬世故長。", "無人知叔子，登覽自憐傷。"]'),
('75d09650-ea84-4bb4-a3c8-bd9eb00d0ba0','秋景 于今九日至','劉辰翁','宋','宋诗','song-poetry','','[]','九日各堪愛，西風歲歲深。',72,'全唐诗/poet.song.236000.json','["九日各堪愛，西風歲歲深。", "長因思往事，忽已至于今。", "不謂秋將晚，幾如老見侵。", "籬邊成獨往，天際起輕陰。", "此會知誰健，明朝肯重尋。", "山高休更上，別自有傷心。"]'),
('b6e99336-e29b-4375-b73c-d47c02cde14f','秋景 窗空雨聲晚','劉辰翁','宋','宋诗','song-poetry','','[]','枕上聞秋雨，愁聲萬古同。',72,'全唐诗/poet.song.236000.json','["枕上聞秋雨，愁聲萬古同。", "孰知殘夜曉，冷浸一窗空。", "窈窕閑箏雁，交疏結網蟲。", "卧聽千葉雨，不似五更風。", "渭水人分內，巴山客夢中。", "山城清漏斷，惟是滴梧桐。"]'),
('f5df722b-e141-404c-9264-c7d53ae6a5b7','秋景 悠然見南山','劉辰翁','宋','宋诗','song-poetry','','[]','異代羲皇上，餘生晉宋間。',72,'全唐诗/poet.song.236000.json','["異代羲皇上，餘生晉宋間。", "悠然無一事，政爾見南山。", "西曲風流遠，東籬意思閑。", "吹衣凉浩蕩，矯首碧孱顔。", "雙蝶來何晚，白雲相與還。", "是中秦博士，相識少相關。"]'),
('26cdd382-d656-4e94-b721-01abd4f82bdb','秋景 寒城菊自花','劉辰翁','宋','宋诗','song-poetry','','[]','菊滿荒城道，餘生一笑難。',72,'全唐诗/poet.song.236000.json','["菊滿荒城道，餘生一笑難。", "地非行樂舊，花自向人寒。", "風雨何登覽，江山共屈蟠。", "無人簪帽去，有蝶繞籬看。", "此處尤堪賞，明朝已是殘。", "淵明生晉晚，不及禊高蘭。"]'),
('affca826-7073-4186-8b7a-c1e7fb57f293','秋景 十日菊','劉辰翁','宋','宋诗','song-poetry','','[]','一年看九九，十日見炎凉。',72,'全唐诗/poet.song.236000.json','["一年看九九，十日見炎凉。", "菊有霜前操，人無節後香。", "就令無宿酒，也不似重陽。", "一夜寒英老，多情舊雨黄。", "帽如前度落，蝶更幾時忙。", "我不知何夕，相收足晚凉。"]'),
('44dcd093-0913-44ca-b9c8-8e4529af8acd','秋景 客愁連蟋蟀','劉辰翁','宋','宋诗','song-poetry','','[]','梧桐驚客夢，去住兩茫然。',72,'全唐诗/poet.song.236000.json','["梧桐驚客夢，去住兩茫然。", "曉覺鷄鳴未，愁惟蟋蟀連。", "江湖無漢地，家世本秦川。", "唧唧月共語，涓涓人獨眠。", "青燈寒四壁，衰鬢織千年。", "唐晉他人有，荒凉故殿前。"]'),
('ff2fff9c-415c-4794-bcdb-a37f0f1c3cad','秋景 蛩響亂秋陰','劉辰翁','宋','宋诗','song-poetry','','[]','蛩響何千百，人情自不禁。',72,'全唐诗/poet.song.236000.json','["蛩響何千百，人情自不禁。", "餘哀動鄰壁，最苦亂秋陰。", "泣盡相思夢，驚殘勸織心。", "露深蟲語語，月黑雁沈沈。", "壞壁歲年遠，長門日夜深。", "手摩銅雀雨，和汝一長吟。"]'),
('cf892aac-4098-4abd-b9ec-1b521c6dbd22','秋景 鶴唳清露垂','劉辰翁','宋','宋诗','song-poetry','','[]','一葉寒金井，惟應獨鶴知。',72,'全唐诗/poet.song.236000.json','["一葉寒金井，惟應獨鶴知。", "空山今夕淚，清露滿空垂。", "華表歸來後，琴心感慨時。", "寥寥天不問，湛湛夜何其。", "富貴朝田薤，琅玕月地芝。", "人間長似水，搔首夢爲誰。"]'),
('85a2b822-42c9-4a2d-aa71-39d8716f6298','秋景 門掩候蟲秋 其一','劉辰翁','宋','宋诗','song-poetry','','[]','四壁可誰語，一年將次休。',72,'全唐诗/poet.song.236000.json','["四壁可誰語，一年將次休。", "村行落葉晚，門掩候蟲秋。", "影有斜燈吐，貧無過客偷。", "蚓號殘月冷，蛩語故宮愁。", "館驛鄰機歎，關山古戍留。", "幽人推夢起，江海有孤舟。"]'),
('e6868020-f6be-410e-a136-74c62e8e1d5b','秋景 門掩候蟲秋 其二','劉辰翁','宋','宋诗','song-poetry','','[]','候蟲鳴寂寂，秋老獨何村。',72,'全唐诗/poet.song.236000.json','["候蟲鳴寂寂，秋老獨何村。", "怨語動行路，居人卧掩門。", "無誰倚朱戶，隨意閉黄昏。", "歲暮已如此，蛩聲胡與言。", "孤燈銷驛夢，殘月落空垣。", "白雁來天地，何由見淚痕。"]'),
('c5f60234-d338-4352-9493-e9132ab2bb7d','秋景 天清木葉聞','劉辰翁','宋','宋诗','song-poetry','','[]','天意清如水，何曾染世氛。',72,'全唐诗/poet.song.236000.json','["天意清如水，何曾染世氛。", "秋風何處起，木葉朅來聞。", "野有牛羊下，高無鴻雁羣。", "凉驚枝上墜，聲向靜中分。", "霜井嬋娟淚，冰溝冥漠君。", "斷腸題柿濕，一半是行雲。"]'),
('4ec6b75c-fa05-4b2a-96e4-6b099896a68b','秋景 出逢危葉落 其一','劉辰翁','宋','宋诗','song-poetry','','[]','舉眼秋蕭索，乾坤豈不容。',72,'全唐诗/poet.song.236000.json','["舉眼秋蕭索，乾坤豈不容。", "葉因危後落，身是出時逢。", "古木猶當道，西風小倚筇。", "崢嶸如解羽，零亂復寒蛩。", "薄似佳人命，飄如去國蹤。", "小山留我止，香月自重重。"]'),
('a705bd34-730d-47dd-976d-f4bfb97b1004','秋景 出逢危葉落 其二','劉辰翁','宋','宋诗','song-poetry','','[]','四顧欲何之，逢秋出自悲。',72,'全唐诗/poet.song.236000.json','["四顧欲何之，逢秋出自悲。", "萬山青未了，一葉落何危。", "未肯哀窮巷，還因立別歧。", "有風驚槁木，如鳥墜高枝。", "梧柳同如此，江湖事可知。", "月明疏影出，踏踏露巢欹。"]'),
('1767c51c-ba0d-4c05-9b0b-770d34721cb6','秋景 遠客坐長夜','劉辰翁','宋','宋诗','song-poetry','','[]','身是秋風客，遊梁更賦梁。',72,'全唐诗/poet.song.236000.json','["身是秋風客，遊梁更賦梁。", "此時家在遠，獨坐夜偏長。", "歲月黑貂晚，江湖白雁霜。", "烏皮人兀兀，蟾影海茫茫。", "扣角餘三歎，聞雞悄四荒。", "爐烟秋伏枕，誰念待班行。"]'),
('8db3241d-355a-498e-b839-c9b430d9ad71','秋景 芙蓉紅岸濕','劉辰翁','宋','宋诗','song-poetry','','[]','岸柳似衰容，高花忽數重。',72,'全唐诗/poet.song.236000.json','["岸柳似衰容，高花忽數重。", "紅光蕩人意，清露濕芙蓉。", "穠麗秋深見，攀翻木末逢。", "便疑江濯錦，不是隰遊龍。", "寒倚驚裙濺，雲歸悄夢蹤。", "霜風多意思，殘日掛高舂。"]'),
('5291a4ac-a04d-44fa-ab9a-a1ea48c4570a','秋景 庭榴剖朱實','劉辰翁','宋','宋诗','song-poetry','','[]','榴壓中庭墜，冰盤薦玉壺。',72,'全唐诗/poet.song.236000.json','["榴壓中庭墜，冰盤薦玉壺。", "西風吹轉綠，嘉實剖來朱。", "摘向欄干近，安除海外無。", "微醺揎絳袖，一笑燦明珠。", "酸徹鄰機齒，凉生浴錦膚。", "冷思當日艷，血色盛羅襦。"]'),
('e16feaab-ebc6-4bf0-b639-debbac160883','秋景 雁南歸','劉辰翁','宋','宋诗','song-poetry','','[]','天闊雁何之，沈雲字字稀。',72,'全唐诗/poet.song.236000.json','["天闊雁何之，沈雲字字稀。", "明知從北至，又說是南歸。", "兵氣侵行急，河聲背影微。", "江湖霜信遠，城郭主人非。", "不惜驚弦得，惟憂繫帛遺。", "河梁人惜別，似爾不能飛。"]'),
('55132b4e-c462-4bf7-92a3-bd4a44f1146e','秋景 鷺于飛 其一','劉辰翁','宋','宋诗','song-poetry','','[]','滄洲開晚景，莽蒼更依稀。',72,'全唐诗/poet.song.236000.json','["滄洲開晚景，莽蒼更依稀。", "有鷺從中起，于天盡處飛。", "數絲風冉冉，一片雪暉暉。", "外路迷鄉國，天風起我衣。", "遠遊尋鶴侶，近不爲魚肥。", "西塞山邊雨，漁簑獨自歸。"]'),
('3a1fcdb5-cf7d-4197-a6c9-d3f0c453cc9b','秋景 鷺于飛 其二','劉辰翁','宋','宋诗','song-poetry','','[]','鷺閑如可語，飛去復何圖。',72,'全唐诗/poet.song.236000.json','["鷺閑如可語，飛去復何圖。", "但見振兮振，不知于此于。", "難令公子濁，似是列仙癯。", "近逼孤雲小，遥看點雪無。", "滄洲何爾我，白髮自江湖。", "風雨魚歌外，玄真逝與俱。"]'),
('df591b2b-1813-403d-a89f-d091b4b68a17','秋景 時菊委嚴霜','劉辰翁','宋','宋诗','song-poetry','','[]','論菊何心傲，生時失衆芳。',72,'全唐诗/poet.song.236000.json','["論菊何心傲，生時失衆芳。", "未須多晚節，政似委嚴霜。", "北地飛飛擊，東籬冉冉黄。", "屑冰和露下，薄命有誰當。", "客去重陽遠，花寒一夜長。", "朝來有佳色，未放早梅香。"]'),
('6dcad805-f06c-49d7-ae51-65ff20e33535','秋景 江動月移石','劉辰翁','宋','宋诗','song-poetry','','[]','石是龍眠處，終無石可扛。',72,'全唐诗/poet.song.236000.json','["石是龍眠處，終無石可扛。", "未應江動月，自是月移江。", "本似岷山雪，今爲嶺表瀧。", "是誰驚兔杵，失却釣魚矼。", "投渚天爲碎，蹲磻影忽雙。", "桂輪無側匿，眼眼似窺窗。"]'),
('d6075989-c616-4a20-8d84-64a1490a9356','秋景 日出籬東水','劉辰翁','宋','宋诗','song-poetry','','[]','雨以田爲壑，疏籬野水中。',72,'全唐诗/poet.song.236000.json','["雨以田爲壑，疏籬野水中。", "憂天沈到底，有日出其東。", "或謂扶桑巧，誰知夢峽空。", "勿朝蓬海白，滿眼菊花紅。", "屐響初來客，牆暄到老翁。", "洗光吾鏡曲，一笑弄丸同。"]'),
('644ec90e-6dc0-4802-b8f6-98f759fc6acd','秋景 夕陽如有意','劉辰翁','宋','宋诗','song-poetry','','[]','又自欲昏黄，高高上夕陽。',72,'全唐诗/poet.song.236000.json','["又自欲昏黄，高高上夕陽。", "殷勤如有意，遲暮起相望。", "牛背笛三弄，桑榆錦一張。", "向人添晼晚，容我更疏狂。", "過雨天如改，穿花日尚長。", "魯陽三舍遠，人世未須忙。"]'),
('c105b967-d7a8-45f6-a452-6c02795d2065','秋景 山園細路高','劉辰翁','宋','宋诗','song-poetry','','[]','不是終南徑，山中取遁逃。',72,'全唐诗/poet.song.236000.json','["不是終南徑，山中取遁逃。", "小園何所有，細路未應高。", "已恨鋤荒菊，何堪彈種桃。", "梯飈那可上，鑱雪誤相遭。", "石卧當途虎，藤穿汲澗猱。", "天機分瀑布，應念甕畦勞。"]'),
('0a659174-a32a-4147-8e5c-462a2210d3da','冬景 冬日可愛','劉辰翁','宋','宋诗','song-poetry','','[]','此日荷天公，寧須挾纊重。',72,'全唐诗/poet.song.236000.json','["此日荷天公，寧須挾纊重。", "一寒偏更老，可愛莫如冬。", "不恨乘駒隙，猶愁閉燭龍。", "身如花正午，春入眼偏濃。", "有喜融霜鬢，何堪借酒容。", "至尊何處在，流涕獻無從。"]'),
('5a577993-a228-4a28-8b8e-67b51753a885','冬景 負暄','劉辰翁','宋','宋诗','song-poetry','','[]','雖霜晴可愛，容我俯前軒。',72,'全唐诗/poet.song.236000.json','["雖霜晴可愛，容我俯前軒。", "縱是圍燕玉，何如負趙暄。", "自憐鮐背癢，敢負太陽恩。", "已覺曲身直，猶勝挾纊溫。", "衰年知潦倒，造物足溫存。", "尚有葵心在，何因獻至尊。"]'),
('6cdc973d-4894-4909-bfb3-990432d831e3','冬景 地爐煨榾柮','劉辰翁','宋','宋诗','song-poetry','','[]','片地爲爐古，長鑱斫雪來。',72,'全唐诗/poet.song.236000.json','["片地爲爐古，長鑱斫雪來。", "蒲團容膝坐，榾柮向人煨。", "鑿破崑山璞，方如煖閣開。", "一根深雨露，四壁漲烟煤。", "光怪浮螭吻，雲星撥芋魁。", "朱門香獸擁，何意早成灰。"]'),
('f4c46513-6bbd-4f01-8cb7-5bacaf7e3087','冬景 舟雪灑寒燈','劉辰翁','宋','宋诗','song-poetry','','[]','舟雪那知重，驚沙灑未乾。',72,'全唐诗/poet.song.236000.json','["舟雪那知重，驚沙灑未乾。", "暮雲千里合，遠客一燈寒。", "飛絮漫空起，推蓬倚醉看。", "風缸青閃閃，水驛白漫漫。", "隔岸如漁火，無人共釣灘。", "閉門安道夢，月黑泝歸難。"]'),
('4de2bdb4-e885-4682-93f6-d9cbefc28777','冬景 爐存火似紅','劉辰翁','宋','宋诗','song-poetry','','[]','向火火無功，爐中本不空。',72,'全唐诗/poet.song.236000.json','["向火火無功，爐中本不空。", "尤存尤自冷，似有似無紅。", "圍共香團獸，燒餘焰吐虹。", "寒威侵鑠處，光氣吐吞中。", "尚覺身成曲，惟應笑是烘。", "箇中明點雪，萬古不曾融。"]'),
('71275f3c-7c48-40f9-80bd-32acce46d56d','冬景 孤舟蓑笠翁','劉辰翁','宋','宋诗','song-poetry','','[]','泛泛水晶宮，孤舟凜欲東。',72,'全唐诗/poet.song.236000.json','["泛泛水晶宮，孤舟凜欲東。", "短蓑并篛笠，舉世一漁翁。", "大雪三千界，輕舠尺八空。", "無衣寒獨速，皓首敗天公。", "乘雁雙鳬外，斜風細雨中。", "羊裘差好事，聱釣不相同。"]'),
('f1e2eefa-05df-4d68-8c7c-e13bd67adc4f','冬景 獨釣寒江雪','劉辰翁','宋','宋诗','song-poetry','','[]','一雪寒如此，何人立釣矼。',72,'全唐诗/poet.song.236000.json','["一雪寒如此，何人立釣矼。", "不知身入畫，獨自影臨江。", "未必魚吞粒，惟應鷺作雙。", "風吹沙皓皓，天闊水淙淙。", "歸去村邊路，看來纜失樁。", "夜深誰訪舊，推月倚蓬窗。"]'),
('96100cc2-46b9-4879-b00e-10820c4e4a0b','冬景 深山催短景','劉辰翁','宋','宋诗','song-poetry','','[]','曝背無餘地，冬晴直萬金。',72,'全唐诗/poet.song.236000.json','["曝背無餘地，冬晴直萬金。", "是誰催短景，政爾礙山深。", "鳥道空中小，猿啼底處尋。", "清霜經曉濕，紅日半天沈。", "隠士三竿夢，宮人一線心。", "百年渾似此，何處惜光陰。"]'),
('943bed35-ebab-4be1-9ef0-5d8b35f59cc3','冬景 至後日初長','劉辰翁','宋','宋诗','song-poetry','','[]','至後晴堪定，陽來藹未央。',72,'全唐诗/poet.song.236000.json','["至後晴堪定，陽來藹未央。", "是雖年已晚，最喜日初長。", "自報黄鐘動，誰將弱線量。", "荒寒無刻漏，宿昔已昏黄。", "天上開南陸，人間入壽鄉。", "魯陽驚昨夢，辛苦繫扶桑。"]'),
('ff150d08-63fc-4677-9cab-c8600c6a7678','冬景 繡紋添弱線','劉辰翁','宋','宋诗','song-poetry','','[]','自取天章繡，深宮漏不聞。',72,'全唐诗/poet.song.236000.json','["自取天章繡，深宮漏不聞。", "弱添今日線，閒認舊時紋。", "明麗千枝錦，蒙茸五色雲。", "忽驚花樣少，不爲女工勤。", "縷結期千載，晴慳暖一分。", "隔窗誰似醉，睡冷篆爐薰。"]'),
('52d670e8-d74f-4810-ab66-112a21b20eec','冬景 梅開不自覺','劉辰翁','宋','宋诗','song-poetry','','[]','度度看梅來，猶疑早計哉。',72,'全唐诗/poet.song.236000.json','["度度看梅來，猶疑早計哉。", "相逢如有待，不自覺全開。", "每念苔枝雪，猶頒玉鏡臺。", "忽能同我笑，知復爲誰催。", "有語爲春誤，何心待月來。", "老夫乘興耳，不作剡溪回。"]'),
('99c42e85-0ce0-4694-a421-8c2ba5cf6fd0','冬景 疏影','劉辰翁','宋','宋诗','song-poetry','','[]','梅影明於畫，空階掃不除。',72,'全唐诗/poet.song.236000.json','["梅影明於畫，空階掃不除。", "自然清意別，比似衆枝疏。", "明艷寒空裏，孤梢落葉餘。", "溪橫殘雪久，日映碧窗虛。", "竹暗愁相並，花寒瘦亦如。", "臨流羞白髮，惟爾獨華予。"]'),
('958c9ecf-5dc6-4ed1-a8f6-91f9fc88665c','冬景 梅蕊驚眼','劉辰翁','宋','宋诗','song-poetry','','[]','又是梅新蕊，寒凋季子裘。',72,'全唐诗/poet.song.236000.json','["又是梅新蕊，寒凋季子裘。", "撫時驚歲晚，滿眼使人愁。", "江路春如許，闌干淚不收。", "別君從灞水，舉目在揚州。", "月已成孤影，花應怪白頭。", "數聲羌笛弄，忍見墜珠樓。"]'),
('6dbce915-ff61-4a5a-9da4-5ad6d8c316f7','冬景 官梅動詩興','劉辰翁','宋','宋诗','song-poetry','','[]','官路行人老，梅開客過時。',72,'全唐诗/poet.song.236000.json','["官路行人老，梅開客過時。", "徘徊深動興，放浪自吟詩。", "水驛兼山驛，南枝更北枝。", "終然無一句，何以寄相思。", "歲月題梁在，風霜牧笛知。", "北人休繫馬，餘恨寄他誰。"]'),
('91c319ec-5427-44e1-a45a-9e3dfbdb1892','冬景 聊寄一枝春','劉辰翁','宋','宋诗','song-poetry','','[]','故知花可惜，聊以贈相思。',72,'全唐诗/poet.song.236000.json','["故知花可惜，聊以贈相思。", "與子別多日，先春有一枝。", "荒凉逢雁過，辛苦折瓊貽。", "北客遥簪雪，東風早驛詩。", "吾衰如雪白，到日是年時。", "若待青青子，尋芳計已遲。"]'),
('4ec49e0a-802e-420e-8012-a28ec889dd05','冬景 漢節梅花外','劉辰翁','宋','宋诗','song-poetry','','[]','十九年辭漢，花如舊日開。',72,'全唐诗/poet.song.236000.json','["十九年辭漢，花如舊日開。", "自持天外節，誰寄隴頭梅。", "死恨節旄盡，生知仗信來。", "春風橫浦驛，夜雪滿鄉臺。", "插鬢人空老，沈雲雁未回。", "何因香入月，下照拂雲堆。"]'),
('cf0f4839-219f-4c9a-baf3-dcc942cf7de4','月','劉辰翁','宋','宋诗','song-poetry','','[]','霓裳聲裏一攧，如今是第幾輪。',28,'全唐诗/poet.song.236000.json','["霓裳聲裏一攧，如今是第幾輪。", "赤壁黄樓都在，古今多少愁人。"]'),
('14954da9-b3b0-4704-acc8-1a2aeeadbb7e','文姬歸漢圖','劉辰翁','宋','宋诗','song-poetry','','[]','鵲巢覆絕孔文舉，錦衾裹葬楊德祖。',320,'全唐诗/poet.song.236000.json','["鵲巢覆絕孔文舉，錦衾裹葬楊德祖。", "銅雀春風歌舞長，獨徵悽然故人女。", "故人有女勝無兒，滿眼興亡身屬誰。", "琴燒笛折箏灰冷，閭巷草深歸忍饑。", "美人用事單于國，細馬駝金爲余北。", "曾從過鴈偕書看，又向枯魚寄聲得。", "胡笳日聽心自哀，天遣前朝漢使來。", "穹廬抱子送于野，欲去欲住真難哉。", "大兒牽衣小兒乳，割乳分携淚如雨。", "放馬兒啼漸不聞，腸斷一如初遇擄。", "畫圖巧畫欲無聲，不盡賢王子母情。", "踟躕拳跼各有態，未必日莫分馳能。", "天長地久何終極，事已不堪回首覓。", "草無南北是青青，雲有朝昏長羃羃。", "琵琶恨絕妒難消，海上羝兒夢豈遥。", "入見玉關天似錦，歸從金馬曉當朝。", "容儀憔悴恩無骨，記問荒唐存又沒。", "衛郎去我墓何斯，魏史親人禮難越。", "當時一女贖元身，亂代流離更可聞。", "天南地北有歸路，四海九州無故人。"]'),
('27615572-71f8-42eb-9284-8864a4956e2f','和答李德臣','劉辰翁','宋','宋诗','song-poetry','','[]','忍寒一百五，開落何匆匆。',60,'全唐诗/poet.song.236000.json','["忍寒一百五，開落何匆匆。", "華堂託孤根，棄我荆棘中。", "味言隨時變，茗薄酪自濃。", "蛺蝶金縷衣，更爲悅己容。", "雖無蛾眉妬，懷抱常忡忡。"]'),
('d075ced4-8c25-4356-8615-8536e79969e4','里門高','劉辰翁','宋','宋诗','song-poetry','','[]','里門高，里門壞，百年風雨何足怪。',48,'全唐诗/poet.song.236000.json','["里門高，里門壞，百年風雨何足怪。", "但憐誰受沐猴烹，子孫不見烏江敗。", "人人知笑不知戒，春草茫茫雉爭界。"]'),
('e1f915c1-bcd9-41ae-8e37-654129dcdfd3','謝客起早自嘲','劉辰翁','宋','宋诗','song-poetry','','[]','筆起春如海，辭窮客到家。',24,'全唐诗/poet.song.236000.json','["筆起春如海，辭窮客到家。", "敲門嗔不應，只是隔梅花。"]'),
('28812820-ba0a-407a-a0dd-192058f5203a','柳意','劉辰翁','宋','宋诗','song-poetry','','[]','獨坐觀柳色，一一如我鬚。',36,'全唐诗/poet.song.236000.json','["獨坐觀柳色，一一如我鬚。", "一日一日深，一年一年枯。", "人言青勝我，安得白於吾。"]'),
('a9bf138a-cbd1-4d4d-8f94-8bf749c70750','文文山畫像贊','劉辰翁','宋','宋诗','song-poetry','','[]','閑居忽忽，萬古咄咄。',60,'全唐诗/poet.song.236000.json','["閑居忽忽，萬古咄咄。", "天風慘然，如動生髮。", "如何尋約，亦念束芻。", "豈其英爽，猶累形軀。", "同時之人，能不顙泚。", "昔忌其生，今妒其死。"]'),
('386f6151-39dd-4d9e-afee-921a3fae7f0c','讀杜拾遺百憂集行有感','劉辰翁','宋','宋诗','song-poetry','','[]','余生行年將六十，不知何者爲憂戚。',192,'全唐诗/poet.song.236000.json','["余生行年將六十，不知何者爲憂戚。", "富貴不驕貧賤安，以此存心度朝夕。", "往年承乏佐中書，大官羊膳供堂食。", "只今賜老作編氓，衣食信天無固必。", "陋巷簞瓢如素居，不管茅茨春雨溼。", "門前載酒求賦詩，錦軸牙籤日堆積。", "在官不置附郭田，既老翻得稽古力。", "毀譽都忘月旦評，姓名不上春秋筆。", "朝米不煩鄰僧送，暮米不煩太倉糴。", "我亦一飯不忘君，文人相輕所不及。", "傷哉白首杜拾遺，入蜀還秦勞轍迹。", "文章蓋世亦何爲，妻子相看百憂集。"]'),
('efc109ca-2067-46c8-94fd-9766a51d05cf','贈製筆生許文瑶','劉辰翁','宋','宋诗','song-poetry','','[]','許生精藝誰可及，材用剛柔以製筆。',128,'全唐诗/poet.song.236000.json','["許生精藝誰可及，材用剛柔以製筆。", "水盆洗出紫兔毫，便覺文章生羽翼。", "蒙恬將軍爲動色，爲是秦王舊時物。", "丞相斯曾從駕行，載此篆書封禪碣。", "從秦至今幾千載，兔尚存皮竹可採。", "利濟天下功不有，入手千人萬人愛。", "我昔爲郎居粉署，用筆唯于許生取。", "輕衫日對紫薇花，寫遍江淹夢中句。"]'),
('469ee5ea-bf17-4de6-abf1-f64fde221687','蘇李泣別圖','劉辰翁','宋','宋诗','song-poetry','','[]','事已矣，泣何爲。',18,'全唐诗/poet.song.236000.json','["事已矣，泣何爲。", "蘇武節，李陵詩。", "噫。"]'),
('1d8d6005-9352-4600-aae2-b7180d09dae9','龍霧洲雪','劉辰翁','宋','宋诗','song-poetry','','[]','此處幾人行，隔波摇暮晴。',48,'全唐诗/poet.song.236000.json','["此處幾人行，隔波摇暮晴。", "洲迴江似玦，山遠雪如城。", "離合看雙櫓，荒寒又一程。", "今年梅未醉，最覺別來輕。"]'),
('11314db7-3419-47f2-bb6e-67913746650d','清明日偶成','劉辰翁','宋','宋诗','song-poetry','','[]','海日高高天欲斜，斷橋無復聽嘔啞。',64,'全唐诗/poet.song.236000.json','["海日高高天欲斜，斷橋無復聽嘔啞。", "墓中酩酊已千載，陌上清明有幾家。", "已老愈疎唯酒盞，更晴相看是梅花。", "年年春怨深如昨，莫把無涯恨有涯。"]'),
('70acda20-8053-4ea0-a325-a92382134c3c','漁歌效陳自堂作','劉辰翁','宋','宋诗','song-poetry','','[]','石頭城落淮水，劉郎浦對伍洲。',28,'全唐诗/poet.song.236000.json','["石頭城落淮水，劉郎浦對伍洲。", "越沼吳湖安在，月明人唱湖州。"]'),
('056b534e-bec4-4646-b76e-efd3835e46f3','探梅四絕  其一','劉辰翁','宋','宋诗','song-poetry','','[]','江天欲雪未雪時，絕江探梅馿倒騎。',32,'全唐诗/poet.song.236000.json','["江天欲雪未雪時，絕江探梅馿倒騎。", "空中著我方成畫，亂後逢花且賦詩。"]'),
('51dd22dc-3852-456e-a1f1-8b212f38a723','探梅四絕  其二','劉辰翁','宋','宋诗','song-poetry','','[]','鈞天遠遠月斜斜，歸客迢遥未到家。',32,'全唐诗/poet.song.236000.json','["鈞天遠遠月斜斜，歸客迢遥未到家。", "一色白雲天似雪，和衣和雪宿梅花。"]'),
('7d809000-cb39-4132-bcae-eb8d7725ef07','探梅四絕  其三','劉辰翁','宋','宋诗','song-poetry','','[]','後五百年無放翁，狂歌醉舞與誰同。',32,'全唐诗/poet.song.236000.json','["後五百年無放翁，狂歌醉舞與誰同。", "漁人入得桃花洞，猶有梅花路未通。"]'),
('4095d97d-1ea5-4db0-819f-c6126de7d2c0','探梅四絕  其四','劉辰翁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','冷蕊何心識老逋，芳名從此落西湖。',32,'全唐诗/poet.song.236000.json','["冷蕊何心識老逋，芳名從此落西湖。", "風霜未改幽堅操，第立花前諱玉奴。"]'),
('afec95fc-0ea2-4be0-9826-7da4973df52e','題宣和雙蟹圖卷','劉辰翁','宋','宋诗','song-poetry','','[]','講餘幾暇諫書空，艮嶽江湖入眼中。',32,'全唐诗/poet.song.236000.json','["講餘幾暇諫書空，艮嶽江湖入眼中。", "郭索能令天一笑，畫圖何必面春風。"]'),
('8cfd295f-9f83-4dc4-9856-bcb1ace78db2','題永興寺雙羅漢樹','劉辰翁','宋','宋诗','song-poetry','','[]','勝遊重過日，雙鬢已如秋。',48,'全唐诗/poet.song.236000.json','["勝遊重過日，雙鬢已如秋。", "古樹連雲幹，蒼枝傍日浮。", "陰垂先代影，僧似六朝幽。", "翠蘚橫鋪地，相貪竟日留。"]'),
('7350ed2d-2901-4241-92aa-e2f845db542e','古意四首  其一','周密','宋','宋诗','song-poetry','','[]','至人斥八極，獨與造物游。',48,'全唐诗/poet.song.236000.json','["至人斥八極，獨與造物游。", "大道無端倪，詎可以力求。", "鵬摶翅垂天，不作醯雞謀。", "清嘯發林麓，月落千山幽。"]'),
('d0da8e36-ab3c-4fb2-80d1-933358f43980','古意四首  其二','周密','宋','宋诗','song-poetry','','[]','老馬伏櫪鳴，終有萬里志。',48,'全唐诗/poet.song.236000.json','["老馬伏櫪鳴，終有萬里志。", "枯桐爨下焦，中抱千古意。", "凡物有所遭，時亦有泰否。", "古木根柢深，春風有時至。"]'),
('d4b0b3e2-dc8a-4443-8440-1e3c2055f4ba','古意四首  其三','周密','宋','宋诗','song-poetry','','[]','正色無嫵媚，大道無狹斜。',48,'全唐诗/poet.song.236000.json','["正色無嫵媚，大道無狹斜。", "所以松柏姿，不作桃李華。", "朱絃已久寂，蛙黽徒相誇。", "懷哉古之人，此意尤可嗟。"]'),
('f786f1da-c32b-480c-95fd-c57aef34de5b','古意四首  其四','周密','宋','宋诗','song-poetry','','[]','南山采薇心，東海乘查意。',48,'全唐诗/poet.song.236000.json','["南山采薇心，東海乘查意。", "種竹成繁陰，鳳兮久不至。", "棲遲坐空谷，落日生愁思。", "所思不可期，迢迢隔煙翠。"]'),
('1dc370e5-d360-48b5-a7ee-ebf24f2a95bf','上平舟楊先生二首  其一','周密','宋','宋诗','song-poetry','','[]','渭川竹千畝，敷翠何森森。',60,'全唐诗/poet.song.236000.json','["渭川竹千畝，敷翠何森森。", "誰云冰雪姿，中有春風心。", "取爲昭華管，吹作黄鍾音。", "相期在大雅，一洗哇俚淫。", "持此阜民物，豈特薰風琴。"]'),
('a5f2256c-bee7-4283-9abc-62f9e2dadec0','上平舟楊先生二首  其二','周密','宋','宋诗','song-poetry','','[]','璞玉至三獻，不計刖足悲。',60,'全唐诗/poet.song.236000.json','["璞玉至三獻，不計刖足悲。", "冶劍時一鳴，寧免流俗疑。", "買絲繡平原，聚金鑄鍾期。", "至寶不自寶，所貴知音知。", "何惜五十絃，爲君奏聲詩。"]'),
('ad056a05-4f0c-4fa4-be81-8f876ce7c5b6','北山四時招隠辭  其一','周密','宋','宋诗','song-poetry','','[]','綠意動兮崇蘭，暖回薄兮千巖。',118,'全唐诗/poet.song.236000.json','["綠意動兮崇蘭，暖回薄兮千巖。", "蘼蕪齊兮繡谷，芳菲菲兮鳥關關。", "步桃塢兮曲折，叩蘭若兮檀欒。", "珮九莖兮窈窕，采三秀兮巑岏。", "石田肥兮可蒔，溪毛秀兮堪餐。", "賦榮木兮胥悅，浩生意兮修蕃。", "田歌起兮啁哳，殷社鼓兮紞紞。", "山中春兮可樂，王孫不來兮謇誰留兮他山。"]'),
('62b44f91-60d1-4bb8-8929-99e12220866d','北山四時招隠辭  其二','周密','宋','宋诗','song-poetry','','[]','草木舞兮山深，蜩蚻弄兮淙鏗。',113,'全唐诗/poet.song.236000.json','["草木舞兮山深，蜩蚻弄兮淙鏗。", "息瓊阜兮嘉蔭，漱玉澗兮甘清。", "泛夫容兮十頃，搴朱實兮千尋。", "虬松兮五鬣，鳳草兮三稜。", "雨龍歸兮靈洞，夜鶴化兮仙岑。", "羌誰招兮太史，耿清夕兮猿吟。", "逃暍影兮散慮，極幽討兮崢嶸。", "樂吾山兮長夏，歸來兮濯滄浪之塵纓。"]'),
('7c6b2617-d8a6-4150-aa9d-b51281ce2350','北山四時招隠辭  其三','周密','宋','宋诗','song-poetry','','[]','灝氣泛兮虛寥，商籟發兮蕭騷。',121,'全唐诗/poet.song.236000.json','["灝氣泛兮虛寥，商籟發兮蕭騷。", "策逍遥兮玉囿，駕言陟兮弁之椒。", "石林林兮獻狀，浮空倒影兮清苕。", "漭具區兮瀉碧，若杯水兮堂坳。", "披素懷兮佩明月，𪡧然嘯兮泠飆。", "閲古今兮宇宙，一日非近兮千載非遥。", "嗟湛輩兮堙滅其奚數，慨其感兮臨高。", "水竹清兮秋晚，賦叢桂兮誰招。"]'),
('1c1a9805-5239-4094-8123-d0ae94a2f458','北山四時招隠辭  其四','周密','宋','宋诗','song-poetry','','[]','風栗栗兮雲黄，梅事動兮貞芳。',124,'全唐诗/poet.song.236000.json','["風栗栗兮雲黄，梅事動兮貞芳。", "紛白月兮廣野，屑寶璐兮平岡。", "雲可怡兮日可獻，野可擷兮水可湘。", "拾樵蘇兮野爨，儲橡栗兮山糧。", "竹房深兮雲暖，芸几浄兮春薌。", "官無徵兮村靜，年屢有兮金穰。", "我今不樂兮歲遲暮，處嘉遯兮徜徉。", "擊鮮拊缶兮聊以卒歲，誰爭子所兮樂其樂兮無央。"]'),
('cfb499ec-663b-4230-a62d-cffad3683ad3','舟遇順風','周密','宋','宋诗','song-poetry','','[]','檣烏指鷁首，助我浮清苕。',120,'全唐诗/poet.song.236000.json','["檣烏指鷁首，助我浮清苕。", "輕帆乘快風，山勢欲動摇。", "岸樹紛相隨，罄折不待招。", "舟師坐奏功，破浪聲如潮。", "身世如白鷗，泛泛殊飄蕭。", "旁觀極歆羨，何異登瀛霄。", "正恐風勢回，世事不可料。", "何如乘安流，天幸其敢徼。", "止止勿盡興，解幔維吾橈。", "朗誦秋水篇，孤月生山椒。"]'),
('bfebea72-c127-48a2-83f0-b36eef3e5150','雪晴小步留飲村舍','周密','宋','宋诗','song-poetry','','[]','散步小逡巡，茅簷愛日新。',48,'全唐诗/poet.song.236000.json','["散步小逡巡，茅簷愛日新。", "梅知春意思，山借雪精神。", "減麴篘村釀，加籩薦野珍。", "蕭然捐世慮，自謂葛天民。"]'),
('dd34d279-bde3-4669-b226-271cc1bc052f','吳中與友人別','周密','宋','宋诗','song-poetry','','[]','臨分生遠思，把手重凄然。',48,'全唐诗/poet.song.236000.json','["臨分生遠思，把手重凄然。", "春別忽秋晚，君歸在我先。", "快風生一葦，新月上三弦。", "回首河橋暮，丹楓夕照邊。"]'),
('bc2ec543-6130-404e-b29c-2ff27d52b9d3','遊靈巖館娃宮','周密','宋','宋诗','song-poetry','','[]','春風吳苑夢淒涼，柳色如雲惹恨長。',64,'全唐诗/poet.song.236000.json','["春風吳苑夢淒涼，柳色如雲惹恨長。", "鳥喙祇堪同患難，蛾眉何事管興亡。", "烏鳶自樂空山靜，麋鹿來遊野草長。", "一片古愁無寫處，滿城鍾鼓送斜陽。"]'),
('293cb73c-0156-47e5-ab8d-e59c76aba33e','會稽山','周密','宋','宋诗','song-poetry','','[]','職方猶記禹南巡，窆石梅梁尚有神。',64,'全唐诗/poet.song.236000.json','["職方猶記禹南巡，窆石梅梁尚有神。", "地接蓬萊雲意古，潮來溟渤水痕春。", "刻碑頌德秦丞相，探穴求書漢史臣。", "玉室金堂今在否，餘糧仙草屬閒人。"]'),
('fc5dbc4b-2f59-474a-99ef-323785a706b3','梨山澤民廟','周密','宋','宋诗','song-poetry','','[]','甘棠遺愛在，香火儼如新。',48,'全唐诗/poet.song.236000.json','["甘棠遺愛在，香火儼如新。", "古木藏雲雨，深廊隠鬼神。", "建州名刺史，唐代老詩人。", "五百餘年後，猶能澤及民。"]'),
('c91a2aa2-3bff-4ade-9fa8-80ff2dbb7702','讀李長吉集','周密','宋','宋诗','song-poetry','','[]','朝剪湘中一尺天，暮翦吳松半江水。',96,'全唐诗/poet.song.236000.json','["朝剪湘中一尺天，暮翦吳松半江水。", "隴西風月屬王孫，錦囊探取元無底。", "酒酣嘔出明月珠，奚驚馿蹶心自如。", "騷哀玄澀無足語，天上不讀人間書。", "新宮銘古玄卿老，定知識字神仙少。", "窗外誰呼祁孔賓，短夢初回玉樓曉。"]'),
('429f85ab-90a2-4f20-9f49-7df99eded155','杼山聞鵑','周密','宋','宋诗','song-poetry','','[]','谿上誰哦柳惲蘋，杼山斜日颺花塵。',32,'全唐诗/poet.song.236000.json','["谿上誰哦柳惲蘋，杼山斜日颺花塵。", "杜鵑只管催春去，不信東風老得人。"]'),
('b889bccc-03e2-4825-98f7-2d4d2c6240aa','木筆花','周密','宋','宋诗','song-poetry','','[]','脫穎吹開紫玉筒，鼠鬚香蘸粉霜茸。',32,'全唐诗/poet.song.236000.json','["脫穎吹開紫玉筒，鼠鬚香蘸粉霜茸。", "含毫寫恨知誰見，綠捲春蕉未展封。"]'),
('7278667f-4fc7-48dc-83ca-5e90c840dd72','顧楷翁歸隠','周密','宋','宋诗','song-poetry','','[]','廣野穹林草樹香，高人新賦遠遊章。',32,'全唐诗/poet.song.236000.json','["廣野穹林草樹香，高人新賦遠遊章。", "二三千載無巢許，薇長西山幾許長。"]');
